// Quiz engine: setup panel (topic chips + length chips) + active quiz UI
// (question card, answer feedback, difficulty adaptation, results screen).
// Phase 2: BANK lives inline. Phase 3 moves it to content/certs/ppl/quiz/*.json.

const BANK = [{"t": "Regulations", "d": 1, "q": "Minimum age for a Private Pilot Certificate (airplane)?", "c": ["16", "17", "18", "15"], "a": 1, "e": "14 CFR 61.103(a): Must be at least 17 years old. Solo privileges require only 16.", "r": "14 CFR 61.103(a)"}, {"t": "Regulations", "d": 1, "q": "Total flight hours required for PPL under Part 61?", "c": ["30 hrs", "35 hrs", "40 hrs", "50 hrs"], "a": 2, "e": "14 CFR 61.109(a): Minimum 40 total flight hours. Part 141 approved courses may require as few as 35 hours.", "r": "14 CFR 61.109(a)"}, {"t": "Regulations", "d": 1, "q": "Bottle-to-throttle minimum time after consuming alcohol?", "c": ["4 hours", "6 hours", "8 hours", "12 hours"], "a": 2, "e": "14 CFR 91.17(a)(2): No crewmember may act within 8 hours of consuming alcohol.", "r": "14 CFR 91.17(a)(2)"}, {"t": "Regulations", "d": 1, "q": "To carry passengers, how many T&Ls in the preceding 90 days?", "c": ["1", "2", "3", "5"], "a": 2, "e": "14 CFR 91.107(a)(3): 3 takeoffs and 3 landings within the preceding 90 days in the same category and class.", "r": "14 CFR 91.107(a)(3)"}, {"t": "Regulations", "d": 1, "q": "AROW \u2014 required aircraft documents on board?", "c": ["Annual, Radio, Operations, Weight", "Airworthiness, Registration, Operating handbook, Weight and balance", "Altimeter, Registration, Oxygen, W&B", "Airspeed, Routes, Ops plan, Weather"], "a": 1, "e": "AROW: Airworthiness certificate, Registration, Operating handbook/AFM, Weight and balance data.", "r": "14 CFR 91.203"}, {"t": "Regulations", "d": 1, "q": "How often must a flight review (BFR) be completed?", "c": ["Every 12 calendar months", "Every 24 calendar months", "Every 36 calendar months", "Every 6 months"], "a": 1, "e": "14 CFR 61.56: Flight review required every 24 calendar months \u2014 at least 1 hr ground plus 1 hr flight.", "r": "14 CFR 61.56"}, {"t": "Regulations", "d": 1, "q": "Maximum airspeed below 10,000 ft MSL?", "c": ["200 KIAS", "250 KIAS", "300 KIAS", "No limit"], "a": 1, "e": "14 CFR 91.117(a): No more than 250 KIAS below 10,000 ft MSL.", "r": "14 CFR 91.117(a)"}, {"t": "Regulations", "d": 1, "q": "Solo flight hours required in the make/model within 60 days of checkride?", "c": ["1 hour", "3 hours", "5 hours", "10 hours"], "a": 1, "e": "14 CFR 61.109(a)(6): At least 3 hours of solo flight in the make and model within 60 days preceding the practical test.", "r": "14 CFR 61.109(a)(6)"}, {"t": "Regulations", "d": 2, "q": "Documents a pilot must carry when acting as PIC?", "c": ["Certificate and logbook", "Pilot certificate, valid medical, government-issued photo ID", "Medical only", "Certificate and endorsements"], "a": 1, "e": "14 CFR 61.3: Pilot certificate, valid medical certificate or BasicMed, and government-issued photo ID.", "r": "14 CFR 61.3"}, {"t": "Regulations", "d": 2, "q": "Maximum BAC allowed when acting as crewmember?", "c": ["0.02%", "0.04%", "0.06%", "0.08%"], "a": 1, "e": "14 CFR 91.17(a)(4): Blood alcohol concentration must be less than 0.04 percent.", "r": "14 CFR 91.17(a)(4)"}, {"t": "Regulations", "d": 2, "q": "Expense sharing with passengers \u2014 what must the pilot pay at minimum?", "c": ["100% of costs", "Their equal pro-rata share", "Up to 50% only", "Any amount"], "a": 1, "e": "14 CFR 61.113(b): Pilot must pay at least their equal share. With 3 passengers, each person pays one-quarter.", "r": "14 CFR 61.113(b)"}, {"t": "Regulations", "d": 2, "q": "3rd-class medical validity for a 38-year-old pilot?", "c": ["12 months", "24 months", "36 months", "60 months"], "a": 3, "e": "14 CFR 61.23(d): 3rd-class medical valid 60 calendar months for pilots under 40; 24 months for pilots 40 and older.", "r": "14 CFR 61.23(d)"}, {"t": "Regulations", "d": 2, "q": "Required solo cross-country total distance for PPL?", "c": ["50 nm", "100 nm", "150 nm", "200 nm"], "a": 2, "e": "14 CFR 61.109(a)(5): Solo XC must be at least 150 nm total, full-stop at 3 or more points, one leg 50 nm or more.", "r": "14 CFR 61.109(a)(5)"}, {"t": "Regulations", "d": 2, "q": "Night currency time window for carrying passengers?", "c": ["Sunset to sunrise", "1 hour after sunset to 1 hour before sunrise", "30 minutes after sunset to 30 minutes before sunrise", "Any darkness"], "a": 1, "e": "14 CFR 91.107(a)(3)(ii): Night period is defined as 1 hour after sunset to 1 hour before sunrise.", "r": "14 CFR 91.107(a)(3)(ii)"}, {"t": "Regulations", "d": 2, "q": "Annual inspection completed March 15 \u2014 when does it expire?", "c": ["March 15 next year", "March 31 next year", "March 14 next year", "12 months to the day"], "a": 1, "e": "14 CFR 91.409: Expires at the end of the 12th calendar month \u2014 March 31 of the following year.", "r": "14 CFR 91.409"}, {"t": "Regulations", "d": 2, "q": "Who is responsible for determining aircraft airworthiness per 91.7?", "c": ["A&P mechanic", "FAA inspector", "Pilot in command", "Aircraft owner"], "a": 2, "e": "14 CFR 91.7(b): The PIC is responsible for determining whether the aircraft is in condition for safe flight.", "r": "14 CFR 91.7(b)"}, {"t": "Regulations", "d": 2, "q": "Minimum altitude over a congested area?", "c": ["500 ft above highest obstacle within 2000 ft", "1000 ft above highest obstacle within 2000 ft horizontal", "500 ft AGL", "1500 ft MSL"], "a": 1, "e": "14 CFR 91.119(b): Over congested areas, 1000 ft above the highest obstacle within a 2000 ft horizontal radius.", "r": "14 CFR 91.119(b)"}, {"t": "Regulations", "d": 2, "q": "Special VFR minimum visibility in Class D airspace?", "c": ["1/2 SM", "1 SM", "3 SM", "Clear of clouds only"], "a": 1, "e": "14 CFR 91.157: Special VFR clearances require at least 1 statute mile flight visibility and clear of clouds.", "r": "14 CFR 91.157"}, {"t": "Regulations", "d": 2, "q": "Night defined for logging flight time (14 CFR 61.51)?", "c": ["Sunset to sunrise", "End of evening civil twilight to beginning of morning civil twilight", "1 hour after sunset to 1 hour before sunrise", "Any reduced-visibility time"], "a": 1, "e": "14 CFR 61.51(b)(3)(i): Night equals end of evening civil twilight to beginning of morning civil twilight.", "r": "14 CFR 61.51(b)(3)(i)"}, {"t": "Regulations", "d": 2, "q": "When overtaking another aircraft, which side do you pass on?", "c": ["Left", "Right", "Either side", "Above only"], "a": 1, "e": "14 CFR 91.113(f): The overtaking aircraft alters course to the RIGHT to pass well clear.", "r": "14 CFR 91.113(f)"}, {"t": "Regulations", "d": 2, "q": "Two aircraft converging at same altitude \u2014 who has right of way?", "c": ["Aircraft on the left", "Aircraft on the right", "Faster aircraft", "Higher aircraft"], "a": 1, "e": "14 CFR 91.113(d): When aircraft converge, the aircraft on the RIGHT has right-of-way.", "r": "14 CFR 91.113(d)"}, {"t": "Regulations", "d": 2, "q": "Right-of-way hierarchy \u2014 balloon vs glider vs powered aircraft?", "c": ["Powered over glider over balloon", "Balloon over glider over powered", "Glider over balloon over powered", "All equal"], "a": 1, "e": "14 CFR 91.113(b): After aircraft in distress, order is balloon, glider, airship, aircraft towing, then powered aircraft.", "r": "14 CFR 91.113(b)"}, {"t": "Regulations", "d": 3, "q": "Inoperative transponder discovered before flight \u2014 conditions for legal departure?", "c": ["Never legal", "Only in VFR conditions", "With ATC authorization, avoiding airspace requiring transponder", "Only at night"], "a": 2, "e": "14 CFR 91.215(d): ATC may authorize a deviation. Flight must avoid Class A, B, C airspace and the Mode C veil.", "r": "14 CFR 91.215(d)"}, {"t": "Regulations", "d": 3, "q": "Required IFR inspections beyond the annual (most complete)?", "c": ["Annual only", "Annual plus 100-hour", "Annual plus altimeter/static 24 mo, transponder 24 mo, VOR 30 days", "Annual and ELT only"], "a": 2, "e": "For IFR: altimeter/pitot-static (91.411, 24 cal months), transponder (91.413, 24 cal months), VOR check (91.171, 30 days).", "r": "14 CFR 91.411, 91.413, 91.171"}, {"t": "Regulations", "d": 3, "q": "Process for flying with inoperative equipment under 91.213 with no MEL?", "c": ["Cannot fly until repaired", "Automatically grounded", "Verify not required by type cert or ops rules, deactivate, placard INOP, mechanic confirms safe", "Owner must approve"], "a": 2, "e": "14 CFR 91.213: If not required by type certificate or operating rules, deactivate, placard INOP, and a certificated mechanic determines no safety impact.", "r": "14 CFR 91.213"}, {"t": "Regulations", "d": 3, "q": "Student pilot solo XC \u2014 what endorsements are required?", "c": ["Logbook only", "Student pilot certificate only", "Both logbook AND certificate endorsement for specific route or area", "None if solo sign-off exists"], "a": 2, "e": "14 CFR 61.93: Requires both a logbook endorsement and a student pilot certificate endorsement for the make, model, and route.", "r": "14 CFR 61.93"}, {"t": "Regulations", "d": 3, "q": "PIC authority to deviate from FARs in an emergency?", "c": ["Must comply at all times", "May deviate as necessary; submit report to FAA if requested", "May deviate only from weather minimums", "Must get ATC approval first"], "a": 1, "e": "14 CFR 91.3(b): In an emergency, PIC may deviate from any FAR to the extent necessary. Written report may be required.", "r": "14 CFR 91.3(b)"}, {"t": "Regulations", "d": 3, "q": "An AD requires action within 50 flight hours; you are at 48 hours. When must you comply?", "c": ["At next annual", "Within next 2 flight hours", "Already past the limit", "Within 6 months regardless"], "a": 1, "e": "14 CFR 39: ADs are legally enforceable. Must comply before reaching the 50-hour threshold \u2014 within the next 2 flight hours.", "r": "14 CFR 39"}, {"t": "Regulations", "d": 3, "q": "Presidential TFR under 91.141 \u2014 inner ring restriction?", "c": ["All flights within 100 nm", "All civilian flight; outer ring requires ATC coordination", "Only IFR flights", "Commercial flights only"], "a": 1, "e": "14 CFR 91.141: Inner ring (typically 10 nm, surface to FL180) prohibits civilian flight. Outer ring (30 nm) requires ATC coordination.", "r": "14 CFR 91.141"}, {"t": "Regulations", "d": 4, "q": "ATC issues an instruction you believe would create a safety hazard. Your authority?", "c": ["Must comply \u2014 ATC has final authority", "Must comply unless you declare an emergency first", "You have final authority under 91.3; may deviate and notify ATC", "Ask for a supervisor on frequency"], "a": 2, "e": "14 CFR 91.3(a): The PIC is the final authority regarding the operation of the aircraft. In an emergency, 91.3(b) allows deviation from any rule.", "r": "14 CFR 91.3"}, {"t": "Weather", "d": 1, "q": "Three ingredients required for thunderstorm formation?", "c": ["Wind, rain, cold temperature", "Moisture, lifting mechanism, atmospheric instability", "Fog, pressure change, high humidity", "Cold front, warm front, occluded front"], "a": 1, "e": "Three ingredients: adequate moisture in the lower atmosphere, a lifting mechanism (fronts, surface heating, orographic), and atmospheric instability.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 1, "q": "AIRMET Zulu warns of?", "c": ["IFR conditions and mountain obscuration", "Moderate turbulence and low-level wind shear", "Moderate icing and freezing level information", "Severe turbulence hazardous to all aircraft"], "a": 2, "e": "AIRMET Zulu covers moderate icing not associated with thunderstorms and provides freezing level information. Sierra = IFR/mtns. Tango = moderate turbulence and LLWS.", "r": "AIM 7-1-6"}, {"t": "Weather", "d": 1, "q": "Temp/dewpoint spread of 3 degrees C or less indicates?", "c": ["Severe turbulence likely", "Fog or low clouds likely to develop", "Thunderstorm activity imminent", "Clear VFR conditions ahead"], "a": 1, "e": "When temperature and dewpoint are within 3 degrees C, the air is near saturation. Fog, mist, or low clouds are likely to form.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 1, "q": "What type of front produces the most intense but shortest-duration weather?", "c": ["Warm front", "Cold front", "Stationary front", "Occluded front"], "a": 1, "e": "Cold fronts move faster and produce narrow bands of intense precipitation and thunderstorms followed by rapid clearing.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 1, "q": "What does 9900 mean in a winds aloft forecast?", "c": ["Winds at 9900 feet", "Winds at 99 knots variable", "Light and variable winds", "Data unavailable"], "a": 2, "e": "In the winds aloft (FB) forecast, 9900 means light and variable winds \u2014 speed less than 5 knots.", "r": "AC 00-45"}, {"t": "Weather", "d": 1, "q": "VFR visibility minimum for Class G airspace below 1200 AGL during the day?", "c": ["3 SM", "1 SM", "1/2 SM", "Clear of clouds only"], "a": 1, "e": "14 CFR 91.155: Class G airspace below 1200 AGL during the day requires only 1 statute mile visibility and clear of clouds.", "r": "14 CFR 91.155"}, {"t": "Weather", "d": 2, "q": "METAR cloud layer BKN025 \u2014 what does this indicate?", "c": ["Broken at 25000 ft MSL", "Broken at 2500 ft AGL", "Scattered at 2500 ft AGL", "Broken at 250 ft AGL"], "a": 1, "e": "METAR cloud heights are in hundreds of feet AGL. BKN025 = broken layer at 2500 ft AGL. A broken layer (5/8 to 7/8 coverage) defines the ceiling.", "r": "AIM 7-1-30"}, {"t": "Weather", "d": 2, "q": "At which thunderstorm stage does rainfall first reach the surface?", "c": ["Cumulus stage", "Mature stage", "Dissipating stage", "Pre-frontal stage"], "a": 1, "e": "Mature stage: both updrafts and downdrafts present; precipitation first reaches the surface. Most hazardous stage.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "VFR minimums inside Class B airspace?", "c": ["3 SM and 500 below 1000 above 2000 horizontal", "1 SM and clear of clouds", "3 SM and clear of clouds", "5 SM and 1000 below 1000 above 1 SM horizontal"], "a": 2, "e": "14 CFR 91.155: Class B requires 3 SM visibility and clear of clouds. No specific cloud distance required \u2014 unique to Class B.", "r": "14 CFR 91.155"}, {"t": "Weather", "d": 2, "q": "Primary hazard of a microburst?", "c": ["Heavy rainfall causing hydroplaning", "Extreme low-level wind shear with outflow exceeding 45 kts causing rapid airspeed and altitude loss", "Ice crystal formation at altitude", "Severe turbulence above 10000 ft"], "a": 1, "e": "A microburst produces outflow exceeding 45 knots. Aircraft flying through encounters headwind then tailwind causing rapid airspeed and altitude loss \u2014 most dangerous on approach or departure.", "r": "AIM 7-1-24"}, {"t": "Weather", "d": 2, "q": "Most dangerous type of structural icing and why?", "c": ["Rime ice \u2014 forms most quickly", "Clear ice \u2014 dense, hard to remove, severely disrupts airfoil shape", "Mixed ice \u2014 unpredictable", "Frost \u2014 forms on ground"], "a": 1, "e": "Clear ice forms from large supercooled droplets spreading before freezing \u2014 dense, transparent, hard to remove, severely alters airfoil shape.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "AIRMET Tango warns of?", "c": ["IFR conditions", "Moderate turbulence, sustained surface winds 30 kts or more, non-convective LLWS", "Moderate icing", "Severe icing hazardous to all aircraft"], "a": 1, "e": "AIRMET Tango: moderate turbulence, sustained surface winds of 30 knots or greater, and non-convective low-level wind shear.", "r": "AIM 7-1-6"}, {"t": "Weather", "d": 2, "q": "Non-convective SIGMET validity period?", "c": ["2 hours", "4 hours", "6 hours", "12 hours"], "a": 1, "e": "Non-convective SIGMETs are valid up to 4 hours. Hurricane/tropical cyclone SIGMETs: 6 hours. Convective SIGMETs: 2 hours.", "r": "AIM 7-1-6"}, {"t": "Weather", "d": 2, "q": "What type of fog forms over a cooler surface and requires wind to develop?", "c": ["Radiation fog", "Advection fog", "Upslope fog", "Steam fog"], "a": 1, "e": "Advection fog requires horizontal movement of warm moist air over a cooler surface. Unlike radiation fog it requires wind and is common along coastlines.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "What is density altitude?", "c": ["Altimeter reading when set to 29.92 in Hg", "Pressure altitude corrected for non-standard temperature \u2014 determines aircraft performance", "Altitude AGL for obstacle clearance", "Height above sea level corrected for humidity only"], "a": 1, "e": "Density altitude = pressure altitude corrected for non-standard temperature and humidity. High DA = less dense air = degraded aircraft performance.", "r": "PHAK Ch.4, Ch.11"}, {"t": "Weather", "d": 2, "q": "Two conditions required simultaneously for structural airframe icing?", "c": ["Cold temperatures and strong winds", "Visible moisture AND temperature at or below 0 degrees C", "Below minus 20 C only", "Rain and any below-freezing temperature"], "a": 1, "e": "Structural icing requires: (1) visible moisture such as clouds, rain, or drizzle, AND (2) temperature at or below 0 degrees C.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "ISA standard temperature lapse rate?", "c": ["1 degree C per 1000 ft", "2 degrees C per 1000 ft", "3 degrees C per 1000 ft", "1 degree F per 1000 ft"], "a": 1, "e": "The International Standard Atmosphere lapse rate is 2 degrees C (3.5 degrees F) per 1000 ft up to the tropopause.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "TAF code PROB40 means?", "c": ["40-knot probability winds", "40 percent probability the forecast conditions will occur during the time period", "Probability of 40-knot gusts", "TAF valid for 40 hours"], "a": 1, "e": "PROB40 in a TAF indicates a 40 percent probability that the listed conditions will occur during the specified time period.", "r": "AIM 7-1-31"}, {"t": "Weather", "d": 2, "q": "Winds aloft forecasts are issued how many times per day?", "c": ["Once daily", "Twice daily", "Four times daily", "Every 6 hours"], "a": 1, "e": "Winds aloft (FB) forecasts are issued twice daily, based on 00Z and 12Z upper-air observation data.", "r": "AC 00-45"}, {"t": "Weather", "d": 2, "q": "What does AIRMET Sierra cover?", "c": ["Moderate turbulence", "IFR conditions and mountain obscuration", "Moderate icing", "Severe turbulence for light aircraft"], "a": 1, "e": "AIRMET Sierra covers IFR conditions (ceiling below 1000 ft and/or visibility below 3 miles over 3000 sq mi or more) and mountain obscuration.", "r": "AIM 7-1-6"}, {"t": "Weather", "d": 3, "q": "At 9000 ft MSL in IMC with freezing level at 8000 ft \u2014 primary structural hazard?", "c": ["Carburetor ice", "Structural airframe icing \u2014 above freezing level means below 0 C in visible moisture", "Instrument icing only", "No hazard \u2014 you are above the freezing level"], "a": 1, "e": "At 9000 ft you are above the 8000 ft freezing level, meaning temperatures are below 0 C. Combined with visible moisture (IMC), both conditions for structural icing are present.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 3, "q": "Conditions most favorable for radiation fog formation?", "c": ["Strong winds, overcast sky, high relative humidity", "Clear skies, calm winds, high relative humidity, long nights in fall or winter", "Warm moist air moving over cold ocean water", "Strong onshore wind over cold coastal waters"], "a": 1, "e": "Radiation fog: clear sky (maximum radiation), calm winds, high humidity, long nights (fall/winter). Ground cools air to its dewpoint.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 3, "q": "What does a lenticular cloud indicate to a pilot?", "c": ["Approaching thunderstorm activity", "Mountain wave activity \u2014 rotor zone and severe turbulence possible on the leeward side", "Approaching warm front", "Moderate icing conditions at that level"], "a": 1, "e": "Lenticular (lens-shaped) stationary clouds form at mountain wave crests on the leeward side. The rotor zone below wave crests can contain extremely violent turbulence.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 3, "q": "PIREPs categorize turbulence. Moderate turbulence means?", "c": ["Minor discomfort but objects stay in place", "Unsecured objects may dislodge, occupants feel strain against belts, difficult walking, aircraft control reduced but maintained", "Aircraft is temporarily out of control", "Engine damage or failure risk is high"], "a": 1, "e": "Moderate turbulence: unsecured objects dislodge, occupants strain against seatbelts, difficult walking, airspeed fluctuations 15 to 25 knots. Aircraft control reduced but maintained throughout.", "r": "AIM 7-1-21"}, {"t": "Weather", "d": 3, "q": "Rapid pressure drop over 2 hours ahead of an approaching cold front indicates?", "c": ["Improving conditions and rapid clearing", "Potential for stronger frontal weather, thunderstorms, gusty winds at passage", "Stable conditions only", "Overnight radiation fog likely"], "a": 1, "e": "Rapid pressure falls ahead of a cold front indicate intensifying low pressure and suggest stronger-than-normal frontal weather.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 3, "q": "What is wind shear and at what phase of flight is it most dangerous?", "c": ["Any wind \u2014 most dangerous at cruise altitude", "Change in wind speed or direction over a short distance \u2014 most dangerous at low altitude during approach and departure", "Only relevant in and near thunderstorms", "A gust front \u2014 only dangerous on the ground"], "a": 1, "e": "Wind shear is a change in wind speed or direction over a short distance. Most hazardous at low altitude near thunderstorms, fronts, and temperature inversions during approach and departure.", "r": "AIM 7-1-24; PHAK Ch.12"}, {"t": "Weather", "d": 3, "q": "What is a temperature inversion and what can it cause?", "c": ["Normal lapse rate \u2014 no special hazard", "Temperature increases with altitude instead of decreasing \u2014 can trap fog near surface and cause low-level wind shear", "Temperature drops rapidly \u2014 associated only with thunderstorms", "Equal temperature at all altitudes"], "a": 1, "e": "A temperature inversion occurs when temperature increases with altitude instead of decreasing. Inversions trap moisture causing low ceilings and visibility. They also create low-level wind shear.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 4, "q": "VFR on top at 8500 ft when clouds below close in. No instrument rating. Best immediate action?", "c": ["Descend through the clouds \u2014 it is an emergency", "Continue VFR on top until you find a gap", "Immediately contact ATC, declare the situation, and request assistance \u2014 radar vectors to VFR, SVFR, or nearest suitable airport", "Climb to Class A airspace"], "a": 2, "e": "This is an urgency or emergency situation. Immediately contact ATC, declare the situation, and request radar vectors to VFR conditions or a Special VFR clearance. Attempting to descend VFR into IMC without an instrument rating is extremely dangerous.", "r": "AIM 6-1-1; 14 CFR 91.3"}, {"t": "Weather", "d": 2, "q": "Carburetor icing most likely at what conditions?", "c": ["Below minus 20 C only", "Between 20 and 70 degrees F with high relative humidity \u2014 even on clear days", "Only when flying through rain or visible moisture", "Only at night"], "a": 1, "e": "Carburetor ice can form between 20 and 70 degrees F with high relative humidity. The venturi effect and fuel vaporization can lower carb temperatures up to 70 degrees F \u2014 ice even on warm clear days.", "r": "PHAK Ch.7"}, {"t": "Weather", "d": 2, "q": "A PIREP of MOD ICE indicates?", "c": ["Minor frost on windshield \u2014 not a hazard", "Moderate structural icing \u2014 a change of course or altitude is recommended", "Severe icing requiring immediate action", "Ice only on airspeed probe"], "a": 1, "e": "Moderate icing (MOD ICE) in a PIREP indicates ice accumulation is such that a change of course or altitude is recommended. Ice accumulates rapidly enough to be problematic if flight continues.", "r": "AIM 7-1-21"}, {"t": "Airspace", "d": 1, "q": "Communication required before entering Class D airspace?", "c": ["ATC clearance must be received", "Two-way radio communication must be established with the controlling facility", "Must file a flight plan", "No communication required for VFR"], "a": 1, "e": "14 CFR 91.129: Two-way radio communication must be established with the ATC facility responsible for Class D airspace before entry.", "r": "14 CFR 91.129"}, {"t": "Airspace", "d": 1, "q": "Class B entry requires what specific clearance from ATC?", "c": ["Two-way radio communications established", "Explicit ATC clearance such as cleared into Class Bravo plus Mode C transponder and ADS-B Out", "Just a Mode C transponder", "Filing a flight plan and squawking a code"], "a": 1, "e": "14 CFR 91.131: Must receive explicit clearance. Simply establishing radio contact is NOT sufficient unlike Class C and D.", "r": "14 CFR 91.131"}, {"t": "Airspace", "d": 1, "q": "Class A airspace begins at what altitude?", "c": ["10000 ft MSL", "14500 ft MSL", "18000 ft MSL", "FL600"], "a": 2, "e": "Class A airspace extends from 18000 ft MSL (FL180) to FL600. All operations within Class A must be conducted under IFR.", "r": "14 CFR 71.33"}, {"t": "Airspace", "d": 1, "q": "Can VFR pilots legally enter an active MOA?", "c": ["No \u2014 ATC clearance required", "Yes \u2014 no prohibition, but extreme caution advised; check FSS for activity status", "Yes \u2014 no restrictions ever apply to VFR in MOAs", "Only if flying below 1000 AGL"], "a": 1, "e": "MOAs do not require ATC clearance for VFR flight. However, pilots should exercise extreme caution and check activity status through FSS. When active, high-speed military maneuvers occur.", "r": "AIM 3-4-5"}, {"t": "Airspace", "d": 2, "q": "Dashed magenta circle around a non-towered airport on a sectional indicates?", "c": ["Class D airspace", "Class C airspace", "Class E airspace starting at the surface associated with instrument approaches", "An alert area boundary"], "a": 2, "e": "A dashed magenta circle indicates Class E airspace beginning at the surface, typically at airports with published instrument approaches but no operating control tower.", "r": "PHAK Ch.15; AIM 3-2-6"}, {"t": "Airspace", "d": 2, "q": "Mode C Veil extends how far from a Class B primary airport?", "c": ["10 nm", "20 nm", "30 nm", "50 nm"], "a": 2, "e": "14 CFR 91.215(b)(2): A transponder with Mode C is required within 30 nm of the Class B primary airport, from the surface up to 10000 ft MSL.", "r": "14 CFR 91.215(b)(2)"}, {"t": "Airspace", "d": 2, "q": "Standard Class C airspace lateral dimensions?", "c": ["10 nm radius surface to 10000", "5 nm inner circle surface to 4000 AGL and 10 nm outer ring 1200 to 4000 AGL", "20 nm radius surface to 5000", "5 nm ring surface to 2500"], "a": 1, "e": "Standard Class C: 5 nm inner circle from surface to 4000 AGL, 10 nm outer ring from 1200 AGL to 4000 AGL.", "r": "AIM 3-2-4"}, {"t": "Airspace", "d": 2, "q": "ADS-B Out required in which airspace?", "c": ["Class B only", "Class A, B, C; Class E at and above 10000 MSL except below 2500 AGL; and above 3000 MSL over Gulf of Mexico", "Only above FL180", "Only in the Mode C veil"], "a": 1, "e": "14 CFR 91.225: ADS-B Out required in Class A, B, C, Class E at or above 10000 MSL (except below 2500 AGL), and above 3000 MSL over the Gulf of Mexico.", "r": "14 CFR 91.225"}, {"t": "Airspace", "d": 2, "q": "What is a Prohibited Area?", "c": ["Airspace requiring special equipment", "Airspace where flight is prohibited at all times \u2014 examples include P-56 (White House) and P-49 (Camp David)", "A Military Operations Area when active", "An Alert Area with high-density traffic"], "a": 1, "e": "Prohibited areas are established for national security reasons where flight is prohibited at all times under 14 CFR 73. No civilian operations permitted.", "r": "14 CFR 73; AIM 3-4-2"}, {"t": "Airspace", "d": 2, "q": "Class C airspace depicted on a sectional chart in what color?", "c": ["Blue", "Magenta", "Blue dashed", "Magenta dashed"], "a": 1, "e": "Class C airspace is shown with solid magenta circles on sectional charts. Class D is depicted with segmented (dashed) blue circles.", "r": "PHAK Ch.15"}, {"t": "Airspace", "d": 2, "q": "Speed limit for aircraft at or below 2500 AGL within 4 nm of a Class C or D airport?", "c": ["250 KIAS", "200 KIAS", "175 KIAS", "No specific limit"], "a": 1, "e": "14 CFR 91.117(b): Below 2500 AGL within 4 nm of a Class C or D airport the speed limit is 200 KIAS.", "r": "14 CFR 91.117(b)"}, {"t": "Airspace", "d": 2, "q": "What is an Alert Area on a sectional chart?", "c": ["Airspace requiring ATC clearance", "High volume of pilot training or unusual aerial activity \u2014 no clearance needed, all pilots equally responsible for collision avoidance", "Military operations \u2014 restricted to military", "Active restricted area"], "a": 1, "e": "Alert Areas contain high volumes of pilot training or unusual aerial activity. No ATC clearance is required. All aircraft equally responsible for collision avoidance.", "r": "AIM 3-4-6"}, {"t": "Airspace", "d": 3, "q": "Control tower closes at 10 PM at a Class D airport. You arrive at 11 PM. What rules apply?", "c": ["Still Class D \u2014 use UNICOM for traffic advisories", "Class D converts to Class E or Class G per the Chart Supplement \u2014 check before flying", "Class D automatically becomes Class B when uncontrolled", "No airspace restrictions apply after the tower closes"], "a": 1, "e": "When a control tower closes, Class D airspace reverts to either Class E or Class G depending on what the Chart Supplement indicates for that specific airport.", "r": "AIM 3-2-5"}, {"t": "Airspace", "d": 3, "q": "When can a pilot legally enter a Restricted Area without prior ATC clearance?", "c": ["Never \u2014 always need prior clearance", "Only if flying below 500 AGL", "When the area is inactive and ATC confirms it is available for normal operations", "Any time in VFR conditions"], "a": 2, "e": "When a Restricted Area is not active, the controlling agency releases it to ATC for normal use. ATC may advise pilots that the area is available. Always verify before entry.", "r": "AIM 3-4-4"}, {"t": "Airspace", "d": 3, "q": "Class D airspace typically extends to what height AGL?", "c": ["1000 ft", "2500 ft", "3000 ft", "4000 ft"], "a": 1, "e": "Class D airspace typically extends from the surface to 2500 ft AGL. Exact boundaries for each airport are shown on sectional charts.", "r": "AIM 3-2-5"}, {"t": "Airspace", "d": 3, "q": "You are 8 nm from a Class C primary airport at 2000 ft MSL with airport elevation 500 ft MSL. The outer ring floor is 1200 AGL. Are you inside Class C?", "c": ["No \u2014 you are outside the 10 nm outer ring", "Yes \u2014 inside the outer ring above its 1200 AGL floor; must establish two-way comms before continuing", "Yes \u2014 ATC clearance explicitly required to enter", "No \u2014 the 5 nm inner circle is the only area requiring comms"], "a": 1, "e": "The outer ring extends 10 nm. At 8 nm you are inside it. At 2000 ft MSL with a 500 ft airport elevation, you are at 1500 ft AGL \u2014 above the 1200 AGL floor of the outer ring. Two-way comms must be established before entry.", "r": "14 CFR 91.130; AIM 3-2-4"}, {"t": "Airspace", "d": 3, "q": "What is a Warning Area?", "c": ["Airspace that requires ATC clearance", "Airspace over international waters (3+ nm from US coast) containing hazardous activities \u2014 VFR not prohibited but strongly discouraged", "Prohibited area near sensitive government installations", "MOA equivalent over international waters"], "a": 1, "e": "Warning Areas are established over international waters containing potentially hazardous activity. They extend from 3 nm outward. Non-participating aircraft are not prohibited but strongly advised to avoid.", "r": "AIM 3-4-5"}, {"t": "Airspace", "d": 4, "q": "You inadvertently fly into an active Restricted Area. What should you do?", "c": ["Nothing \u2014 if VFR no enforcement action possible", "Exit immediately, contact ATC, identify yourself and explain the situation. Be prepared for possible FAA enforcement action.", "Only enforcement if you were IFR", "File a NASA ASRS report and nothing else is required"], "a": 1, "e": "Unauthorized entry into a Restricted Area is an airspace violation. Exit immediately, contact ATC, and be prepared to file a report. FAA may take enforcement action. Filing a NASA ASRS report provides some protection but does not eliminate FAA action.", "r": "14 CFR 91.123; AIM 3-4-4"}, {"t": "Airspace", "d": 2, "q": "What equipment is required to operate in Class A airspace?", "c": ["VFR equipment plus a transponder", "IFR-equipped aircraft plus an operable Mode C transponder", "Just a two-way radio", "Transponder and ADS-B Out only"], "a": 1, "e": "Class A requires IFR equipment including suitable navigation equipment, plus an operable Mode C transponder. Operations must be under an IFR clearance.", "r": "14 CFR 91.135"}, {"t": "Airspace", "d": 3, "q": "A TFR under 91.137(a)(1) \u2014 what type of operations does it primarily protect?", "c": ["Presidential movement", "Space operations", "Aircraft flying relief operations at or below 1000 AGL for immediate safety of individuals", "Public entertainment events"], "a": 2, "e": "14 CFR 91.137(a)(1): This type of TFR protects aircraft flying relief operations at or below 1000 AGL, law enforcement aircraft, and aircraft providing direct safety support.", "r": "14 CFR 91.137(a)(1)"}, {"t": "Airspace", "d": 2, "q": "What document should always be checked for airspace that converts when a tower closes?", "c": ["Sectional aeronautical chart", "Chart Supplement (formerly Airport/Facility Directory)", "NOTAM system", "AIM Chapter 3"], "a": 1, "e": "The Chart Supplement contains specific information about each airport including what the airspace converts to when the tower is closed and the hours of operation.", "r": "AIM 3-2-5"}, {"t": "Airspace", "d": 3, "q": "ATC tells you to stay outside the Bravo. You have not received cleared into Class B. What does this mean?", "c": ["You are cleared into the Class B but at low altitude", "You do NOT have clearance to enter Class B and must remain outside its boundaries", "You may transit at or below the floor of the Class B", "ATC will guide you through on VFR flight following"], "a": 1, "e": "Without hearing the words cleared into Class Bravo airspace or a similar explicit clearance, you do not have authorization to enter Class B.", "r": "14 CFR 91.131; AIM 3-2-3"}, {"t": "Airspace", "d": 2, "q": "What is an SFRA and where does one exist in the US?", "c": ["Standard Flight Rules Area \u2014 applies everywhere", "Special Flight Rules Area \u2014 the Washington DC area (DC SFRA) requires specific training and authorization to operate within", "Simplified Flight Route Authorization \u2014 for commercial operators", "Seasonal Flight Restriction Area \u2014 applied during wildfire season"], "a": 1, "e": "An SFRA imposes specific requirements beyond standard FARs. The Washington DC SFRA (within 30 nm of DCA) requires specific online training and an ATC authorization or flight plan to operate within.", "r": "14 CFR 93.331"}, {"t": "Airspace", "d": 2, "q": "Solid blue segmented (dashed) circle on a sectional chart depicts what?", "c": ["Class B airspace", "Class C airspace", "Class D airspace surface area", "Class E airspace at the surface"], "a": 2, "e": "Class D airspace is depicted with a segmented (dashed) blue circle on sectional charts.", "r": "PHAK Ch.15"}, {"t": "Airspace", "d": 2, "q": "A magenta vignette (shaded boundary) on a sectional indicates Class E airspace starting at what altitude?", "c": ["Surface", "700 ft AGL (within the shaded area)", "1200 ft AGL (outside the shaded area)", "2500 ft AGL"], "a": 1, "e": "The magenta shaded area indicates Class E transition airspace beginning at 700 ft AGL. Outside the shaded area, Class E typically starts at 1200 AGL.", "r": "PHAK Ch.15; AIM 3-2-6"}, {"t": "Navigation", "d": 1, "q": "VFR cruising altitude for magnetic course 090 degrees at 7500 ft MSL (more than 3000 AGL)?", "c": ["7000 ft", "7500 ft", "8500 ft", "9500 ft"], "a": 1, "e": "14 CFR 91.159: MC 0 to 179 degrees (eastbound) = odd thousands plus 500. MC 090 is eastbound so valid altitudes are 3500, 5500, 7500, 9500 ft. 7500 ft is correct.", "r": "14 CFR 91.159"}, {"t": "Navigation", "d": 1, "q": "VFR cruising altitude rule for westbound flight at MC 270 degrees?", "c": ["Odd thousands plus 500 ft", "Even thousands plus 500 ft", "Any altitude above 3000 AGL", "Even thousands only"], "a": 1, "e": "14 CFR 91.159: MC 180 to 359 degrees (westbound) = even thousands plus 500 ft. MC 270 is westbound so use 4500, 6500, 8500 ft etc.", "r": "14 CFR 91.159"}, {"t": "Navigation", "d": 1, "q": "TVMDC formula \u2014 what does each letter represent?", "c": ["Temperature Visibility Moisture Drag Ceiling", "True course plus or minus Variation equals Magnetic plus or minus Deviation equals Compass course", "Turbulence Velocity Moisture Dew Cloud", "Time Voltage Magnetic deviation CAS"], "a": 1, "e": "TVMDC: True course +/- Variation = Magnetic course +/- Deviation = Compass course. East is subtract, West is add. Memory: True Virgins Make Dull Company.", "r": "PHAK Ch.16"}, {"t": "Navigation", "d": 1, "q": "VFR day fuel reserve requirement?", "c": ["20 minutes at cruise", "30 minutes at cruise", "45 minutes at cruise", "1 hour at cruise"], "a": 1, "e": "14 CFR 91.151(a)(1): Must have enough fuel to fly to the first intended landing plus at least 30 minutes at normal cruising speed during daylight.", "r": "14 CFR 91.151(a)(1)"}, {"t": "Navigation", "d": 1, "q": "VFR night fuel reserve requirement?", "c": ["20 minutes", "30 minutes", "45 minutes", "1 hour"], "a": 2, "e": "14 CFR 91.151(a)(2): Night VFR requires fuel to reach the first intended landing plus at least 45 minutes at normal cruising speed.", "r": "14 CFR 91.151(a)(2)"}, {"t": "Navigation", "d": 2, "q": "Solid magenta circle around an airport on a sectional chart indicates?", "c": ["Class D airspace", "Class C airspace", "Class E airspace at the surface", "Class B inner ring"], "a": 1, "e": "A solid magenta circle indicates Class C airspace. Class D is a segmented (dashed) blue circle. Class E at the surface is a dashed magenta circle.", "r": "PHAK Ch.15"}, {"t": "Navigation", "d": 2, "q": "Sectional aeronautical chart scale?", "c": ["1:250000", "1:500000", "1:1000000", "1:750000"], "a": 1, "e": "Sectional charts are published at 1:500000 scale, approximately 1 inch equals 6.86 nm. VFR Terminal Area Charts (TAC) for Class B areas are 1:250000.", "r": "AIM 9-1-4"}, {"t": "Navigation", "d": 2, "q": "TAS 120 kts with a direct 20-kt headwind \u2014 groundspeed?", "c": ["140 kts", "120 kts", "100 kts", "110 kts"], "a": 2, "e": "Groundspeed = TAS minus headwind component for a direct headwind. 120 minus 20 equals 100 kts.", "r": "PHAK Ch.17"}, {"t": "Navigation", "d": 2, "q": "Maximum Elevation Figure (MEF) on a sectional chart represents?", "c": ["The highest terrain elevation in the quadrangle", "The highest obstacle plus 100 ft vertical clearance rounded up to the next 100 ft", "The minimum safe VFR cruising altitude", "The radar coverage floor altitude"], "a": 1, "e": "The MEF includes the highest obstacle in a lat/lon quadrangle plus 100 ft of vertical clearance, rounded up to the next 100 ft increment.", "r": "PHAK Ch.16"}, {"t": "Navigation", "d": 2, "q": "Sectional aeronautical charts are revised how often?", "c": ["Every 3 months", "Every 6 months", "Every 12 months", "Every 56 days like instrument charts"], "a": 1, "e": "VFR Sectional charts are revised every 6 months. World Aeronautical Charts (WAC) are revised annually. TACs are also revised every 6 months.", "r": "AIM 9-1-4"}, {"t": "Navigation", "d": 2, "q": "VOR navigation frequency range?", "c": ["108.0 to 117.95 MHz", "118.0 to 136.975 MHz", "329 to 335 MHz", "108.0 to 111.95 MHz only"], "a": 0, "e": "VOR navigation frequencies are 108.0 to 117.95 MHz. The range 108.0 to 111.95 MHz is shared with ILS localizers (odd tenths). Comm frequencies are 118.0 to 136.975 MHz.", "r": "AIM 1-1-3"}, {"t": "Navigation", "d": 3, "q": "True course 045 degrees, magnetic variation 10 degrees East \u2014 magnetic course?", "c": ["055 degrees", "045 degrees", "035 degrees", "050 degrees"], "a": 2, "e": "TVMDC: TC +/- Variation = MC. East variation means subtract. MC = 045 minus 10 = 035 degrees.", "r": "PHAK Ch.16"}, {"t": "Navigation", "d": 3, "q": "What does RAIM stand for and why is it important?", "c": ["Radar Altitude Indication Monitor \u2014 used for altitude alerts", "Receiver Autonomous Integrity Monitoring \u2014 checks GPS signal integrity; required for IFR non-WAAS approaches", "Radio Altitude Instrument Module \u2014 backup gyro system", "Real-time Airspace Information Module \u2014 for airspace alerts"], "a": 1, "e": "RAIM uses redundant GPS satellites to monitor signal integrity autonomously. For IFR GPS approaches without WAAS, a RAIM check must confirm adequate signal integrity before departure.", "r": "AIM 1-1-17"}, {"t": "Navigation", "d": 3, "q": "Is a VFR flight plan legally required?", "c": ["Yes for all cross-country flights", "Yes for any flight over 50 nm", "No \u2014 strongly recommended for search and rescue but not legally required by the FARs", "Yes in Class E airspace"], "a": 2, "e": "VFR flight plans are NOT required by the FARs. However, they are strongly recommended as a search-and-rescue tool. File with FSS and close on arrival.", "r": "AIM 5-1-4"}, {"t": "Navigation", "d": 3, "q": "You cross a checkpoint 3 minutes late at 120 kts groundspeed. How far behind are you?", "c": ["3 nm", "5 nm", "6 nm", "2 nm"], "a": 2, "e": "At 120 kts groundspeed the aircraft covers 2 nm per minute. Three minutes late = 2 times 3 = 6 nm behind the planned position.", "r": "PHAK Ch.17"}, {"t": "Navigation", "d": 3, "q": "What is dead reckoning navigation?", "c": ["Navigation using only radio navigation aids", "Calculating current position from a known starting point using heading, airspeed or groundspeed, time, and wind \u2014 without external position fixes", "Navigation by GPS only", "Navigation using only visual ground references"], "a": 1, "e": "Dead reckoning calculates current position from a known starting point by advancing that position using estimated groundspeed, heading corrected for wind, and elapsed time.", "r": "PHAK Ch.17"}, {"t": "Navigation", "d": 2, "q": "What is magnetic variation and how does easterly variation affect conversion from true to magnetic course?", "c": ["Magnetic variation is compass deviation \u2014 no effect on heading", "Magnetic variation is the angle between true north and magnetic north. East variation: subtract from true course to get magnetic course.", "East variation means add to get magnetic course", "Variation only applies east of the prime meridian"], "a": 1, "e": "Magnetic variation is the angular difference between true north and magnetic north shown by isogonic lines on charts. East variation: subtract (TC minus variation = MC). West variation: add.", "r": "PHAK Ch.16"}, {"t": "Navigation", "d": 2, "q": "ATIS \u2014 what information does it provide and where is the frequency found?", "c": ["Air Traffic Information System \u2014 on sectional chart legend", "Automated Terminal Information Service \u2014 provides current weather, active runways, and NOTAMs; frequency on sectional chart or Chart Supplement", "Air Traffic ILS System \u2014 for instrument approaches only", "Airport Traffic Identification System \u2014 for towered airports only"], "a": 1, "e": "ATIS provides continuous recorded information about weather, runways, NOTAMs, and other terminal information. Frequencies are found on sectional charts near the airport symbol and in the Chart Supplement.", "r": "AIM 4-1-13"}, {"t": "Navigation", "d": 3, "q": "True altitude vs pressure altitude \u2014 what is the difference?", "c": ["They are the same thing", "True altitude is actual height above MSL; pressure altitude is indicated altitude when altimeter is set to 29.92 in Hg", "Pressure altitude is corrected for temperature; true altitude is shown on the altimeter", "True altitude is AGL; pressure altitude is MSL"], "a": 1, "e": "True altitude is actual height above mean sea level. Pressure altitude is the altitude indicated when the altimeter is set to 29.92 in Hg. Density altitude = pressure altitude corrected for temperature.", "r": "PHAK Ch.8, Ch.11"}, {"t": "Navigation", "d": 2, "q": "What is the purpose of the wind correction angle (WCA)?", "c": ["To correct for magnetic variation", "To adjust the aircraft heading into the wind so the actual track over the ground matches the desired course despite crosswind", "To correct for runway slope during landing", "To adjust airspeed for wind during cruise"], "a": 1, "e": "The wind correction angle adjusts the heading to compensate for crosswind drift, so the actual ground track matches the desired course.", "r": "PHAK Ch.17"}, {"t": "Maneuvers", "d": 1, "q": "ACS altitude tolerance for steep turns?", "c": ["plus or minus 50 ft", "plus or minus 100 ft", "plus or minus 200 ft", "plus or minus 150 ft"], "a": 1, "e": "ACS Task VIII.B: Maintain entry altitude within plus or minus 100 ft throughout the steep turn maneuver.", "r": "ACS FAA-S-ACS-6 Task VIII.B"}, {"t": "Maneuvers", "d": 1, "q": "Bank angle required for steep turns on the Private Pilot ACS?", "c": ["30 degrees", "40 degrees", "45 degrees", "60 degrees"], "a": 2, "e": "ACS Task VIII.B requires steep turns at exactly 45 degrees of bank. Load factor at 45 degrees is 1.41g.", "r": "ACS FAA-S-ACS-6 Task VIII.B"}, {"t": "Maneuvers", "d": 1, "q": "Vx is used for what purpose?", "c": ["Maximum range speed", "Best angle of climb \u2014 maximum altitude gained per unit of horizontal distance", "Best rate of climb \u2014 maximum altitude gained per unit of time", "Turbulence penetration speed"], "a": 1, "e": "Vx (best angle of climb) provides maximum altitude gain per unit of horizontal distance. Used for obstacle clearance after takeoff. Transition to Vy once clear.", "r": "PHAK Ch.11; AFH Ch.5"}, {"t": "Maneuvers", "d": 1, "q": "Vy is used for what purpose?", "c": ["Best angle of climb for obstacle clearance", "Best rate of climb \u2014 maximum altitude gain per unit of time", "Normal approach speed", "Maneuvering speed for turbulence"], "a": 1, "e": "Vy (best rate of climb) provides maximum altitude gain per unit of time. Used for en-route climb after obstacle clearance to reach cruise altitude efficiently.", "r": "PHAK Ch.11; AFH Ch.5"}, {"t": "Maneuvers", "d": 1, "q": "First action in any stall recovery?", "c": ["Apply full power immediately", "Retract flaps immediately", "Reduce angle of attack by pitching forward to break the stall", "Apply right rudder to stop roll"], "a": 2, "e": "First priority in stall recovery is to reduce the angle of attack \u2014 pitch the nose forward to break the stall. Apply full power after the stall breaks and retract flaps incrementally.", "r": "ACS Task VIII.D; AFH Ch.4"}, {"t": "Maneuvers", "d": 1, "q": "Normal landing ACS touchdown tolerance?", "c": ["plus or minus 100 ft", "plus or minus 200 ft", "plus or minus 400 ft", "plus or minus 600 ft"], "a": 2, "e": "ACS Task X.A: Normal landing requires touchdown within plus or minus 400 ft of the aiming point, on centerline, with no drift, at or below Vref.", "r": "ACS FAA-S-ACS-6 Task X.A"}, {"t": "Maneuvers", "d": 2, "q": "Power-off stall recovery \u2014 when should the pilot initiate recovery?", "c": ["After aircraft loses 100 ft of altitude", "At the first indication of stall \u2014 buffet, stall horn, or loss of control effectiveness", "Only after a full stall break occurs", "At a specific airspeed listed in the POH"], "a": 1, "e": "ACS requires recovery at the first indication of stall: stall warning horn activation, buffet, or loss of normal control effectiveness. Do not wait for a full stall.", "r": "ACS Task VIII.D"}, {"t": "Maneuvers", "d": 2, "q": "In ground reference maneuvers, when should bank angle be steepest?", "c": ["When heading directly into the wind", "When heading directly crosswind", "When heading downwind with highest groundspeed", "Bank angle is always constant throughout"], "a": 2, "e": "To maintain constant radius ground track: downwind = highest groundspeed = steepest bank needed. Upwind = lowest groundspeed = shallowest bank.", "r": "AFH Ch.6"}, {"t": "Maneuvers", "d": 2, "q": "Entry position for turns around a point?", "c": ["Directly upwind of the point", "45 degrees to the downwind leg abeam the point", "On a downwind heading directly abeam the point at desired radius", "Directly crosswind of the point"], "a": 2, "e": "Standard entry: on a downwind heading directly abeam the point at the desired radius distance. This ensures the steepest bank is needed at entry when groundspeed is highest.", "r": "AFH Ch.6"}, {"t": "Maneuvers", "d": 2, "q": "Soft field takeoff elevator control input during the takeoff roll?", "c": ["Neutral elevator", "Full forward elevator to reduce nosewheel drag", "Full aft (back) pressure on elevator to transfer weight to wings and off the nosewheel", "Differential braking only with neutral elevator"], "a": 2, "e": "Full aft elevator pressure reduces weight on the nosegear (which could dig into soft surface) and transfers weight to the wings as quickly as possible for early liftoff.", "r": "AFH Ch.8"}, {"t": "Maneuvers", "d": 2, "q": "Short field landing ACS touchdown tolerance?", "c": ["plus or minus 100 ft", "At or within 200 ft beyond the aiming point", "plus or minus 400 ft", "At or before the aiming point"], "a": 1, "e": "ACS Task X.F: Short field landing requires touchdown at or within 200 ft beyond the specified touchdown point. More demanding than normal landing (400 ft).", "r": "ACS FAA-S-ACS-6 Task X.F"}, {"t": "Maneuvers", "d": 2, "q": "Correct go-around sequence after a full-flaps approach?", "c": ["Apply full flaps then power then pitch up", "Full power then carb heat off then retract all flaps at once then Vy", "Pitch for climb attitude plus full power then carb heat off then flaps incrementally then Vy climb", "Retract all flaps first then apply power"], "a": 2, "e": "Go-around: simultaneously pitch for climb attitude and apply full power, turn off carb heat, retract flaps incrementally per POH (not all at once), then establish Vy climb speed.", "r": "AFH Ch.8; ACS Task X.I"}, {"t": "Maneuvers", "d": 2, "q": "During S-turns across a road when should the wings be level?", "c": ["Only at the initial entry point", "Each time the aircraft crosses the reference line (the road)", "Only when heading directly upwind", "Only at the midpoint of each semi-circle"], "a": 1, "e": "Wings must be level each time the aircraft crosses the reference road. Immediately after crossing the bank increases to its steepest (downwind side) then progressively decreases as the aircraft turns upwind.", "r": "AFH Ch.6"}, {"t": "Maneuvers", "d": 3, "q": "Load factor at 45 degrees bank and effect on stall speed?", "c": ["1.0g \u2014 no effect on stall speed", "1.41g \u2014 stall speed increases by approximately 19 percent", "2.0g \u2014 stall speed doubles", "1.41g \u2014 stall speed increases by approximately 41 percent"], "a": 1, "e": "Load factor at 45 degrees = 1 divided by cosine of 45 = 1.41g. Stall speed increases by the square root of 1.41 which is approximately 1.19 \u2014 about a 19 percent increase. At 60 degrees: LF = 2.0g, stall speed +41%.", "r": "PHAK Ch.4"}, {"t": "Maneuvers", "d": 3, "q": "Why does slow flight require more right rudder than cruise flight?", "c": ["The rudder is physically less effective at slow airspeeds", "P-factor, torque, and spiraling slipstream all increase at high angle of attack and low airspeed causing a left-turning tendency that must be countered", "The aileron takes over rudder function at slow speed", "More rudder is simply needed for coordination at any slow speed"], "a": 1, "e": "The four left-turning tendencies (P-factor, torque, spiraling slipstream, gyroscopic precession) are most pronounced at high angle of attack and low airspeed \u2014 exactly slow flight conditions. Right rudder counters these forces.", "r": "PHAK Ch.5"}, {"t": "Maneuvers", "d": 3, "q": "First action after an engine failure in flight?", "c": ["Declare an emergency on 121.5 MHz", "Attempt engine restart immediately using the emergency checklist", "Establish best glide speed (Vg or Vbg) immediately to maximize gliding range", "Identify and turn toward the nearest airport"], "a": 2, "e": "First priority: establish best glide speed immediately to maximize gliding range and time available. Then: choose a landing site, run the restart checklist, communicate (squawk 7700, 121.5 MHz), and prepare for off-airport landing.", "r": "ACS Task XII; AFH Ch.17"}, {"t": "Maneuvers", "d": 3, "q": "What is ground effect and how does it benefit soft field takeoff?", "c": ["Friction of the wheels on the runway surface", "Reduction of induced drag when flying within approximately one wingspan height AGL \u2014 allows acceleration to Vy in the reduced-drag environment", "Effect of crosswind components near the surface", "Turbulence created by heated ground on warm days"], "a": 1, "e": "Ground effect within approximately one wingspan height AGL reduces induced drag up to 50 percent. In a soft field takeoff, the aircraft stays in ground effect to accelerate to Vy before climbing away.", "r": "PHAK Ch.5; AFH Ch.8"}, {"t": "Maneuvers", "d": 3, "q": "Forward slip is used for what purpose?", "c": ["Increasing airspeed on final approach", "Rapidly losing altitude without increasing airspeed \u2014 useful when overshooting the glidepath or landing without flaps", "Correcting for crosswind during landing \u2014 same as a sideslip", "Increasing lift during short field operations"], "a": 1, "e": "A forward slip creates significant drag through cross-controlling (aileron deflection and opposite rudder), which bleeds altitude without increasing airspeed. Useful when overshooting or when flaps are unavailable.", "r": "AFH Ch.8"}, {"t": "Maneuvers", "d": 3, "q": "Crosswind landing using the wing-low (sideslip) technique \u2014 correct control inputs?", "c": ["Into-wind aileron plus opposite downwind rudder to align the nose with the runway", "Opposite aileron (upwind) plus opposite rudder \u2014 both away from wind", "Both aileron and rudder input into the wind simultaneously", "Crab into the wind throughout and remove the crab just before touchdown"], "a": 0, "e": "Wing-low (sideslip): apply into-wind aileron (upwind wing drops slightly) plus downwind rudder (to align nose with runway centerline). The upwind main gear touches down first.", "r": "AFH Ch.8"}, {"t": "Maneuvers", "d": 4, "q": "The aircraft ahead executes a go-around. Their vortices drift across your flight path at your altitude on final. Best action?", "c": ["Continue the approach \u2014 wake turbulence only affects aircraft directly below", "Stay on centerline \u2014 vortices dissipate within 30 seconds", "Execute a go-around or fly on the upwind side of the runway centerline to avoid the descending and drifting vortices", "Increase airspeed to fly through the wake turbulence zone quickly"], "a": 2, "e": "Wake vortices sink at 400 to 500 fpm and drift downwind. If a preceding aircraft goes around ahead of you, their vortices are at approximately your altitude and drifting. Go-around or fly the upwind side of their track.", "r": "AIM 7-3-5"}, {"t": "Maneuvers", "d": 2, "q": "What is the base-to-final stall and what causes it?", "c": ["A stall caused by excessive speed on final approach", "An accelerated stall caused by excessive bank, back pressure, and skidding turn when overshooting the centerline at low altitude", "A stall caused by flap deployment on final", "A stall caused by flying too slow on the base leg"], "a": 1, "e": "The base-to-final stall occurs when overshooting the centerline causes the pilot to add back pressure and skid the turn with outside rudder rather than increasing bank. This creates an accelerated stall at very low altitude.", "r": "AFH Ch.8; PHAK Ch.4"}, {"t": "Maneuvers", "d": 3, "q": "What is a secondary stall?", "c": ["A stall that occurs on the second attempt at landing", "A stall during recovery from the initial stall when the pilot pulls back too aggressively before sufficient airspeed is regained", "A stall in the traffic pattern below 600 ft AGL", "A stall caused by ice accumulation on the wings"], "a": 1, "e": "A secondary stall occurs during recovery from an initial stall when back pressure is applied too aggressively before adequate airspeed returns, again exceeding the critical angle of attack.", "r": "AFH Ch.4"}, {"t": "Maneuvers", "d": 2, "q": "What is wake turbulence and what generates it?", "c": ["Engine exhaust turbulence trailing behind the aircraft", "Wingtip vortices generated whenever a wing produces lift \u2014 counter-rotating vortices trailing behind the aircraft", "Propwash from large propeller-driven aircraft", "Jet blast from jet engines at low power settings"], "a": 1, "e": "Wake turbulence is generated by the production of lift. High pressure air beneath the wing rolls around the wingtip to low pressure above, creating counter-rotating vortices. Heaviest aircraft at slowest speed produces the worst wake.", "r": "AIM 7-3-2"}, {"t": "Maneuvers", "d": 3, "q": "ACS heading tolerance during straight-and-level flight?", "c": ["plus or minus 5 degrees", "plus or minus 10 degrees", "plus or minus 15 degrees", "plus or minus 20 degrees"], "a": 1, "e": "ACS Task V.A: Straight-and-level flight tolerance is heading plus or minus 10 degrees, altitude plus or minus 100 ft, and airspeed plus or minus 10 kts.", "r": "ACS FAA-S-ACS-6 Task V.A"}, {"t": "Maneuvers", "d": 2, "q": "During an emergency landing off-airport what radio and transponder actions should be taken?", "c": ["No radio action needed \u2014 focus on flying only", "Squawk 7700 and attempt to contact ATC on 121.5 MHz while continuing to fly the aircraft", "Only contact tower if one is nearby", "File a flight plan on 122.8 MHz"], "a": 1, "e": "When declaring an emergency: squawk 7700 on the transponder and attempt to contact ATC on 121.5 MHz. Aviate first \u2014 navigate and communicate are secondary priorities.", "r": "AIM 6-1-1; ACS Task XII"}, {"t": "Maneuvers", "d": 2, "q": "Short field takeoff \u2014 what speed is used for initial climb to clear an obstacle?", "c": ["Vy \u2014 best rate of climb", "Va \u2014 maneuvering speed", "Vx \u2014 best angle of climb until obstacle is cleared then transition to Vy", "Normal rotation speed plus 10 knots"], "a": 2, "e": "Short field takeoff: rotate at the POH-specified speed, climb at Vx (best angle) to clear the obstacle, then transition to Vy for the en-route climb. Always use the POH for specific speeds.", "r": "AFH Ch.8; ACS Task X.E"}, {"t": "Maneuvers", "d": 2, "q": "What is the purpose of the rectangular course ground reference maneuver?", "c": ["To practice steep turns at altitude", "To simulate flying the airport traffic pattern and practice wind drift correction on straight legs and turns", "To practice navigation using ground references", "To develop proficiency in short field operations"], "a": 1, "e": "The rectangular course simulates the traffic pattern and develops the pilot's ability to make proper wind drift corrections on straight legs and coordinate turns of varying bank to maintain a rectangular ground track.", "r": "AFH Ch.6; ACS Task VII.A"}, {"t": "Maneuvers", "d": 2, "q": "How high AGL should ground reference maneuvers generally be performed?", "c": ["300 to 500 ft AGL", "600 to 1000 ft AGL", "1500 to 2000 ft AGL", "2500 to 3000 ft AGL"], "a": 1, "e": "ACS and AFH specify ground reference maneuvers should be performed at 600 to 1000 ft AGL. This provides adequate safety margin while keeping the aircraft close enough to observe ground references clearly.", "r": "AFH Ch.6; ACS Task VII"}, {"t": "Maneuvers", "d": 2, "q": "What speed should be established immediately after an engine failure?", "c": ["Vx \u2014 best angle of climb to reach the nearest airport", "Best glide speed (Vg or Vbg) to maximize gliding range and time available", "Vy \u2014 best rate of climb speed", "Va \u2014 maneuvering speed to protect the airframe"], "a": 1, "e": "Immediately establish best glide speed. In most small aircraft this is listed in the POH. It provides the maximum gliding distance for the altitude available.", "r": "AFH Ch.17; ACS Task XII"}, {"t": "Maneuvers", "d": 3, "q": "During a power-on departure stall why is right rudder critical?", "c": ["Right rudder is not needed during departure stalls", "At high power and high angle of attack, left-turning tendencies (P-factor, torque, slipstream) are at maximum and must be countered aggressively to prevent a snap roll or spin entry", "Right rudder prevents the flaps from extending asymmetrically", "Right rudder helps the aircraft climb at Vx during recovery"], "a": 1, "e": "During power-on stalls at high angle of attack and full power, all four left-turning tendencies are at maximum strength. Without aggressive right rudder, the aircraft may snap left and enter an incipient spin \u2014 extremely dangerous at low altitude.", "r": "AFH Ch.4; PHAK Ch.5"}, {"t": "Systems", "d": 1, "q": "Which instruments are powered by the pitot-static system?", "c": ["Attitude indicator, heading indicator, turn coordinator", "Airspeed indicator, altimeter, vertical speed indicator", "Only the altimeter", "All six primary flight instruments"], "a": 1, "e": "Pitot-static system powers: Airspeed Indicator (pitot plus static pressure), Altimeter (static only), and Vertical Speed Indicator (static only). Gyroscopic instruments use vacuum or electrical power.", "r": "PHAK Ch.8"}, {"t": "Systems", "d": 1, "q": "Color of 100LL aviation gasoline?", "c": ["Red", "Green", "Blue", "Colorless or straw-colored"], "a": 2, "e": "100LL (low-lead) avgas is dyed blue. Regular 100 avgas is green. Jet-A turbine fuel is colorless or light straw-colored. Never use Jet-A in a piston engine.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 1, "q": "When is carburetor ice most likely to form?", "c": ["Only at temperatures below minus 20 C", "At temperatures between 20 and 70 degrees F with high relative humidity even on clear days", "Only when flying through rain or visible moisture", "Only at night when temperatures drop rapidly"], "a": 1, "e": "Carburetor ice can form between 20 and 70 degrees F with high relative humidity. The venturi effect and fuel vaporization in the carburetor can lower its temperature up to 70 degrees F.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 1, "q": "A negative ammeter reading indicates?", "c": ["Battery is fully charged", "Normal alternator charging operation", "Alternator has failed and the battery is discharging to power the electrical system", "Excessive engine RPM causing overcharge"], "a": 2, "e": "A negative ammeter (discharge) reading indicates the alternator is not producing sufficient power and the battery is supplying current to the electrical system. Shed electrical load and land.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 2, "q": "When should carburetor heat be applied?", "c": ["Only when engine roughness is already detected", "Preventively any time conditions favor icing: 20 to 70 degrees F with visible moisture, fog, or high humidity", "Only during descent and not during cruise", "Never on a fuel-injected engine regardless of conditions"], "a": 1, "e": "Apply carb heat preventively when icing conditions exist. Apply full carb heat \u2014 partial carb heat can partially melt ice, allowing it to refreeze in a more dangerous location.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 2, "q": "Pitot tube fully blocked with no drain hole open \u2014 how does the ASI behave?", "c": ["ASI reads zero", "ASI acts like an altimeter \u2014 reads higher when climbing and lower when descending", "ASI freezes at the speed when blockage occurred", "ASI is unaffected because the static port still functions"], "a": 1, "e": "With pitot fully blocked and no drain, trapped pressure cannot equalize with altitude changes. Climbing = ASI reads higher (acts like altimeter). Descending = reads lower.", "r": "PHAK Ch.8"}, {"t": "Systems", "d": 2, "q": "Purpose of the magneto check during runup?", "c": ["Ensure the battery is fully charged for start", "Verify each magneto operates independently and that RPM drop is within published limits", "Check alternator output and charging rate", "Prime the engine fuel system for takeoff"], "a": 1, "e": "The magneto check verifies each magneto is operational by switching from BOTH to each individual magneto. Typical acceptable drop is 125 RPM maximum per magneto and 50 RPM maximum differential between the two.", "r": "POH; AFH Ch.2"}, {"t": "Systems", "d": 2, "q": "Alternate static source \u2014 effect on pitot-static instruments?", "c": ["No change \u2014 alternate static is perfectly calibrated", "ASI reads lower, altimeter reads lower, VSI spikes upward", "ASI slightly HIGH, altimeter slightly HIGH, VSI momentarily DOWN then corrects", "Only the altimeter is affected; ASI and VSI unchanged"], "a": 2, "e": "Cockpit air is at slightly lower pressure than outside due to ram-air effects. Using alternate static: ASI reads slightly high, altimeter reads slightly high, and VSI deflects downward momentarily before correcting.", "r": "PHAK Ch.8; POH"}, {"t": "Systems", "d": 2, "q": "What causes the graveyard spiral?", "c": ["A failed vacuum system causing the attitude indicator to tumble", "The leans illusion causes the pilot to believe the banked turn is straight and level; pulling back to stop descent only tightens the spiral", "Loss of engine power combined with a coordinated turn", "Relying only on outside visual references in deteriorating visibility"], "a": 1, "e": "Graveyard spiral: the leans cause the pilot to sense a banked turn as straight and level. Pulling back to stop descent tightens the spiral rather than stopping it. Trust the attitude indicator.", "r": "AIM 8-1-5; PHAK Ch.17"}, {"t": "Systems", "d": 3, "q": "Water found in a fuel sump sample \u2014 what does it look like and what should you do?", "c": ["Blue tint throughout \u2014 normal fuel additive, safe to fly", "Clear globules or drops at the bottom \u2014 drain multiple samples until obtaining pure blue fuel; do not fly with contaminated fuel", "Cloudy appearance throughout \u2014 safe after agitating the fuel", "Air bubbles at the surface \u2014 safe to fly"], "a": 1, "e": "Water is denser than avgas and sinks. It appears as clear globules or drops at the bottom of the sample cup. Drain multiple sump samples until obtaining pure blue fuel with no globules.", "r": "PHAK Ch.7; AFH Ch.2"}, {"t": "Systems", "d": 3, "q": "Heading indicator precession \u2014 typical rate and corrective action?", "c": ["Up to 1 degree per minute \u2014 realign every 5 minutes", "Up to 3 degrees per 15 minutes \u2014 realign with magnetic compass during straight-and-level unaccelerated flight every 10 to 15 minutes", "Never precesses if the instrument is functioning properly", "Fixed by the deviation card installed in the cockpit"], "a": 1, "e": "Gyroscopic precession causes the DI to drift up to 3 degrees per 15 minutes. Periodically realign with the magnetic compass during straight-and-level, unaccelerated, unturning flight.", "r": "PHAK Ch.8"}, {"t": "Systems", "d": 3, "q": "What is P-factor and when is it most pronounced?", "c": ["Power factor \u2014 ratio of engine efficiency to fuel consumption", "Asymmetric blade effect: at high AoA the descending propeller blade has a greater angle of attack and produces more thrust than the ascending blade causing a left-turning tendency; most pronounced at high power and low airspeed", "Precession of the directional gyro caused by aircraft maneuvering", "Pitch factor relating angle of attack to lift coefficient in high-performance aircraft"], "a": 1, "e": "P-factor: at high angles of attack the descending (right-side) prop blade has a greater relative angle of attack and produces more thrust. This asymmetric thrust causes a left-turning tendency most pronounced in slow flight and climb.", "r": "PHAK Ch.5"}, {"t": "Systems", "d": 3, "q": "Fuel-injected engine vs carbureted engine \u2014 difference in icing risk?", "c": ["Fuel-injected engines have more carburetor ice risk", "Fuel-injected engines cannot develop carburetor ice (no carburetor) but air induction icing can occur at the inlet or air filter", "Fuel injection completely eliminates all icing-related risk", "Both types of engines have identical icing risk under the same conditions"], "a": 1, "e": "No carburetor = no carburetor ice. However fuel-injected engines can suffer induction icing at the air filter or inlet in freezing fog or visible moisture conditions. An alternate air source is provided for this.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 3, "q": "Suction gauge reads below the green arc \u2014 what does this indicate?", "c": ["Normal operation \u2014 green arc is just a reference", "Low engine oil pressure \u2014 unrelated to suction gauge", "Vacuum system failure \u2014 attitude indicator and heading indicator may be unreliable; transition to partial panel procedures", "Alternator failure \u2014 electrical instruments will fail next"], "a": 2, "e": "Suction gauge below the green arc (typically 4.5 to 5.4 in Hg) indicates insufficient vacuum for the vacuum-driven attitude indicator and heading indicator. These instruments may give unreliable or failing readings.", "r": "PHAK Ch.8"}, {"t": "Systems", "d": 2, "q": "What does gyroscopic rigidity mean and which instruments use this property?", "c": ["A spinning gyroscope resists changes to its axis of rotation \u2014 used in the attitude indicator and heading indicator", "Gyroscopes always point toward magnetic north and are used in the magnetic compass", "Gyroscopes spin in sync with engine RPM and are used in the tachometer", "Gyroscopes resist vibration and are used in the altimeter for smoothing"], "a": 0, "e": "Rigidity in space: a spinning gyroscope resists any change to its axis orientation. Both the attitude indicator and heading indicator use this property. The turn coordinator uses gyroscopic precession rather than rigidity.", "r": "PHAK Ch.8"}, {"t": "Systems", "d": 1, "q": "What does the Vertical Speed Indicator (VSI) measure and does it have any lag?", "c": ["Actual instantaneous climb rate with no lag \u2014 most accurate instrument", "Rate of change of static pressure indicating climb or descent rate \u2014 has a 6 to 9 second lag for accurate readings", "Rate of change of airspeed used for energy management", "Angle of attack converted to feet per minute \u2014 no lag"], "a": 1, "e": "The VSI uses a calibrated leak to measure the rate of change of static pressure. It shows trend immediately but requires 6 to 9 seconds to stabilize at the accurate rate.", "r": "PHAK Ch.8"}, {"t": "Systems", "d": 2, "q": "What does it mean when oil pressure reads zero immediately after engine start?", "c": ["Normal \u2014 takes time for oil to circulate", "Indication of a serious lubrication failure \u2014 shut down immediately to prevent engine damage", "Only a problem if the oil temperature also rises", "The gauge is probably faulty \u2014 continue the flight"], "a": 1, "e": "Positive oil pressure should appear within approximately 30 seconds of engine start. If oil pressure does not register within this time, shut the engine down immediately. Operating without oil pressure causes catastrophic engine damage in seconds.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 3, "q": "Magnetic compass acceleration and turning errors \u2014 what do ANDS and OSUN mean?", "c": ["ANDS = Accurate North Detection System; OSUN = Old Sun navigation", "Accelerate-North Decelerate-South on east-west headings. Overshoot-North Undershoot-South when turning through north and south in the northern hemisphere", "ANDS and OSUN are not real aviation acronyms", "They describe compass deviation in different geographic regions"], "a": 1, "e": "ANDS: On east or west headings, acceleration causes the compass to deflect toward North; deceleration toward South. OSUN: In turns the compass overshoots when turning to a northerly heading and undershoots turning to a southerly heading in the northern hemisphere.", "r": "PHAK Ch.8"}, {"t": "Systems", "d": 2, "q": "What is the function of the attitude indicator and what type of error can affect it?", "c": ["Shows magnetic heading \u2014 affected by compass variation", "Shows pitch and bank attitude using gyroscopic rigidity \u2014 may show slight precession error after prolonged coordinated turns", "Shows rate and direction of turn \u2014 affected by ball displacement", "Shows vertical speed \u2014 affected by static port blockage"], "a": 1, "e": "The attitude indicator uses gyroscopic rigidity in space to display pitch and bank attitude relative to the horizon. After sustained coordinated turns, slight precession can occur causing a small apparent bank upon returning to straight and level.", "r": "PHAK Ch.8"}, {"t": "Systems", "d": 3, "q": "Oil temperature gauge reads in the red arc. What should you do?", "c": ["Continue the flight \u2014 red arcs are just advisory", "Land as soon as practicable; reduce power, enrich mixture, check oil pressure, consider opening cowl flaps to increase cooling", "Increase power to generate more oil circulation", "Ignore it if the oil pressure is still in the green"], "a": 1, "e": "Red arc on any engine instrument indicates a dangerous operating condition. High oil temperature can indicate low oil quantity, a blocked oil cooler, or excessive engine load. Reduce power, allow cooling, and land as soon as practicable.", "r": "PHAK Ch.7; POH"}, {"t": "Systems", "d": 2, "q": "What is the purpose of the primer before engine start?", "c": ["To lubricate the cylinders before startup", "To inject fuel directly into the cylinders or intake manifold to aid cold engine starting by enriching the initial mixture", "To pressurize the fuel system for the fuel injectors", "To purge air from the fuel lines before start"], "a": 1, "e": "The primer injects raw fuel directly into the cylinders or intake manifold to create a combustible mixture for cold starts. Excess priming can cause hydraulic lock or fire. Always follow POH instructions.", "r": "PHAK Ch.7; POH"}, {"t": "Systems", "d": 3, "q": "What is torque as a left-turning tendency and when is it most pronounced?", "c": ["Engine vibration \u2014 affects all flight phases equally", "Reaction to the clockwise engine and propeller rotation causes the aircraft to roll to the left; most pronounced at high power and low airspeed", "Torque only affects tailwheel aircraft", "Torque is only present during aerobatic maneuvers"], "a": 1, "e": "Torque: Newton's third law \u2014 clockwise engine/propeller rotation causes an equal and opposite counterclockwise (left roll) reaction on the aircraft. Most pronounced at high power and low airspeed such as during takeoff and climb.", "r": "PHAK Ch.5"}, {"t": "Systems", "d": 2, "q": "What does a positive ammeter reading indicate?", "c": ["Battery is discharging and needs replacement", "The alternator is producing power and the electrical system is operating normally", "Excessive electrical load \u2014 shed unnecessary equipment", "Alternator failure with battery backup active"], "a": 1, "e": "A positive ammeter reading indicates the alternator is producing power and the electrical system is operating normally. Monitor for any sudden change to a negative reading.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 2, "q": "The turn coordinator displays what information?", "c": ["Only the rate of turn in degrees per second", "Rate of turn and coordination (slip or skid) via the ball \u2014 standard rate equals 3 degrees per second or 360 degrees in 2 minutes", "Only slip or skid via the inclinometer ball", "Pitch attitude and bank angle like the attitude indicator"], "a": 1, "e": "Turn coordinator displays: (1) rate and approximate direction of turn via the miniature aircraft symbol, and (2) coordination via the inclinometer ball. Standard rate turn is 3 degrees per second (360 in 2 minutes).", "r": "PHAK Ch.8"}, {"t": "Systems", "d": 3, "q": "Pitot tube blocked with drain hole open \u2014 how does the ASI behave?", "c": ["ASI acts like an altimeter", "ASI reads zero because no pitot pressure reaches the instrument", "ASI freezes at the speed when blockage occurred", "ASI reads correctly from static port alone"], "a": 1, "e": "When the pitot tube is blocked but the drain hole is open, pitot pressure drains away. The ASI reads zero because there is no pitot pressure to create a differential with static. Unlike fully blocked (no drain) which acts like an altimeter.", "r": "PHAK Ch.8"}, {"t": "Aeromedical", "d": 1, "q": "I'M SAFE checklist \u2014 what does each letter represent?", "c": ["Instruments Mixture Speed Altitude Fuel Engine", "Illness Medication Stress Alcohol Fatigue Emotion \u2014 personal fitness self-assessment before flight", "Ice Moisture Storms Airspace Fog Equipment", "Ignition Magnetos Stall speed AOA Fuel ELT"], "a": 1, "e": "I'M SAFE: Illness (am I sick?), Medication (any impairing drugs?), Stress (psychological condition?), Alcohol (within 8-hour and 0.04% BAC limits?), Fatigue (adequately rested?), Emotion (emotionally stable?).", "r": "AIM 8-1-1; PHAK Ch.17"}, {"t": "Aeromedical", "d": 1, "q": "Night vision begins to deteriorate from hypoxia above approximately what altitude?", "c": ["3000 ft MSL", "5000 ft MSL", "10000 ft MSL", "14000 ft MSL"], "a": 1, "e": "Night vision is the first faculty affected by hypoxia, beginning to deteriorate at approximately 5000 ft MSL. Supplemental oxygen is recommended for night flights above 5000 ft.", "r": "AIM 8-1-2"}, {"t": "Aeromedical", "d": 1, "q": "Above what altitude must the pilot use supplemental oxygen continuously?", "c": ["Above 12500 ft MSL", "Above 14000 ft MSL", "Above 15000 ft MSL", "Above 18000 ft MSL"], "a": 1, "e": "14 CFR 91.211: Above 14000 ft MSL the pilot must use supplemental oxygen for the entire duration of flight.", "r": "14 CFR 91.211"}, {"t": "Aeromedical", "d": 1, "q": "Passengers must be provided supplemental oxygen above what altitude?", "c": ["Above 12500 ft MSL", "Above 14000 ft MSL", "Above 15000 ft MSL", "Above 18000 ft MSL"], "a": 2, "e": "14 CFR 91.211(a)(3): Above 15000 ft MSL the PIC must provide supplemental oxygen to each occupant.", "r": "14 CFR 91.211(a)(3)"}, {"t": "Aeromedical", "d": 1, "q": "Maximum blood alcohol content allowed when acting as a crewmember?", "c": ["0.02 percent", "0.04 percent", "0.06 percent", "0.08 percent"], "a": 1, "e": "14 CFR 91.17(a)(4): Blood alcohol concentration must be less than 0.04 percent. Note this is lower than the legal driving limit in most states.", "r": "14 CFR 91.17(a)(4)"}, {"t": "Aeromedical", "d": 2, "q": "Symptoms of hyperventilation and how is it treated?", "c": ["Identical to hypoxia but only occurs at high altitude; treat with descent", "Lightheadedness, tingling fingers, dizziness, muscle spasms from excess CO2 loss; treat by consciously slowing breathing, talking aloud, or breathing into a bag", "Treat immediately with supplemental oxygen", "Symptoms only at altitude; no treatment"], "a": 1, "e": "Hyperventilation results from breathing too rapidly and exhausting CO2. Symptoms: tingling, dizziness, visual disturbances. Treatment: slow breathing consciously, talk aloud, or breathe into a bag. Check altitude first to differentiate from hypoxia.", "r": "AIM 8-1-3"}, {"t": "Aeromedical", "d": 2, "q": "What is the leans illusion?", "c": ["The sensation of pitching up when actually in level flight", "A false sensation of being in a bank after returning to straight-and-level flight \u2014 the pilot may unconsciously re-bank to restore the feel of level", "A visual illusion caused by sloping terrain beneath the aircraft", "Only occurs when an instrument fails"], "a": 1, "e": "The leans: gradual bank develops below the vestibular detection threshold. Upon returning to level the pilot senses the opposite bank and may unconsciously re-bank to feel level again.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 2, "q": "Carbon monoxide poisoning \u2014 symptoms and immediate action?", "c": ["Excessive oxygen \u2014 treat by reducing oxygen flow", "Colorless odorless combustion byproduct entering cabin through heater leaks; symptoms: headache, drowsiness, gray vision; action: shut off heater, open fresh air vents, land immediately, use supplemental oxygen", "Nitrogen toxicity requiring immediate descent", "Only affects smokers with pre-existing lung conditions"], "a": 1, "e": "CO is colorless and odorless. Sources include heater exhaust leaks. Symptoms: headache, drowsiness, gray tint to vision, impaired judgment. Immediate action: shut off cabin heat, open fresh air vents, land as soon as possible, use supplemental oxygen.", "r": "AIM 8-1-4"}, {"t": "Aeromedical", "d": 2, "q": "Visual illusion causing a pilot to fly an unexpectedly low approach at night over featureless terrain?", "c": ["Wide runway illusion causing the pilot to fly too high", "Black hole approach \u2014 absence of visual cues causes pilots to fly a dangerously low approach; always use VASI or PAPI", "Narrow runway illusion causing the pilot to fly too low", "Upslope runway illusion making the runway appear longer"], "a": 1, "e": "Black hole approach illusion: landing toward unlighted terrain at night without surrounding visual cues. Pilots tend to fly an approach that appears visually correct but is actually dangerously low. Always use VASI, PAPI, or ILS.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 2, "q": "Upslope runway creates what visual illusion and what is the hazard?", "c": ["Makes aircraft appear lower than it is \u2014 pilot tends to fly a high approach", "Makes aircraft appear higher than it is \u2014 pilot may fly a lower-than-normal approach and undershoot the runway", "Has no effect on approach angle perception", "Creates the same illusion as a downslope runway"], "a": 1, "e": "An upsloping runway appears shorter and creates the illusion that the aircraft is higher than normal. The pilot may respond by flying lower, actually undershooting. The opposite effect occurs with a downsloping runway.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 2, "q": "Euphoria is an early symptom of which condition?", "c": ["Hyperventilation \u2014 too much breathing", "Hypoxia \u2014 early euphoria and false sense of well-being are insidious symptoms that may prevent the pilot from recognizing the condition", "Carbon monoxide poisoning", "Dehydration at altitude"], "a": 1, "e": "Hypoxia is insidious because early symptoms include euphoria and an exaggerated sense of well-being along with impaired judgment. The pilot may not realize anything is wrong until incapacitation.", "r": "AIM 8-1-2"}, {"t": "Aeromedical", "d": 3, "q": "Pilot experiences tingling fingers and dizziness on approach at 6000 ft after a 2-hour flight \u2014 most likely cause?", "c": ["Hypoxia \u2014 6000 ft is too high without supplemental oxygen", "Hyperventilation from anxiety or stress \u2014 slow breathing consciously to diagnose and treat", "Carbon monoxide poisoning from the heater system", "Dehydration causing electrolyte imbalance"], "a": 1, "e": "At 6000 ft hypoxia is unlikely for healthy pilots (O2 required above 12500 ft). Tingling and dizziness during a potentially stressful approach phase is more consistent with hyperventilation. Slow the breathing rate to treat.", "r": "AIM 8-1-3"}, {"t": "Aeromedical", "d": 3, "q": "What is the Coriolis illusion and when does it occur?", "c": ["A visual illusion from a sloping runway surface", "Occurs when a pilot moves their head in a different plane while in a sustained turn \u2014 the inner ear senses rotation in multiple planes creating a strong tumbling or spinning sensation", "The sensation of climbing when power is suddenly increased", "A compass reading error in polar regions due to magnetic anomalies"], "a": 1, "e": "Coriolis illusion: when a pilot tilts their head in a different plane during a sustained turn, the semicircular canals receive conflicting signals causing a powerful and disorienting tumbling or spinning sensation. Avoid sudden head movements in IMC.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 3, "q": "Last drink at 8 PM. Earliest legal departure time as a crewmember?", "c": ["Midnight \u2014 4 hours is sufficient", "4:00 AM the following day \u2014 8 hours after the last drink", "10:00 PM \u2014 2 hours is enough if you feel fine", "Any time you personally feel capable of flying safely"], "a": 1, "e": "14 CFR 91.17(a)(2): 8-hour bottle-to-throttle minimum. Last drink at 8 PM means earliest legal departure is 4:00 AM. The FAA recommends 24 hours from last drink for maximum safety.", "r": "14 CFR 91.17(a)(2)"}, {"t": "Aeromedical", "d": 3, "q": "A pilot is on an OTC medication and feels no side effects. Can they legally and safely fly?", "c": ["Yes \u2014 no perceived side effects means the medication is safe for flight", "No \u2014 many OTC medications have physiological effects on aviation performance even without noticeable symptoms; always consult an AME before flying on any medication", "Yes \u2014 over-the-counter medications are always permitted for flight", "Only prescription medications require AME consultation before flying"], "a": 1, "e": "Many OTC medications including antihistamines, decongestants, and some pain relievers can cause sedation, impaired judgment, or other effects without the pilot noticing. Always consult an Aviation Medical Examiner (AME) before flying on any medication.", "r": "AIM 8-1-1"}, {"t": "Aeromedical", "d": 2, "q": "At what altitude between 12500 and 14000 ft MSL must the pilot use supplemental oxygen?", "c": ["Never \u2014 O2 only required above 14000", "When this altitude range is flown for more than 30 minutes", "Anytime above 12500 MSL regardless of duration", "Only above 13500 MSL"], "a": 1, "e": "14 CFR 91.211(a)(1): Between 12500 and 14000 ft MSL, the required flight crewmember must use supplemental oxygen for the portions of flight exceeding 30 minutes at that altitude band.", "r": "14 CFR 91.211(a)(1)"}, {"t": "Aeromedical", "d": 2, "q": "What is spatial disorientation?", "c": ["Becoming geographically lost during a cross-country flight", "A false sense of the aircraft's attitude, motion, or position caused by misleading sensory inputs \u2014 corrected by trusting and flying by flight instruments", "A condition that only occurs when instruments fail", "A gradual disorientation from fatigue over long flights"], "a": 1, "e": "Spatial disorientation occurs when the vestibular system and other senses provide misleading information about aircraft attitude or motion. In IMC, pilots must disregard sensory feelings and trust flight instruments.", "r": "AIM 8-1-5; PHAK Ch.17"}, {"t": "Aeromedical", "d": 2, "q": "Narrow runway illusion \u2014 what approach error does it cause?", "c": ["Pilot flies a lower than normal approach \u2014 risk of undershooting", "Pilot flies a higher than normal approach \u2014 risk of landing long or floating", "No effect on approach angle perception", "Same as wide runway illusion but less severe"], "a": 0, "e": "A narrow runway appears to be farther away, making the pilot think the aircraft is higher than normal. This leads to a lower approach and risk of undershooting or hitting obstacles short of the runway.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 3, "q": "What is the graveyard spin illusion?", "c": ["A visual illusion from spinning runway approach lighting", "During a prolonged spin the body adapts to the rotation and the pilot feels they have stopped. When the spin actually stops, the pilot senses rotation in the opposite direction and may re-enter the spin.", "A spin that develops during the landing flare", "An optical illusion that makes the ground appear to spin during low-level flight"], "a": 1, "e": "During a prolonged spin, the semicircular canals adapt and stop sensing rotation. When the spin is stopped, the sudden change feels like rotation in the opposite direction and the pilot may re-enter the spin to stop the false sensation.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 2, "q": "What is hypoxia and what makes hypemic hypoxia particularly dangerous?", "c": ["Excess oxygen in the bloodstream \u2014 rare at altitude", "Oxygen deficiency at the cellular level. Hypemic hypoxia (carbon monoxide poisoning) is considered particularly dangerous because CO has no color or smell and the pilot may feel fine initially.", "Only occurs above 18000 ft MSL", "Hypoxia only affects unfit or elderly pilots"], "a": 1, "e": "Hypoxia is oxygen deficiency at the cellular level. Types include hypoxic (altitude), hypemic (CO poisoning/anemia), stagnant (circulation failure), and histotoxic (alcohol/drugs). Hypemic hypoxia from CO is insidious because CO is colorless and odorless.", "r": "AIM 8-1-2"}, {"t": "Aeromedical", "d": 3, "q": "A pilot notices their thinking is slowing down and they feel unusually warm and comfortable at FL100 in IMC. What should they suspect?", "c": ["Normal physiological response to cruise flight \u2014 nothing to worry about", "Possible hypoxia \u2014 descend to lower altitude immediately, use supplemental oxygen, and reassess the situation", "Hyperventilation \u2014 increase breathing rate to restore alertness", "Dehydration \u2014 drink water and continue the flight"], "a": 1, "e": "Slowed thinking, warmth, and unusual comfort at altitude are classic hypoxia symptoms. The insidious nature means the pilot may not recognize the impairment. Immediate action: descend, use oxygen, and assess whether flight can safely continue.", "r": "AIM 8-1-2"}, {"t": "Aeromedical", "d": 2, "q": "What is the purpose of the I'M SAFE checklist?", "c": ["To check the aircraft before flight \u2014 same as TOMATO FLAMES", "To provide a personal self-assessment of pilot fitness to fly before each flight, covering the most common human factors that cause accidents", "To check ATC frequencies before flight", "To verify weather is above VFR minimums"], "a": 1, "e": "I'M SAFE is a personal minimums and human factors checklist. A pilot who identifies a concern in any category \u2014 illness, impairing medication, excessive stress, alcohol within limits, fatigue, or emotional distress \u2014 should not fly.", "r": "AIM 8-1-1; PHAK Ch.17"}, {"t": "Aeromedical", "d": 2, "q": "Continuing to fly while knowingly ill, on impairing medication, or while significantly fatigued \u2014 what regulatory concept applies?", "c": ["The pilot must self-certify fitness using the I'M SAFE checklist and may not legally fly if any item is a concern", "Only a medical doctor can ground a pilot", "FAA will notify the pilot if they are unfit to fly", "Self-certification is not required \u2014 it is always the airline's responsibility"], "a": 0, "e": "Pilots are responsible for self-certifying their fitness to fly. The I'M SAFE checklist formalizes this. A pilot who is ill, on impairing medication, excessively fatigued, or emotionally distressed should not exercise pilot privileges.", "r": "14 CFR 61.53; AIM 8-1-1"}, {"t": "Aeromedical", "d": 3, "q": "What does histotoxic hypoxia mean?", "c": ["Hypoxia caused by altitude above 10000 ft", "Hypoxia where the cells cannot use oxygen properly due to a toxic substance such as alcohol or drugs even when oxygen levels are adequate", "Hypoxia caused by low blood circulation", "Hypoxia caused by carbon monoxide binding to hemoglobin"], "a": 1, "e": "Histotoxic hypoxia: cells cannot properly utilize oxygen due to toxic substances like alcohol, narcotics, or certain drugs, even when oxygen partial pressure is adequate. This explains why alcohol significantly worsens altitude effects.", "r": "AIM 8-1-2"}, {"t": "Aeromedical", "d": 2, "q": "What are the two factors that make hypoxia particularly dangerous in aviation?", "c": ["It is very painful and occurs suddenly", "Symptoms can be insidious with the pilot feeling well and even euphoric, and judgment is impaired before the pilot recognizes the problem", "Hypoxia only affects vision so the pilot can still fly instruments", "Hypoxia is easily recognizable by all pilots with proper training"], "a": 1, "e": "Hypoxia is dangerous because: (1) early symptoms include euphoria and a false sense of well-being (insidious onset), and (2) judgment is impaired before the pilot recognizes the problem, preventing appropriate self-corrective action.", "r": "AIM 8-1-2"}, {"t": "Regulations", "d": 2, "q": "Under 14 CFR 91.409, a 100-hour inspection is required for aircraft used for what purpose?", "c": ["Any aircraft flown for personal use", "Aircraft used to carry persons for hire or flight instruction for hire", "All certificated aircraft regardless of use", "Aircraft over 10 years old"], "a": 1, "e": "14 CFR 91.409(b): A 100-hour inspection is required for aircraft used to carry persons for hire or used for flight instruction for hire. It is in addition to, not a replacement for, the annual inspection.", "r": "14 CFR 91.409(b)"}, {"t": "Regulations", "d": 2, "q": "Can a 100-hour inspection be exceeded? If so, by how much?", "c": ["No \u2014 never exceed 100-hour limit", "Yes \u2014 up to 10 hours to fly to a location where the inspection can be performed", "Yes \u2014 up to 5 hours to fly to a location where the inspection can be performed", "Yes \u2014 any amount if the pilot accepts responsibility"], "a": 1, "e": "14 CFR 91.409(b): The 100-hour limitation may be exceeded by not more than 10 hours if necessary to fly the aircraft to a place where the inspection can be done. The excess time must be included in computing the next 100 hours.", "r": "14 CFR 91.409(b)"}, {"t": "Regulations", "d": 3, "q": "A pilot flies an aircraft that requires a type rating without holding that type rating. What regulation applies?", "c": ["14 CFR 61.31 \u2014 a type rating is required to act as PIC of certain large aircraft, turbojet-powered aircraft, or as specified by the FAA", "14 CFR 91.7 \u2014 only airworthiness matters", "No regulation \u2014 type ratings are optional", "14 CFR 61.56 \u2014 only the flight review matters"], "a": 0, "e": "14 CFR 61.31: Type ratings are required for aircraft over 12,500 lbs MGTOW, turbojet-powered aircraft, and other specific aircraft designated by the FAA. Operating without the required type rating is a certificate action offense.", "r": "14 CFR 61.31"}, {"t": "Regulations", "d": 2, "q": "What is the minimum visibility and ceiling for a student pilot to conduct a solo cross-country flight?", "c": ["3 SM and 1000 ft ceiling", "The visibility and ceiling must meet VFR minimums for the airspace AND meet the instructor-set personal minimums in the student's logbook endorsement", "Only VFR minimums apply \u2014 same as any VFR pilot", "5 SM and 3000 ft ceiling"], "a": 1, "e": "14 CFR 61.93 and 61.87: The flight instructor must provide a solo XC endorsement and may set specific weather minimums in the endorsement. The student may not fly if conditions are below either VFR minimums OR the instructor's stated minimums.", "r": "14 CFR 61.93; 61.87"}, {"t": "Regulations", "d": 3, "q": "What does BasicMed allow a private pilot to do that a regular 3rd-class medical does not simplify?", "c": ["Allows flying without any medical review", "Allows private pilots to act as PIC using a regular medical examination by any state-licensed physician rather than an FAA Aviation Medical Examiner \u2014 valid 48 months", "Allows instrument flight without any medical", "Replaces the need for a flight review"], "a": 1, "e": "14 CFR 61.23 and AC 68-1: BasicMed allows pilots to get a medical examination from any state-licensed physician (not necessarily an AME). The exam is valid 48 calendar months and requires completion of an online course every 24 months.", "r": "14 CFR 61.23; AC 68-1"}, {"t": "Regulations", "d": 2, "q": "A pilot has a student pilot certificate. What endorsement is needed before the first solo flight?", "c": ["No endorsement needed \u2014 certificate is sufficient", "An endorsement in the student's logbook from their instructor authorizing solo flight in a specific make and model of aircraft", "Only a medical certificate is required", "A written test must be passed first"], "a": 1, "e": "14 CFR 61.87(n): Before solo flight, a student pilot must have an instructor endorsement in their logbook that specifically authorizes solo in the make and model of aircraft to be flown.", "r": "14 CFR 61.87(n)"}, {"t": "Regulations", "d": 3, "q": "When is a pre-solo written test required and who administers it?", "c": ["Never \u2014 practical evaluation only", "Before the first solo flight \u2014 the student must pass a written test on the applicable regulations and the flight characteristics of the aircraft, administered and graded by the student's instructor", "Only before the checkride", "Only if the student fails the initial oral evaluation"], "a": 1, "e": "14 CFR 61.87(b): Before solo flight, an instructor must administer and grade a written test covering Part 91 rules applicable to student solo flight and the flight characteristics and limitations of the aircraft.", "r": "14 CFR 61.87(b)"}, {"t": "Regulations", "d": 2, "q": "Under 14 CFR 91.111, a pilot must not operate so close to another aircraft as to create what?", "c": ["Any possibility of contact", "A collision hazard", "Turbulence that affects the other aircraft", "Noise in excess of EPA limits"], "a": 1, "e": "14 CFR 91.111(a): No person may operate an aircraft so close to another aircraft as to create a collision hazard.", "r": "14 CFR 91.111(a)"}, {"t": "Regulations", "d": 2, "q": "What does 14 CFR 91.151 require regarding VFR fuel reserves?", "c": ["Only enough fuel to reach destination", "Day: enough fuel to destination plus 30 minutes at cruise. Night: enough fuel to destination plus 45 minutes at cruise.", "Always carry enough fuel for 1 hour beyond destination", "Fuel reserves are only required for IFR flight"], "a": 1, "e": "14 CFR 91.151(a): VFR day requires fuel to reach first intended landing plus 30 minutes at normal cruise. VFR night requires fuel to reach first intended landing plus 45 minutes at normal cruise.", "r": "14 CFR 91.151(a)"}, {"t": "Regulations", "d": 3, "q": "What is a logbook endorsement and what is its legal significance?", "c": ["A social endorsement \u2014 has no legal standing", "A written statement by a certificated flight instructor in the pilot's logbook authorizing specific operations \u2014 legally required for solo, solo XC, and practical tests", "Only required for commercial operations", "Required only after a failed checkride"], "a": 1, "e": "Endorsements by a CFI in a pilot's logbook carry legal weight under 14 CFR Part 61. They certify that training requirements have been met and authorize specific operations. Missing required endorsements can be grounds for certificate action.", "r": "14 CFR 61.87; 61.93; 61.39"}, {"t": "Regulations", "d": 2, "q": "Under 14 CFR 91.119, what altitude must be maintained over open water or sparsely populated areas?", "c": ["500 ft AGL at all times", "500 ft above the surface, except when necessary for takeoff and landing", "1000 ft above the highest obstacle within 2000 ft horizontal", "No specific requirement \u2014 pilot judgment applies"], "a": 1, "e": "14 CFR 91.119(c): Over open water or sparsely populated areas, the pilot must not operate below 500 ft above the surface except when necessary for takeoff or landing.", "r": "14 CFR 91.119(c)"}, {"t": "Regulations", "d": 3, "q": "What is an ELT and when must its battery be replaced?", "c": ["Emergency Landing Transponder \u2014 replaced at every annual", "Emergency Locator Transmitter \u2014 battery must be replaced when 50% of its useful life has expired OR after 1 cumulative hour of use, whichever comes first", "Emergency Locator Transmitter \u2014 replaced every 2 years regardless", "ELTs do not have replacement requirements"], "a": 1, "e": "14 CFR 91.207(c): ELT batteries must be replaced when 50% of their useful life (or useful life of charge) has expired, or after the ELT has been in use for more than 1 cumulative hour. Replacement date must be marked on the outside of the transmitter.", "r": "14 CFR 91.207(c)"}, {"t": "Regulations", "d": 2, "q": "Which of the following is NOT one of the privileges of a private pilot certificate?", "c": ["Acting as PIC for pleasure flights", "Carrying passengers for compensation when splitting fuel costs equally", "Acting as PIC on a revenue-generating charter flight", "Flying in Class D airspace with required equipment"], "a": 2, "e": "14 CFR 61.113(a): Private pilots may not act as PIC of an aircraft for compensation or hire. Revenue-generating charter operations require at minimum a commercial pilot certificate.", "r": "14 CFR 61.113(a)"}, {"t": "Regulations", "d": 3, "q": "What is the difference between a safety pilot and a safety pilot acting as PIC?", "c": ["There is no difference \u2014 safety pilots are always PIC", "A safety pilot may act as required crewmember (not PIC) when the flying pilot maintains PIC status, OR the safety pilot may be designated PIC before the flight begins \u2014 this affects who must meet currency and medical requirements", "Safety pilots never need to meet any currency requirements", "Safety pilots must always be PIC"], "a": 1, "e": "14 CFR 91.109(c): A safety pilot must at minimum hold a private certificate and appropriate medical. If the safety pilot is the required PIC, they log PIC time and must be current. If the flying pilot is PIC, they log PIC and the safety pilot logs SIC. This must be agreed upon before flight.", "r": "14 CFR 91.109(c); 61.51"}, {"t": "Regulations", "d": 2, "q": "What does 14 CFR 91.13 prohibit?", "c": ["Flying faster than Vne", "Operating an aircraft in a careless or reckless manner so as to endanger the life or property of another", "Flying over restricted areas", "Flying at night without position lights"], "a": 1, "e": "14 CFR 91.13(a): No person may operate an aircraft in a careless or reckless manner so as to endanger the life or property of another person. This is one of the most broadly applicable FARs and covers many unsafe behaviors.", "r": "14 CFR 91.13(a)"}, {"t": "Regulations", "d": 2, "q": "A pilot receives a Notice to Comply from the FAA regarding an alleged violation. What is the best first step?", "c": ["Ignore it \u2014 verbal notices have no legal force", "Consult an aviation attorney familiar with FAR enforcement before responding", "Immediately admit fault and accept any penalty", "Report the issue to NTSB"], "a": 1, "e": "FAA enforcement actions have serious consequences including certificate suspension or revocation. Consulting an aviation attorney (or the AOPA Legal Services Plan) before responding to any FAA violation notice is strongly recommended.", "r": "FAA Order 2150.3"}, {"t": "Regulations", "d": 1, "q": "What is the minimum flight visibility for VFR flight in Class E airspace below 10,000 ft MSL?", "c": ["1 SM", "2 SM", "3 SM", "5 SM"], "a": 2, "e": "14 CFR 91.155: The minimum flight visibility for VFR flight in Class E airspace below 10,000 ft MSL is 3 statute miles.", "r": "14 CFR 91.155"}, {"t": "Regulations", "d": 2, "q": "When must a pilot report a change of address to the FAA Civil Aviation Registry?", "c": ["Within 30 days of the address change", "Within 60 days of the address change \u2014 14 CFR 61.60", "Annually when renewing the certificate", "Only when requesting a new certificate"], "a": 1, "e": "14 CFR 61.60: A certificated pilot must notify the FAA Civil Aviation Registry in Oklahoma City of any change of permanent mailing address within 60 days of the change. Failure to do so renders the certificate invalid for exercising privileges.", "r": "14 CFR 61.60"}, {"t": "Regulations", "d": 3, "q": "Under what conditions may a private pilot act as PIC of an aircraft for a charitable organization?", "c": ["Any time the organization is a registered nonprofit", "Only under specific conditions outlined in 14 CFR 61.113(d) \u2014 charity flights operated under a specific FAA exception, typically requiring advance DOT/FAA authorization", "Never \u2014 private pilots cannot fly for any charitable purpose", "Anytime the pilot charges nothing personally"], "a": 1, "e": "14 CFR 61.113(d): A private pilot may act as PIC of an aircraft in connection with a business or employment if the flight is only incidentally related to business and is not a primary business function. Charitable flights for compensation are a complex area requiring specific FAA authorization.", "r": "14 CFR 61.113(d)"}, {"t": "Regulations", "d": 2, "q": "What is the purpose of the NASA Aviation Safety Reporting System (ASRS)?", "c": ["To report accidents to the NTSB", "A confidential voluntary reporting system for aviation incidents and near-misses \u2014 filing a report within 10 days provides limited immunity from FAA certificate action for inadvertent violations", "To report mechanical defects to aircraft manufacturers", "Required by FAA for all commercial operators"], "a": 1, "e": "The NASA ASRS (AIM 7-6-1): A voluntary confidential reporting system that provides limited immunity from FAA enforcement for inadvertent violations IF a report is filed within 10 days of the incident. Does not protect from criminal violations or accidents.", "r": "AIM 7-6-1; AC 00-46"}, {"t": "Weather", "d": 2, "q": "What is a convective SIGMET and how long is it valid?", "c": ["Same as a regular SIGMET \u2014 4 hours", "A SIGMET specifically for severe convective weather (thunderstorms) covering an area 3000 sq mi or more, or embedded thunderstorms, or tornadoes, or hail 3/4 inch or greater \u2014 valid 2 hours", "A SIGMET issued by pilots only \u2014 valid until conditions end", "A SIGMET for volcanic ash only \u2014 valid 6 hours"], "a": 1, "e": "Convective SIGMETs (WST) cover severe or extreme convective weather including tornadoes, hail at or above 3/4 inch diameter, severe or extreme turbulence, severe icing, and widespread thunderstorms. Issued hourly (or special), valid 2 hours.", "r": "AIM 7-1-6"}, {"t": "Weather", "d": 2, "q": "What is a PIREP and what format does it follow?", "c": ["Pilot Route Evaluation Plan \u2014 informal pilot checklist", "Pilot Report \u2014 standardized report from a pilot in flight providing actual weather observations; includes: UA/UUA, location, time, altitude, aircraft type, sky, temp, wind, turbulence, icing, remarks", "Pressure Indication Reference for En-route Planning \u2014 a weather product", "Published Instrument Route Entry Procedure \u2014 an IFR document"], "a": 1, "e": "PIREPs (Pilot Reports) provide real-time weather data from pilots in flight. Format: type (UA=routine, UUA=urgent), location (3-letter identifier), time (UTC), altitude (FL), aircraft type (AC), sky (SK), temperature (TA), wind (WV), turbulence (TB), icing (IC), remarks (RM).", "r": "AIM 7-1-21"}, {"t": "Weather", "d": 3, "q": "What is the standard atmosphere pressure at sea level in inches of mercury?", "c": ["29.82 in Hg", "29.92 in Hg", "30.02 in Hg", "28.92 in Hg"], "a": 1, "e": "The International Standard Atmosphere (ISA) defines sea level standard pressure as 29.92 in Hg (1013.25 millibars). This is the altimeter setting used to obtain pressure altitude.", "r": "PHAK Ch.8, Ch.12"}, {"t": "Weather", "d": 2, "q": "A METAR reports winds as 27015G25KT. What does this mean?", "c": ["Winds from 270 degrees at 15 knots with gusts to 25 knots", "Winds from 270 degrees at 25 knots gusting to 15 knots", "Winds variable from 270 to 150 degrees at 25 knots", "Winds from 270 at 15 knots with visibility 25 SM"], "a": 0, "e": "In a METAR, wind format is: direction (270 = from the west), speed (15 knots), G = gusts, gust speed (25 knots). So 27015G25KT = wind from 270 degrees at 15 knots with gusts to 25 knots.", "r": "AIM 7-1-30"}, {"t": "Weather", "d": 2, "q": "What is the difference between IFR and LIFR conditions?", "c": ["There is no difference \u2014 IFR and LIFR are the same", "IFR is ceiling 500 to below 1000 ft and/or visibility 1 to below 3 SM. LIFR (Low IFR) is ceiling below 500 ft and/or visibility below 1 SM.", "IFR is any ceiling below 3000 ft. LIFR is any ceiling below 1000 ft.", "LIFR is only used in military aviation"], "a": 1, "e": "Aviation weather flight categories: VFR (ceiling above 3000 ft, vis above 5 SM), MVFR (ceiling 1000-3000 ft and/or vis 3-5 SM), IFR (ceiling 500 to below 1000 ft and/or vis 1 to below 3 SM), LIFR (ceiling below 500 ft and/or vis below 1 SM).", "r": "AIM 7-1-30"}, {"t": "Weather", "d": 3, "q": "What is a cold front occlusion and a warm front occlusion?", "c": ["These are the same weather phenomenon called an occluded front", "Cold front occlusion: the cold front catches and lifts the warm front \u2014 colder air behind. Warm front occlusion: the air ahead of the warm front is colder \u2014 less common in the US.", "Occluded fronts do not have subtypes", "An occluded front is simply a stationary front that has changed direction"], "a": 1, "e": "An occluded front forms when a cold front overtakes a warm front. In a cold front occlusion (more common), the air behind the cold front is colder than the air ahead of the warm front. In a warm front occlusion, the air ahead of the warm front is colder.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "What does a METAR SKY cover of OVC010 indicate?", "c": ["Overcast clouds at 10000 ft", "Overcast clouds at 1000 ft AGL \u2014 this is the ceiling", "Overcast clouds at 100 ft AGL", "10 percent overcast cloud coverage"], "a": 1, "e": "In a METAR, SKC=sky clear, FEW=1-2 oktas, SCT=3-4 oktas scattered, BKN=5-7 oktas broken (defines ceiling), OVC=8 oktas overcast (defines ceiling). Heights are in hundreds of feet AGL. OVC010 = overcast at 1000 ft AGL.", "r": "AIM 7-1-30"}, {"t": "Weather", "d": 2, "q": "What is the freezing level and how does it affect flight planning?", "c": ["The altitude at which cabin temperature reaches 0 degrees C", "The altitude at which the ambient air temperature is 0 degrees C \u2014 above this altitude temperatures are below freezing and structural icing is possible in visible moisture", "The altitude at which fuel begins to freeze in the tanks", "The altitude at which carburetor ice is most likely"], "a": 1, "e": "The freezing level is the altitude at which the ambient air temperature equals 0 degrees C. Flight above the freezing level in visible moisture creates icing conditions for the airframe. Multiple freezing levels can exist if temperature inversions are present.", "r": "PHAK Ch.12; AIM 7-1-22"}, {"t": "Weather", "d": 3, "q": "What is a pressure gradient and how does it affect wind speed?", "c": ["Pressure gradient is the difference in pressure between engine intake and exhaust \u2014 affects engine performance", "Pressure gradient is the rate of pressure change per unit horizontal distance. A steep pressure gradient (closely spaced isobars) indicates stronger winds. A shallow gradient (widely spaced isobars) indicates light winds.", "Pressure gradient only affects altimeter readings", "Pressure gradient is only relevant for IFR flight planning"], "a": 1, "e": "The pressure gradient is the rate of change of pressure over horizontal distance, shown by spacing of isobars on surface analysis charts. Closely spaced isobars indicate a steep gradient and strong winds. Widely spaced isobars indicate light winds.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "What is orographic lift and what type of clouds does it produce?", "c": ["Lift created by hot asphalt runways in summer", "Lift created when air is forced to rise over terrain \u2014 produces orographic clouds including cap clouds, lenticular clouds, and can trigger significant thunderstorm activity", "Lift created by jet engines \u2014 only applies to jets", "Lift created by temperature inversions"], "a": 1, "e": "Orographic lift occurs when moving air is forced upward by terrain. As air rises it cools, potentially reaching the dewpoint and forming clouds. This can produce cap clouds, lenticular clouds (wave), and can trigger convective activity on the windward side.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "What does a center weather advisory (CWA) provide?", "c": ["A replacement for the GFA for a specific center's area", "An unscheduled weather advisory issued by an ARTCC meteorologist for conditions that don't meet SIGMET criteria but may affect the safety of IFR operations or VFR flight in the area \u2014 valid 2 hours", "A daily weather briefing for center aircraft only", "A forecast issued by the NWS for oceanic operations"], "a": 1, "e": "Center Weather Advisories (CWAs) are issued by ARTCC meteorologists for weather that doesn't meet SIGMET criteria but may affect safety. They cover the ARTCC area of responsibility and are valid for up to 2 hours.", "r": "AIM 7-1-25"}, {"t": "Weather", "d": 3, "q": "What is frost and why is it dangerous to aircraft?", "c": ["Frost is essentially the same as light snow \u2014 it melts on takeoff and is not dangerous", "Frost is ice crystals that form on aircraft surfaces when the surface temperature is at or below the dewpoint AND below freezing. Even light frost can significantly disrupt airflow over the wing and reduce lift by up to 30%.", "Frost is only dangerous on the windshield \u2014 not on wings", "Frost is only dangerous for large transport aircraft"], "a": 1, "e": "Frost forms when a surface is at or below the dewpoint and below 0 degrees C. Even a thin layer of frost significantly disrupts the smooth flow of air over the wing by increasing surface roughness, reducing lift up to 30 percent and increasing drag. All frost must be removed before flight.", "r": "PHAK Ch.12; AC 135-17"}, {"t": "Weather", "d": 2, "q": "What is a stability index and what does a high/low value indicate?", "c": ["A number indicating aircraft stability in turbulence \u2014 higher is more stable", "Atmospheric stability indices such as the Lifted Index measure the potential for thunderstorm development. A negative Lifted Index indicates instability and thunderstorm potential. Positive values indicate stable air.", "A measure of autopilot performance", "An instrument indicator in the cockpit"], "a": 1, "e": "Stability indices like the Lifted Index compare the temperature of a parcel of air lifted to 500 mb with the actual temperature at that level. Negative values indicate the parcel is warmer than its environment (unstable), suggesting convective potential. Values below -6 suggest severe thunderstorms.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "What weather phenomenon is associated with a rapidly falling barometric pressure?", "c": ["Improving VFR conditions", "Approaching low pressure system \u2014 typically deteriorating weather, increasing winds, and possible precipitation", "Fog formation", "Stable high pressure settling in"], "a": 1, "e": "A rapidly falling barometric pressure indicates an approaching low pressure system. Low pressure systems are associated with rising air, clouds, precipitation, and generally deteriorating weather conditions.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 3, "q": "What is a squall line and how does it affect VFR flight planning?", "c": ["A line of thunderstorms that can extend hundreds of miles and contain severe weather, embedded thunderstorms, and violent turbulence \u2014 VFR pilots should consider it a no-go boundary", "A minor weather system similar to a warm front", "A line of fog banks along a coastline", "A boundary between different air masses with no significant weather"], "a": 0, "e": "A squall line is a non-frontal line of active thunderstorms that can extend hundreds of miles ahead of a cold front. It contains the most severe weather of any convective system and should not be penetrated by VFR (or most IFR) aircraft. It requires complete avoidance.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "What is an isobar and how is it used on a surface analysis chart?", "c": ["A line connecting points of equal temperature", "A line connecting points of equal atmospheric pressure \u2014 isobars show wind patterns, frontal systems, and help identify areas of strong pressure gradient (strong winds)", "A line connecting points of equal humidity", "A line connecting points of equal cloud cover"], "a": 1, "e": "Isobars are lines on a surface analysis chart connecting points of equal atmospheric pressure. Wind flows roughly parallel to isobars (modified by friction near the surface). Closely spaced isobars indicate a steep pressure gradient and strong winds.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "What is the Coriolis force and how does it affect wind direction in the northern hemisphere?", "c": ["Coriolis force has no effect on aviation weather", "The Coriolis effect causes winds to deflect to the right in the northern hemisphere due to the Earth's rotation \u2014 results in clockwise circulation around high pressure and counterclockwise around low pressure", "Coriolis force causes winds to deflect left in the northern hemisphere", "Coriolis force only affects high-altitude jet streams"], "a": 1, "e": "The Coriolis effect, caused by Earth's rotation, deflects moving air to the right in the northern hemisphere. This results in clockwise circulation around high-pressure systems and counterclockwise circulation around low-pressure systems (Buys-Ballot's Law: stand with your back to the wind, low pressure is to your left in northern hemisphere).", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 3, "q": "What is wind shear on approach and what are the warning signs?", "c": ["Wind shear on approach is only a problem for large aircraft", "Wind shear on approach warning signs include: airspeed fluctuations of 15 knots or more, unusual pitch attitudes required to maintain glidepath, rapid change in descent rate, and loss of visual perspective on runway", "Wind shear on approach always produces turbulence so it is easy to detect", "Wind shear on approach only occurs in thunderstorms"], "a": 1, "e": "Wind shear on approach can be subtle and rapidly dangerous. Warning signs: significant airspeed fluctuations (15+ kts), unusual power changes needed to stay on glidepath, rapid VSI changes, runway perspective changes. The recommended action is a go-around if significant wind shear is encountered.", "r": "AIM 7-1-24"}, {"t": "Weather", "d": 2, "q": "What is MVFR and what ceiling and visibility define it?", "c": ["Minimum VFR \u2014 ceiling at or above 3000 ft and visibility at or above 5 SM", "Marginal VFR \u2014 ceiling 1000 to 3000 ft and/or visibility 3 to 5 SM", "Military VFR \u2014 only applies to military operations", "Medium VFR \u2014 ceiling between 1000 and 10000 ft"], "a": 1, "e": "MVFR (Marginal VFR) is a flight category defined as ceiling 1000 to 3000 ft and/or visibility 3 to 5 SM. These conditions are legal for VFR flight but represent marginal margins. Many accidents occur in MVFR conditions as weather deteriorates to IFR.", "r": "AIM 7-1-30"}, {"t": "Weather", "d": 3, "q": "How does humidity affect aircraft performance and density altitude?", "c": ["Humidity has no effect on aircraft performance", "High humidity increases density altitude because water vapor is lighter than dry air, replacing denser oxygen and nitrogen molecules \u2014 this reduces engine power and aerodynamic performance", "High humidity decreases density altitude because water is heavier than air", "Humidity only affects turbine engines, not piston aircraft"], "a": 1, "e": "High relative humidity increases density altitude because water vapor (molecular weight 18) is less dense than dry air (molecular weight ~29). This displaces oxygen and reduces engine power output and propeller/wing efficiency. Hot, humid days at high elevation airports can create extremely high density altitude.", "r": "PHAK Ch.11"}, {"t": "Airspace", "d": 2, "q": "What is the floor of Class E airspace in most controlled areas en route?", "c": ["Surface everywhere", "700 ft AGL near airports with instrument approaches; 1200 ft AGL in most other areas", "2500 ft AGL", "Only above FL180"], "a": 1, "e": "Class E airspace has several different floors depending on the area. Near airports with instrument approaches: 700 ft AGL (shown by magenta shading on sectionals). En-route over most of the continental US: 1200 ft AGL. In some areas it begins at the surface.", "r": "AIM 3-2-6; PHAK Ch.15"}, {"t": "Airspace", "d": 3, "q": "What is the difference between an airspace clearance and two-way communication in Class B vs Class C?", "c": ["There is no difference \u2014 all controlled airspace requires clearance", "Class B requires explicit ATC clearance (must hear 'cleared into the Bravo'). Class C requires only two-way communication to be established (ATC acknowledging your callsign). Never enter Class B without explicit clearance.", "Both Class B and C require explicit clearance", "Neither Class B nor C requires clearance for VFR"], "a": 1, "e": "This is a critical distinction: Class B requires explicit clearance language from ATC (cleared into Class B airspace). Class C requires only that two-way communication is established \u2014 ATC does not have to issue a clearance, but they must acknowledge your aircraft by callsign. Never enter Class B without explicit clearance.", "r": "14 CFR 91.130, 91.131"}, {"t": "Airspace", "d": 2, "q": "What is the purpose of a NOTAM and where can they be obtained?", "c": ["Notice to Air Missions \u2014 provides time-critical aeronautical information that is temporary in nature or not known far enough in advance to be published \u2014 available through 1800wxbrief.com, ATIS, ForeFlight, and other FAA-authorized sources", "Notice to All Mechanics \u2014 maintenance advisories", "Notice to Airframe Manufacturers \u2014 design changes", "Not required for VFR flight planning"], "a": 0, "e": "NOTAMs (Notices to Air Missions) provide time-critical aeronautical information about airport closures, runway closures, TFRs, GPS outages, NAVAID outages, and other temporary conditions. VFR pilots must check NOTAMs before every flight. Available at 1800wxbrief.com, ForeFlight, Garmin Pilot, and directly from FSS.", "r": "AIM 5-1-3"}, {"t": "Airspace", "d": 3, "q": "What is the DC SFRA and what specific requirements does it impose on VFR pilots?", "c": ["The DC SFRA does not apply to VFR flights", "The Washington DC Special Flight Rules Area (30 nm of DCA): requires completion of an FAA online course, an assigned discrete transponder code, two-way radio, and filing a specific SFRA flight plan or having an ATC authorization before entry", "Only applies to IFR aircraft", "Only applies to aircraft over 12,500 lbs"], "a": 1, "e": "14 CFR 93.331: The DC SFRA (30 nm of DCA, surface to FL180) requires: (1) completion of the FAA online SFRA training course, (2) filing an SFRA flight plan or having an ATC authorization, (3) squawking a discrete ATC-assigned transponder code, (4) two-way radio communication. VFR pilots must also comply with the DC ADIZ requirements.", "r": "14 CFR 93.331; AIM 9-1-2"}, {"t": "Airspace", "d": 2, "q": "Under what conditions can a pilot operate below 10,000 ft MSL in Class A airspace?", "c": ["Any time with ATC permission", "Never \u2014 all Class A operations must be under IFR at or above 18,000 ft MSL", "Only for military training", "Only with a type rating for the aircraft"], "a": 1, "e": "Class A airspace is defined as 18,000 ft MSL to FL600. All operations within Class A must be conducted under IFR, by an instrument-rated pilot, with an appropriate IFR clearance. There are no VFR operations in Class A.", "r": "14 CFR 71.33; 91.135"}, {"t": "Airspace", "d": 3, "q": "What is a VFR flyway and how does it relate to Class B airspace?", "c": ["A VFR flyway is the same as a VFR corridor", "A VFR flyway is a published route around (not through) Class B airspace that allows VFR aircraft to transit an area without entering the Bravo \u2014 shown on TAC charts as dashed lines with recommended altitudes", "A VFR flyway requires ATC clearance", "VFR flyways are only for helicopters"], "a": 1, "e": "VFR flyways (also called VFR corridors in some contexts) are published on VFR Terminal Area Charts (TAC). They are recommended routes around Class B airspace for VFR aircraft to avoid the Bravo without needing clearance. They should not be confused with VFR corridors through Class B (which do exist at some locations).", "r": "AIM 3-5-5"}, {"t": "Airspace", "d": 2, "q": "What does it mean when a sectional chart shows a dashed blue circle with an altitude number such as [27] inside it?", "c": ["The maximum altitude for VFR flight in that area", "The floor of Class E airspace in hundreds of feet MSL (e.g., [27] = 2700 ft MSL) \u2014 shown as the top of Class G beneath it", "The MEF for the quadrangle", "The maximum transponder altitude for that sector"], "a": 1, "e": "Dashed blue circles (step-down fixes or airspace segments) with altimeter numbers in brackets or parentheses indicate the floor of Class E airspace in MSL at that point. This is important when transitioning between airspace classes vertically.", "r": "PHAK Ch.15"}, {"t": "Airspace", "d": 2, "q": "What is the purpose of a Class B VFR corridor, where one exists?", "c": ["A high-speed route for jet aircraft", "A specific designated passage through Class B airspace that VFR aircraft may use without ATC clearance \u2014 at specified altitudes and typically following a specific route such as between two outer rings", "A route around Class B for VFR aircraft", "A helicopter route under Class B airspace"], "a": 1, "e": "At some Class B airports, specific VFR corridors through (not around) the Bravo airspace are established. These allow VFR aircraft to transit the area at specific altitudes without requiring a clearance \u2014 but the pilot must remain within the corridor boundaries. Not all Class B airports have these.", "r": "AIM 3-2-3"}, {"t": "Airspace", "d": 3, "q": "What is the lateral dimension of the Mode C veil and what equipment does it require?", "c": ["10 nm from the Class B primary airport \u2014 requires only a transponder", "30 nm from the Class B primary airport up to 10,000 ft MSL \u2014 requires a transponder with Mode C capability AND ADS-B Out (both required simultaneously)", "20 nm from any Class B airport \u2014 requires Mode C only", "50 nm from any Class B airport \u2014 requires full IFR equipment"], "a": 1, "e": "14 CFR 91.215 and 91.225: The Mode C veil extends 30 nm from the Class B primary airport, from the surface up to 10,000 ft MSL. Both an operable Mode C transponder AND ADS-B Out are required in this area.", "r": "14 CFR 91.215; 91.225"}, {"t": "Airspace", "d": 2, "q": "What are the minimum requirements to operate in Class G airspace?", "c": ["Transponder and ADS-B Out", "Two-way radio communication", "Virtually no requirements \u2014 Class G is uncontrolled airspace where basic VFR rules (visibility and cloud clearance) still apply, but no communications or equipment are required", "At least a student pilot certificate"], "a": 2, "e": "Class G is uncontrolled airspace. No ATC communication, clearance, or special equipment is required. However, all VFR weather minimums (visibility and cloud clearance) still apply. See-and-avoid responsibilities remain in effect.", "r": "14 CFR 91.126; PHAK Ch.15"}, {"t": "Airspace", "d": 3, "q": "What is an ADIZ and what are the requirements for VFR flight through it?", "c": ["Air Defense Identification Zone \u2014 only applies to IFR flights", "Air Defense Identification Zone \u2014 VFR pilots must file a DVFR (Defense VFR) flight plan, two-way radio, operable transponder, and must depart within 5 minutes of filed time or notify ATC before deviating from the filed plan", "ADIZs have been eliminated \u2014 only the DC SFRA remains", "ADIZ only applies to international flights"], "a": 1, "e": "ADIZs (Air Defense Identification Zones) are established for national security purposes, particularly along the US coasts. VFR pilots must file a DVFR flight plan, maintain two-way radio communication, have an operable transponder, and depart within 5 minutes of the filed departure time.", "r": "14 CFR 99; AIM 5-6-1"}, {"t": "Airspace", "d": 2, "q": "When a control tower is in operation what is the significance of a flashing green light signal to an aircraft on the ground?", "c": ["Stop", "Cleared to takeoff", "Cleared to taxi", "Return to starting point on airport"], "a": 1, "e": "14 CFR 91.125 / AIM 4-3-13: Light gun signals to aircraft on the ground. Flashing green = cleared to taxi. Steady green = cleared for takeoff. Flashing red = taxi clear of runway. Steady red = stop. Alternating red and green = exercise extreme caution.", "r": "14 CFR 91.125; AIM 4-3-13"}, {"t": "Airspace", "d": 2, "q": "What does a steady red light signal from the tower mean to an aircraft in flight?", "c": ["Give way to other aircraft and continue circling", "Do not land \u2014 airport unsafe or closed", "Continue circling, airport not clear for landing", "Return to starting point on airport"], "a": 0, "e": "14 CFR 91.125 / AIM 4-3-13: Light gun signals to aircraft in flight. Steady red = give way to other aircraft and continue circling. Flashing red = airport unsafe \u2014 do not land. Flashing green = return for landing. Steady green = cleared to land.", "r": "14 CFR 91.125; AIM 4-3-13"}, {"t": "Airspace", "d": 3, "q": "What is a Temporary Flight Restriction (TFR) under 14 CFR 91.143 and when is it used?", "c": ["A permanent airspace restriction", "A TFR for space operations (rocket launches) that temporarily restricts airspace to protect the public from hazards associated with space flight operations", "A TFR for presidential movement only", "A TFR for military training areas"], "a": 1, "e": "14 CFR 91.143: This specific type of TFR is established for space flight operations to protect airspace during rocket launches, space vehicle ascents and descents. The TFR defines the restricted area and time period around launch/landing sites.", "r": "14 CFR 91.143"}, {"t": "Airspace", "d": 2, "q": "What is the definition of Class E airspace at the surface and where does it commonly exist?", "c": ["Any airspace below Class D", "Class E airspace that begins at the surface (depicted by dashed magenta circles) \u2014 commonly established at airports with published instrument procedures but no operating control tower, or at some airports with part-time towers", "All airspace below 700 ft AGL", "Class E surface areas are only near major airports"], "a": 1, "e": "Class E surface areas extend from the surface and are depicted with dashed magenta circles on sectional charts. They are commonly established at airports with published instrument approaches (often ILS or RNAV approaches) where instrument protection down to the surface is needed but no control tower operates.", "r": "AIM 3-2-6; PHAK Ch.15"}, {"t": "Navigation", "d": 2, "q": "What is a VOR radial and how is it defined?", "c": ["A radial is a signal transmitted TO the VOR from an aircraft", "A radial is a magnetic bearing FROM the VOR station \u2014 the 090 radial is the line extending east from the VOR. Aircraft position is described by which radial they are ON, not flying.", "A radial is a true bearing from the VOR", "A radial is a GPS direct-to course"], "a": 1, "e": "VOR radials are magnetic bearings extending outward FROM the VOR station. The 090 radial extends east (090 degrees magnetic) from the station. If you are on the 090 radial, you are east of the VOR. Radials are always FROM the station regardless of which direction you are flying.", "r": "AIM 1-1-3; PHAK Ch.16"}, {"t": "Navigation", "d": 2, "q": "What is a VOR station service volume and why does it matter for flight planning?", "c": ["The service volume is unlimited for all VOR stations", "VOR stations have defined service volumes (T=Terminal, L=Low Altitude, H=High Altitude) within which reliable signal reception is guaranteed \u2014 planning should use VORs within their service volume for the altitude being flown", "VOR service volume only applies to IFR flight", "All VOR stations have the same service volume"], "a": 1, "e": "VOR stations are classified by their Standard Service Volume (SSV): T (Terminal) 25 nm up to 12,000 ft AGL; L (Low altitude) 40 nm up to 18,000 ft; H (High altitude) 130 nm above 14,500 ft. Using a VOR outside its service volume may result in unreliable signal reception.", "r": "AIM 1-1-8"}, {"t": "Navigation", "d": 3, "q": "What is deviation and how does it differ from variation?", "c": ["Deviation and variation are the same \u2014 both refer to magnetic declination", "Variation is the difference between true north and magnetic north (isogonic lines on charts). Deviation is the error in a specific compass caused by local magnetic influences in the aircraft \u2014 shown on the compass deviation card.", "Deviation is the difference between true north and geographic north", "Variation is the compass error; deviation is the chart correction"], "a": 1, "e": "Magnetic variation is the angular difference between true north and magnetic north \u2014 a fixed geographic value shown by isogonic lines on charts. Deviation is the error in a specific aircraft's magnetic compass caused by magnetic fields from aircraft systems, engines, and structure \u2014 unique to each aircraft and shown on the compass deviation card.", "r": "PHAK Ch.16"}, {"t": "Navigation", "d": 2, "q": "When would you use Vx immediately after liftoff during a short field takeoff?", "c": ["Never \u2014 always use Vy after takeoff", "When obstacles are present on the departure end \u2014 Vx provides the greatest altitude gain over horizontal distance, clearing obstacles", "When the runway is soft or wet", "When departing from a high-elevation airport"], "a": 1, "e": "Vx is used when obstacles must be cleared on the departure end of the runway. It provides the maximum altitude gained per unit of horizontal distance traveled, trading slower climb rate for steeper climb angle. Transition to Vy once the obstacle is cleared.", "r": "PHAK Ch.11; AFH Ch.8"}, {"t": "Navigation", "d": 2, "q": "What is the VFR cruising altitude rule and at what point does it begin to apply?", "c": ["Applies at all altitudes", "Applies only above 18,000 ft MSL", "Applies when more than 3,000 ft above the surface (AGL) \u2014 not MSL. Below 3,000 AGL there is no cruising altitude requirement.", "Applies above 1,000 ft MSL"], "a": 2, "e": "14 CFR 91.159: The VFR cruising altitude rule applies when flying at more than 3,000 feet ABOVE THE SURFACE (AGL), not above MSL. In a mountainous area where the terrain is at 8,000 ft MSL, the rule begins at 11,000 ft MSL (8,000 + 3,000).", "r": "14 CFR 91.159"}, {"t": "Navigation", "d": 3, "q": "You are flying a magnetic course of 355 degrees at 8,500 ft MSL, more than 3,000 ft AGL. Is this a legal VFR cruising altitude?", "c": ["Yes \u2014 any altitude above 3,000 AGL is fine", "No \u2014 magnetic course 355 degrees is northbound (0-179 degrees range) so odd thousands plus 500 should be used. 8,500 is even thousands plus 500 and would be used for westbound (180-359 degrees). Correct altitude would be 7,500 or 9,500 ft.", "Yes \u2014 8,500 is acceptable for any heading", "No \u2014 you should be at 9,000 ft"], "a": 1, "e": "14 CFR 91.159: MC 355 degrees is northbound (0-179 degrees range), which requires ODD thousands plus 500 ft: 3,500; 5,500; 7,500; 9,500 etc. 8,500 ft is the even + 500 altitude used for westbound/southbound (180-359 degree range). This is a common exam trap.", "r": "14 CFR 91.159"}, {"t": "Navigation", "d": 2, "q": "What is pilotage and how is it used in VFR navigation?", "c": ["Pilotage is automated navigation using GPS", "Pilotage is navigation by visual reference to landmarks \u2014 the pilot identifies ground features and compares them to the aeronautical chart to confirm position and navigate along a route", "Pilotage is navigation using only radio aids", "Pilotage is the process of taxiing at an unfamiliar airport"], "a": 1, "e": "Pilotage is visual navigation by reference to landmarks. The pilot identifies cities, rivers, highways, railroads, lakes, towers, and other features visible from the air and matches them to the aeronautical chart to confirm position and navigate. Often combined with dead reckoning for cross-country flights.", "r": "PHAK Ch.17"}, {"t": "Navigation", "d": 2, "q": "What is the purpose of a flight log or navigation log on a cross-country flight?", "c": ["It is only required for IFR flights", "A navigation log documents the planned route, checkpoints, headings, distances, estimated groundspeeds, fuel burns, and estimated times enroute \u2014 used to track progress and identify when off course during VFR XC flights", "Navigation logs are obsolete now that GPS is available", "A navigation log is required to be filed with the FAA"], "a": 1, "e": "A navigation log (nav log or flight log) is a planning document that organizes all cross-country flight data: checkpoints, true/magnetic course, wind correction angle, true/magnetic heading, compass heading, distance, groundspeed, estimated time enroute, and fuel burn. It is essential for situational awareness during the flight.", "r": "PHAK Ch.17"}, {"t": "Navigation", "d": 3, "q": "An altimeter set to 29.42 in Hg when the current altimeter setting is 29.92 in Hg. How does this affect the indicated altitude compared to true altitude?", "c": ["No effect \u2014 altimeters are self-correcting", "The altimeter will read approximately 500 feet LOWER than actual altitude \u2014 the pilot is higher than the altimeter indicates. Remember: high to low, look out below.", "The altimeter will read 500 feet higher than actual altitude", "The altimeter will be exactly correct but the VSI will be affected"], "a": 1, "e": "Each 0.10 in Hg change in altimeter setting corresponds to approximately 100 ft of altitude error. Setting the altimeter too low (29.42 vs. 29.92 = 0.50 in Hg too low) causes the altimeter to read approximately 500 ft LOW \u2014 the aircraft is 500 ft HIGHER than indicated. High to low, look out below.", "r": "PHAK Ch.8"}, {"t": "Navigation", "d": 2, "q": "What is the difference between indicated airspeed (IAS), calibrated airspeed (CAS), and true airspeed (TAS)?", "c": ["They are all the same \u2014 different names for the same measurement", "IAS is what the airspeed indicator shows. CAS is IAS corrected for instrument and position errors (published in POH). TAS is CAS corrected for altitude and temperature \u2014 the actual speed through the air mass. TAS increases with altitude at a constant IAS.", "IAS is only used on the ground; TAS is used in the air", "CAS is used only for IFR operations"], "a": 1, "e": "IAS (Indicated Airspeed): what the ASI reads. CAS (Calibrated Airspeed): IAS corrected for instrument and position errors (from POH calibration tables). TAS (True Airspeed): CAS corrected for non-standard density (altitude and temperature) \u2014 the actual speed through the air mass. TAS is approximately 2% greater than CAS per 1000 ft of altitude.", "r": "PHAK Ch.8"}, {"t": "Navigation", "d": 2, "q": "What is compass rose on a sectional chart and what is its purpose?", "c": ["A decorative element with no navigational purpose", "Magnetic reference roses printed around VOR stations showing magnetic degrees to assist in interpreting VOR radials relative to surrounding terrain and airspace features", "A rose-shaped symbol indicating a helicopter landing pad", "A symbol for a rotating beacon at an airport"], "a": 1, "e": "Compass roses printed around VOR stations on sectional charts show magnetic degrees clockwise from magnetic north. They help pilots visualize VOR radials and assist in interpreting CDI indications relative to landmarks and airspace on the chart.", "r": "PHAK Ch.16"}, {"t": "Navigation", "d": 3, "q": "What is a course deviation indicator (CDI) and how does it display VOR guidance?", "c": ["CDI is the Course Direction Indicator \u2014 only used on GPS", "The CDI displays how far left or right the aircraft is from the selected course (OBS setting). Each dot of deflection = 2 degrees off course. The course line is the OBS setting; the needle deflects toward the course to re-intercept.", "CDI always displays bearing to the station", "CDI only works within 5 nm of the VOR station"], "a": 1, "e": "The CDI displays the aircraft's lateral displacement from the selected VOR course (OBS setting). When the needle deflects right, the course is to the right \u2014 fly right to center it. Each dot = approximately 2 degrees off course. Full-scale deflection = 10 degrees off course. The OBS sets which radial or course is selected.", "r": "PHAK Ch.16; AIM 1-1-3"}, {"t": "Navigation", "d": 2, "q": "What is a Class B VFR transition route?", "c": ["A high-altitude route above Class B for jet traffic", "Specific published routes through Class B airspace on VFR Terminal Area Charts that VFR aircraft may use at specified altitudes \u2014 NOT a clearance; pilots must receive ATC authorization to use these routes", "A VFR route around Class B airspace \u2014 same as a flyway", "A VFR route only for turboprops and jets"], "a": 1, "e": "VFR transition routes are published on TAC charts and provide specific routes through Class B airspace at designated altitudes. However, VFR pilots must STILL receive ATC clearance to use these routes \u2014 they are not clearance-free corridors. The term 'transition route' on a TAC indicates a commonly used path that ATC is familiar with.", "r": "AIM 3-2-3"}, {"t": "Navigation", "d": 2, "q": "How does the E6B flight computer assist with fuel planning and why is it important to use actual data?", "c": ["The E6B cannot assist with fuel planning \u2014 it is only for wind calculations", "The E6B (or electronic equivalent) can calculate fuel burn based on fuel flow rate and time enroute \u2014 but accurate results require using actual POH fuel flow figures for the specific power setting and altitude planned, not standard estimates", "The E6B automatically downloads fuel prices from FBOs", "E6B fuel calculations are not accepted by the FAA"], "a": 1, "e": "The E6B flight computer can calculate fuel requirements (fuel flow x time = fuel burn). The critical factor is using accurate POH fuel consumption data for the specific power setting and altitude planned. Using manufacturer estimates without accounting for actual power settings or a fuel-enriched mixture leads to dangerous fuel planning errors.", "r": "PHAK Ch.17"}, {"t": "Navigation", "d": 3, "q": "What is a compass locator and how is it used for navigation?", "c": ["A handheld compass used to find the airport", "A low or medium frequency (LF/MF) NDB (Non-Directional Beacon) co-located with an ILS outer or middle marker \u2014 used with an ADF receiver to home to the beacon", "A magnetic compass installed in the control tower", "A GPS waypoint near an airport"], "a": 1, "e": "A compass locator is a low-power NDB (Non-Directional Beacon) co-located with ILS outer markers (LOM) or middle markers (LMM). It operates on 200-415 kHz and can be received with an ADF (Automatic Direction Finder). Compass locators are used for instrument approaches and as a backup navaid.", "r": "AIM 1-1-2"}, {"t": "Maneuvers", "d": 2, "q": "What is Va (maneuvering speed) and why does it change with aircraft weight?", "c": ["Va is the maximum structural cruising speed \u2014 never changes", "Va is the maximum speed at which full or abrupt application of any single flight control will not cause structural damage. Va decreases as weight decreases because a lighter aircraft develops less lift per unit deflection and stalls sooner, protecting the structure.", "Va is the best glide speed \u2014 constant at all weights", "Va is the flap extension speed \u2014 changes with altitude"], "a": 1, "e": "Va (maneuvering speed) is the maximum speed at which full deflection of a single flight control will not overstress the aircraft (the aircraft will stall before exceeding limit load). Va decreases as weight decreases \u2014 a lighter aircraft stalls more easily providing structural protection. Always use the POH Va for current aircraft weight.", "r": "PHAK Ch.4; POH"}, {"t": "Maneuvers", "d": 3, "q": "During steep turns, why does the nose tend to drop and what is the corrective action?", "c": ["The nose drops because of carburetor ice \u2014 apply carb heat", "The nose drops because the increased load factor (1.41g at 45 degrees) requires increased lift, which means increased back pressure on the elevator is needed throughout the turn. As bank increases, more back pressure is required.", "The nose drops due to propeller torque in turns", "The nose drops because of compass precession errors"], "a": 1, "e": "In a steep turn, the increased load factor (1.41g at 45 degrees) means the aircraft requires more lift than in level flight. This increased lift requirement must be provided by increasing angle of attack through back pressure on the elevator. If back pressure is not maintained, the nose will drop and altitude will be lost.", "r": "PHAK Ch.4; AFH Ch.8"}, {"t": "Maneuvers", "d": 2, "q": "What is the purpose of performing clearing turns before beginning a maneuver?", "c": ["Clearing turns warm up the engine before high-power maneuvers", "Clearing turns are 90-degree or 180-degree turns performed before practicing maneuvers to clear the area of other aircraft \u2014 standard practice before any slow flight, stall, or steep turn", "Clearing turns reset the heading indicator", "Clearing turns are required by the ACS in all maneuvers"], "a": 1, "e": "Clearing turns (typically two 90-degree turns or one 180-degree turn) are performed before any maneuver that diverts attention from outside (steep turns, slow flight, stalls). They allow the pilot to visually clear the practice area of other traffic. This is standard safe practice and expected during the checkride.", "r": "AFH Ch.3"}, {"t": "Maneuvers", "d": 3, "q": "What is an accelerated stall and how is it different from a power-off stall?", "c": ["An accelerated stall only occurs at very high airspeeds", "An accelerated stall occurs when the critical angle of attack is exceeded while the aircraft is in a banked or maneuvering condition \u2014 the stall can occur at speeds significantly above the normal stall speed due to the increased load factor from the maneuver", "An accelerated stall is a stall caused by sudden power application", "An accelerated stall only affects high-performance aircraft"], "a": 1, "e": "An accelerated stall occurs when the critical angle of attack is reached while the aircraft is under increased load factor (in a turn, pull-up, etc.). Because load factor increases the stall speed (Vs x sqrt(LF)), an accelerated stall can occur at airspeeds well above the normal Vs. The base-to-final stall is a classic example.", "r": "PHAK Ch.4"}, {"t": "Maneuvers", "d": 2, "q": "What is the proper technique for establishing and maintaining slow flight?", "c": ["Reduce power to idle and maintain level flight", "Gradually reduce power while maintaining altitude with increasing back pressure, extend flaps as needed, add right rudder to counteract left-turning tendencies. Establish at a speed 5-10 kts above stall. Maintain altitude with back pressure and power adjustments.", "Reduce power suddenly and immediately add full flaps", "Slow flight is only practiced at altitude, not in the traffic pattern"], "a": 1, "e": "Slow flight setup: gradually reduce power while maintaining altitude with back pressure, add flaps incrementally, add right rudder to compensate for increased left-turning tendencies at high AoA. Establish and maintain flight at 5-10 kts above stall speed. The aircraft should be responsive to all controls (not in a mushing condition).", "r": "AFH Ch.4; ACS Task VIII.C"}, {"t": "Maneuvers", "d": 3, "q": "During a power-on stall (departure stall), what control input is most critical to prevent an incipient spin?", "c": ["Elevator \u2014 maintain back pressure throughout", "Aileron \u2014 use aileron to keep wings level", "Rudder \u2014 aggressive right rudder to counteract left-turning tendencies at full power and high AoA. A wing drop during the stall must be corrected with rudder, not aileron.", "Throttle \u2014 reduce power at first stall indication"], "a": 2, "e": "During power-on stalls, all four left-turning tendencies are at maximum intensity. Aggressive right rudder is critical to keep the ball centered and prevent a wing from dropping. If a wing drops during the stall, use opposite RUDDER (not aileron) to raise it \u2014 aileron input during a stall can aggravate a spin.", "r": "AFH Ch.4; PHAK Ch.5"}, {"t": "Maneuvers", "d": 2, "q": "What is the standard traffic pattern altitude for propeller-driven aircraft at an airport without a published pattern altitude?", "c": ["500 ft AGL", "800 ft AGL", "1000 ft AGL", "1500 ft AGL"], "a": 2, "e": "The standard traffic pattern altitude for propeller-driven aircraft is 1000 ft AGL unless otherwise specified in the Chart Supplement or by NOTAMs. Turbine-powered aircraft typically fly 1500 ft AGL. Pattern altitudes may vary and should always be checked in the Chart Supplement.", "r": "AIM 4-3-3"}, {"t": "Maneuvers", "d": 2, "q": "What is the proper scanning technique to detect other aircraft in VFR conditions?", "c": ["Continuous sweep from left to right at a steady speed", "Systematic sectional scanning \u2014 divide the field of view into segments of 10-15 degrees and pause briefly on each sector. The eye detects movement and change best when not sweeping continuously. Also check different vertical levels.", "Only scan the final approach corridor", "Use TCAS alerts only \u2014 visual scanning is not effective"], "a": 1, "e": "The most effective collision avoidance technique is systematic sectional scanning. Divide the visual field into 10-15 degree segments and pause momentarily on each. The eye detects movement/contrast changes most effectively when paused. Continuous sweeping reduces detection ability. Also look high and low, not just level.", "r": "AIM 8-1-6"}, {"t": "Maneuvers", "d": 3, "q": "What is the effect of carburetor ice on engine operation and how is it recognized?", "c": ["Carb ice increases engine roughness and power but does not affect RPM", "Carb ice causes a gradual unexplained decrease in RPM (fixed-pitch prop) or manifold pressure (constant-speed prop), often accompanied by engine roughness. In severe cases, the engine may quit entirely.", "Carb ice causes the fuel gauge to drop rapidly", "Carb ice only affects magneto-driven engines"], "a": 1, "e": "Carburetor ice restricts airflow through the carburetor, leaning the mixture and reducing engine power. Symptoms: gradual decrease in RPM (fixed-pitch) or manifold pressure (constant-speed), possible roughness. Apply full carb heat \u2014 expect further RPM drop as ice melts and enrichens mixture, then smooth RPM increase as ice clears.", "r": "PHAK Ch.7"}, {"t": "Maneuvers", "d": 2, "q": "During a normal approach and landing, what is the purpose of the final flap extension?", "c": ["Final flap extension increases airspeed for safety", "Final flap extension increases drag and lift, allowing a steeper approach path at a slower airspeed \u2014 reduces the landing roll and allows precise glidepath control", "Final flap extension is only for short field landings", "Full flaps are never used in normal landings"], "a": 1, "e": "Extending flaps (particularly the final increment) on final approach increases both lift and drag. This allows the aircraft to maintain a steeper glidepath at a slower approach speed, reducing float over the runway and landing roll. The specific flap setting and approach speed are determined by the POH.", "r": "AFH Ch.8; PHAK Ch.5"}, {"t": "Systems", "d": 2, "q": "What is the purpose of the aircraft's fuel selector valve and what are the common positions?", "c": ["The fuel selector controls fuel temperature \u2014 not common in light aircraft", "The fuel selector valve controls which fuel tank(s) feed the engine. Common positions: LEFT (left tank only), RIGHT (right tank only), BOTH (both tanks simultaneously), OFF. Some aircraft require specific takeoff and landing positions per the POH.", "The fuel selector valve also controls the mixture", "The fuel selector is always left in BOTH \u2014 it has no other use"], "a": 1, "e": "The fuel selector valve directs fuel from the selected tank(s) to the engine. Improper fuel management (running a tank dry, improper position for takeoff/landing) is a leading cause of engine failures. Always follow POH procedures for fuel selector position during each phase of flight.", "r": "PHAK Ch.7; POH"}, {"t": "Systems", "d": 3, "q": "What is the function of the aircraft's vacuum system and what instruments depend on it?", "c": ["The vacuum system powers the electrical instruments as a backup", "The vacuum system uses engine-driven vacuum pumps to drive the gyroscopic attitude indicator and heading indicator through suction cups. Most light aircraft have a single vacuum pump \u2014 failure leaves these instruments unreliable.", "The vacuum system only powers the turn coordinator", "The vacuum system powers all six flight instruments"], "a": 1, "e": "The vacuum (suction) system uses an engine-driven pump to spin the gyroscopes in the attitude indicator and heading indicator. A vacuum failure makes these instruments unreliable within minutes. The turn coordinator is typically electrically powered and remains operational after vacuum failure. Check suction gauge in preflight.", "r": "PHAK Ch.8"}, {"t": "Systems", "d": 2, "q": "What is a magneto and why do aircraft typically have two?", "c": ["A magneto is an electrical generator powered by the battery \u2014 only one is needed", "A magneto is a self-contained high-voltage electrical generator that provides ignition to the engine spark plugs \u2014 independent of the aircraft's electrical system. Two magnetos provide engine redundancy so the engine continues operating if one magneto fails.", "Magnetos power the avionics systems", "Magnetos are only found in turbine engines"], "a": 1, "e": "Magnetos are self-contained electrical generators that produce high-voltage current for spark plugs independent of the aircraft's battery and alternator. Having two magnetos (each firing one plug per cylinder) provides redundancy \u2014 if one magneto fails, the engine continues on the other. This is checked during the runup.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 2, "q": "What is the purpose of the landing gear extension and retraction system position indicator?", "c": ["It shows hydraulic system pressure", "The landing gear position indicator shows whether the gear is up-and-locked, down-and-locked, or in transit \u2014 typically with lights: green for down-and-locked, red for in-transit or unsafe, and no light for gear up and locked on some aircraft", "It shows brake wear status", "It only indicates if the nose gear is extended"], "a": 1, "e": "The landing gear position indicator typically uses lights (green = down and locked, red/amber = in transit or unsafe, dark = up and locked on some aircraft) to indicate landing gear position. Some aircraft use mechanically displayed indicators. Always verify gear position using both the indicator and any available audible warnings.", "r": "PHAK Ch.7; POH"}, {"t": "Systems", "d": 3, "q": "What is a fuel-injected engine's throttle body and how does it differ from a carburetor?", "c": ["Fuel injection and carburetor systems are identical \u2014 different names only", "A fuel injection system meters fuel directly into each cylinder's intake port (port injection) or into the intake manifold (throttle body injection) rather than mixing it in a venturi as in a carburetor. Benefits include more precise fuel metering, no carburetor ice risk, and better fuel distribution.", "Fuel injection systems always use more fuel than carburetors", "Fuel injection is only used in turbine engines"], "a": 1, "e": "Fuel injection systems deliver fuel directly to each cylinder intake port or throttle body, bypassing the carburetor venturi. This eliminates carburetor icing, provides more precise fuel metering, better fuel distribution among cylinders, and generally better performance. However, fuel-injected engines can experience hot-start difficulties and vapor lock.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 2, "q": "What is the purpose of the primer in a fuel-injected engine vs a carbureted engine?", "c": ["Both use primers identically \u2014 no difference", "Carbureted engines use a primer to inject fuel into cylinder(s) for cold starts. Many fuel-injected engines do not have traditional primers but instead use the throttle position and boost pump to prime the system \u2014 specific cold start procedures vary significantly by aircraft.", "Primers are only used in carbureted engines", "Primers are not used in any modern aircraft engine"], "a": 1, "e": "In carbureted engines, the primer injects fuel directly into cylinders for cold starts. Many fuel-injected engines use a different cold-start procedure involving the throttle and electric fuel boost pump to prime the fuel injection system \u2014 the POH cold-start procedure must be followed precisely to avoid flooding or fire.", "r": "PHAK Ch.7; POH"}, {"t": "Systems", "d": 3, "q": "What are the four forces acting on an aircraft in flight and when are they balanced?", "c": ["Lift, drag, weight, and thrust \u2014 balanced during climbing only", "Lift, drag, weight, and thrust act on an aircraft at all times. They are in equilibrium (balanced) during straight-and-level, unaccelerated flight when lift equals weight and thrust equals drag.", "Lift and weight are always equal; thrust and drag are only equal at cruise", "Only two forces act on an aircraft \u2014 gravity and engine thrust"], "a": 1, "e": "The four forces are: Lift (opposes weight, acts perpendicular to flightpath), Weight (gravity, acts toward Earth's center), Thrust (acts along flightpath, forward), Drag (opposes motion, acts along flightpath, rearward). In straight-and-level, unaccelerated flight: Lift = Weight and Thrust = Drag.", "r": "PHAK Ch.4"}, {"t": "Systems", "d": 2, "q": "What is Vne and what does exceeding it risk?", "c": ["Vne is normal cruise speed \u2014 no risk to exceed briefly", "Vne (Never Exceed Speed) is the maximum speed for the aircraft in any flight operation. Exceeding Vne risks structural failure or control surface flutter, which can cause catastrophic airframe failure. Shown as a red line on the airspeed indicator.", "Vne is the maximum flap speed \u2014 only risks flap damage", "Vne is the maximum takeoff speed \u2014 only applies on the ground"], "a": 1, "e": "Vne (Never Exceed Speed) is the speed above which structural damage or failure may occur due to aeroelastic flutter, control surface flutter, or exceeding design load limits. It is shown as a red radial line on the airspeed indicator. Never exceed Vne under any circumstances.", "r": "PHAK Ch.4; POH"}, {"t": "Systems", "d": 2, "q": "What color coding is used on the airspeed indicator and what does each color represent?", "c": ["Airspeed indicators have no color coding \u2014 only numbers", "White arc: flap operating range (Vs0 to Vfe). Green arc: normal operating range (Vs1 to Vno). Yellow arc: caution range \u2014 smooth air only (Vno to Vne). Red line: never exceed speed (Vne).", "Green arc is the takeoff range; red line is cruise speed", "White arc is IFR range; green arc is VFR range"], "a": 1, "e": "Airspeed indicator color coding: White arc (flap range) = Vs0 (stall, gear/flaps down) to Vfe (maximum flap extension). Green arc (normal ops) = Vs1 (stall, clean) to Vno (maximum structural cruise). Yellow arc (caution \u2014 smooth air only) = Vno to Vne. Red radial line = Vne (never exceed).", "r": "PHAK Ch.8; 14 CFR 23"}, {"t": "Systems", "d": 3, "q": "What is gyroscopic precession and which instrument uses this property?", "c": ["Precession is the tendency of a gyro to resist changes to its spin axis \u2014 not used in any flight instrument", "Gyroscopic precession: a force applied to a spinning gyroscope causes it to react 90 degrees later in the direction of rotation. The turn coordinator uses precession \u2014 a yaw input (rudder) causes the gyro to precess and display a bank-rate indication.", "Precession is the same as rigidity \u2014 used in the heading indicator", "Precession only occurs at high RPM gyros in turbine aircraft"], "a": 1, "e": "Gyroscopic precession: when a force is applied to a spinning gyroscope, the effect appears 90 degrees later in the direction of rotation. The turn coordinator (TC) uses precession \u2014 a yaw input causes the gimbal-mounted gyro to precess, deflecting the miniature aircraft to indicate rate of turn. The TC is NOT a direct bank angle indicator.", "r": "PHAK Ch.8"}, {"t": "Aeromedical", "d": 2, "q": "What is flicker vertigo and when does it occur?", "c": ["A type of vertigo caused only by turbulence", "Flicker vertigo can occur when sunlight flickers through rotating propeller blades at certain frequencies (4 to 20 cycles per second) \u2014 can cause nausea, dizziness, unconsciousness, or even seizures in susceptible individuals. Wearing sunglasses reduces risk.", "Flicker vertigo only affects helicopter pilots", "Flicker vertigo is a myth \u2014 not recognized medically"], "a": 1, "e": "Flicker vertigo (photic driving or photosensitive epilepsy) can be induced when light flickers in the frequency range of 4 to 20 cycles per second \u2014 which can occur with a propeller blocking sunlight. Symptoms range from nausea and dizziness to loss of consciousness. Wearing sunglasses reduces the flicker effect.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 2, "q": "What is the somatogravic illusion and when is it most dangerous?", "c": ["An illusion only experienced by astronauts", "The somatogravic illusion occurs during rapid acceleration \u2014 the pilot senses a nose-high pitch attitude (like a gravity vector pulling them back into the seat) when actually accelerating in level flight. Most dangerous during a go-around or catapult launch \u2014 can cause the pilot to push forward into the ground.", "The somatogravic illusion only occurs at night", "The somatogravic illusion is the same as the leans"], "a": 1, "e": "The somatogravic illusion: during rapid acceleration, the increased G-force causes the pilot to sense a nose-high pitch attitude (false climb sensation). This can cause the pilot to push forward on the controls, pitching the nose down at low altitude. Most dangerous during go-around, takeoff, or cat shots \u2014 especially at night or in IMC.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 2, "q": "What is time of useful consciousness (TUC) and why is it important?", "c": ["TUC is the time before a pilot must land to avoid fatigue", "TUC is the time after oxygen supply is lost during which a pilot retains the ability to perform useful mental and physical tasks before hypoxia causes incapacitation. TUC decreases rapidly with increasing altitude \u2014 at FL250 it may be only 3-5 minutes, at FL350 it may be 30-60 seconds.", "TUC is the maximum flight time per day", "TUC is the time between engine starts at high altitude airports"], "a": 1, "e": "Time of Useful Consciousness (TUC) is the time after oxygen supply is interrupted (or hypoxia begins) during which the pilot can still perform purposeful actions. At FL180: ~20-30 min. At FL250: ~3-5 min. At FL350: ~30-60 sec. At FL430: ~9-12 sec. This is why rapid donning of oxygen equipment is critical at high altitude.", "r": "AIM 8-1-2"}, {"t": "Aeromedical", "d": 2, "q": "What is motion sickness and how should a pilot manage it?", "c": ["Motion sickness has no effect on flight safety because it is only gastrointestinal", "Motion sickness causes nausea, vomiting, sweating, disorientation, and fatigue \u2014 significantly impairing pilot performance. Management: focus on horizon or fixed points, avoid reading, use fresh air/ventilation, and in severe cases, land. OTC anti-motion sickness drugs are generally disqualifying.", "Motion sickness is normal and does not affect flight performance", "Motion sickness only occurs in turbulence and resolves when turbulence ends"], "a": 1, "e": "Motion sickness significantly impairs pilot performance through nausea, dizziness, fatigue, and disorientation. In early stages: focus on outside horizon, control ventilation, avoid tasks requiring head movements. Most OTC remedies (Dramamine, Benadryl) cause sedation and are disqualifying. Severe motion sickness is an I'M SAFE concern.", "r": "AIM 8-1-5; PHAK Ch.17"}, {"t": "Aeromedical", "d": 3, "q": "What effect does high altitude flight have on trapped gas in body cavities?", "c": ["High altitude reduces trapped gas \u2014 beneficial for body cavities", "Boyle's Law: as pressure decreases with altitude, trapped gas expands. Gas in the middle ear, sinuses, gastrointestinal tract, and any trapped gas from dental work or recent surgery can cause significant pain. Flying with a cold or upper respiratory infection can trap gas in the middle ear causing aerotitis media.", "High altitude has no effect on body gas \u2014 only affects air in tanks", "This only applies to unpressurized aircraft above 25,000 ft"], "a": 1, "e": "Boyle's Law: gas volume is inversely proportional to pressure. As altitude increases (lower pressure), trapped gas in body cavities expands. Middle ear and sinus problems (barotitis/barosinusitis) from trapped gas are serious aeromedical hazards. Never fly with a cold that blocks sinus or Eustachian tube drainage. This affects ALL altitudes in unpressurized aircraft.", "r": "AIM 8-1-1"}, {"t": "Aeromedical", "d": 2, "q": "What is the sclerae hypoxia effect and at what altitude does night vision first degrade?", "c": ["Sclerae hypoxia causes the whites of the eyes to turn blue at altitude", "Night vision begins to degrade at approximately 5000 ft MSL because the rods in the retina (which detect low light) are extremely sensitive to hypoxia. Supplemental oxygen at night is recommended even at altitudes well below legal requirements.", "Night vision degrades only above 14000 ft", "Night vision is not affected by altitude"], "a": 1, "e": "The rod cells in the retina, which provide night (low-light) vision, are extremely sensitive to hypoxia. Night visual acuity begins to degrade at approximately 5000 ft MSL \u2014 significantly below the altitude at which supplemental oxygen is legally required (12,500 ft). Use of supplemental oxygen on night flights is strongly recommended above 5000 ft.", "r": "AIM 8-1-2"}, {"t": "Aeromedical", "d": 3, "q": "What is the recommended off-axis scanning technique for night vision?", "c": ["Look directly at objects for best night vision", "Look approximately 5-10 degrees off to the side of an object rather than directly at it \u2014 the center of the retina (fovea) contains cones (color/detail vision) which are less sensitive in low light. The peripheral retina has more rods which are better for low-light detection.", "Night vision is best when looking directly into bright lights", "Focus directly at runway threshold lights for best night vision"], "a": 1, "e": "The fovea (center of the retina) contains cones which detect color and detail but require more light. In low-light conditions, rods in the peripheral retina provide better detection. By looking approximately 5-10 degrees off to the side of an object (off-axis viewing), you use the more sensitive rods rather than the less-sensitive fovea.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 2, "q": "What are the symptoms of dehydration at altitude and how does it affect pilot performance?", "c": ["Dehydration has no measurable effect on pilot performance", "Dehydration at altitude causes fatigue, reduced concentration, headache, and impaired decision-making \u2014 often misidentified as other conditions. The low humidity in aircraft cabins accelerates dehydration. Pilots should drink water regularly during flight.", "Dehydration only affects physical performance, not cognitive performance", "Dehydration effects are cancelled by the pressurization system"], "a": 1, "e": "Dehydration impairs cognitive performance and contributes to fatigue, poor decision-making, and susceptibility to hypoxia effects. Low humidity in aircraft cabins (especially at altitude) accelerates fluid loss even without obvious sweating. Pilots should drink water regularly before and during flight and avoid caffeine and alcohol which worsen dehydration.", "r": "PHAK Ch.17"}, {"t": "Aeromedical", "d": 3, "q": "What is the danger of self-medicating with over-the-counter pain relievers before flight?", "c": ["OTC pain relievers are always safe for flight", "Many OTC pain relievers can impair judgment, cause drowsiness (antihistamines in combination products), mask pain indicating a serious underlying condition, or have drug interactions. Aspirin can affect platelets; ibuprofen and naproxen can cause gastrointestinal issues at altitude.", "OTC pain relievers only affect pilots on long flights", "Pain relievers have no effect on pilot cognitive performance"], "a": 1, "e": "OTC medications require careful consideration before flight. Combination products (cold and flu medications) often contain antihistamines causing drowsiness. Aspirin affects platelet function. Any medication that treats a condition (pain, congestion) may mask symptoms of a medical condition that itself is disqualifying. Always consult an AME before flying on any medication.", "r": "AIM 8-1-1"}, {"t": "Aeromedical", "d": 2, "q": "What is the danger of flying within 24 hours of scuba diving?", "c": ["No danger \u2014 scuba diving and flying are compatible activities", "After scuba diving, dissolved nitrogen in the body tissues can form bubbles (decompression sickness / the bends) when exposed to lower pressure at altitude. The FAA recommends waiting at least 12 hours after a no-decompression dive and at least 24 hours after decompression diving or multiple dives.", "The danger is only for dives below 100 feet", "The danger only applies if the pilot had ear problems during diving"], "a": 1, "e": "Scuba diving dissolves nitrogen into body tissues under pressure. At altitude, lower pressure can cause dissolved nitrogen to form bubbles in tissues and blood (decompression sickness), causing joint pain, paralysis, or death. FAA guidelines: wait at least 12 hours after a single no-decompression dive; at least 24 hours after multiple dives, decompression dives, or any problems during diving.", "r": "AIM 8-1-1"}, {"t": "Maneuvers", "d": 2, "q": "What is Va (maneuvering speed) and how should it be used in turbulence?", "c": ["Maximum flap extension speed", "Design maneuvering speed \u2014 at or below Va, full deflection of a single control will not overstress the airframe; slow to Va or below in turbulence", "Minimum control airspeed", "Best glide speed for emergencies"], "a": 1, "e": "Va is the design maneuvering speed. At or below Va, a full deflection of one control surface will not overstress the airframe \u2014 the aircraft stalls before structural damage occurs. In turbulence, reduce to Va. Note: Va decreases as weight decreases.", "r": "PHAK Ch.11; POH"}, {"t": "Maneuvers", "d": 2, "q": "What is Vfe (flap extension speed) and why is it important?", "c": ["The speed at which flaps must be extended on all approaches", "Maximum speed at which flaps may be extended \u2014 exceeding Vfe can damage the flap mechanism; indicated by top of white arc on ASI", "Minimum speed for flap extension", "Optimal speed for short field landings"], "a": 1, "e": "Vfe is the maximum flap extended speed \u2014 the top of the white arc on the airspeed indicator. Extending flaps or flying with flaps extended above Vfe can cause structural damage to the flap system. Always verify airspeed before extending flaps.", "r": "PHAK Ch.11; POH"}, {"t": "Maneuvers", "d": 2, "q": "What is the normal traffic pattern sequence at a non-towered airport?", "c": ["Take off, fly direct to final, land", "Upwind, crosswind, downwind, base, final \u2014 left pattern unless right traffic is specified", "Downwind, crosswind, upwind, base, final", "Direct entry to any leg is preferred"], "a": 1, "e": "Standard traffic pattern: Upwind (parallel to runway in takeoff direction), Crosswind (90-degree turn), Downwind (parallel, opposite landing direction), Base (90-degree turn), Final (aligned with runway). Standard pattern is left-turning unless right traffic is specified.", "r": "AIM 4-3-3"}, {"t": "Maneuvers", "d": 2, "q": "What is traffic pattern altitude (TPA) at most airports?", "c": ["Always 1000 ft AGL", "500 ft AGL", "Typically 1000 ft AGL for piston aircraft; 1500 ft AGL for turbine aircraft; verify in Chart Supplement for specific airport", "2000 ft AGL standard"], "a": 2, "e": "Standard TPA is 1000 ft AGL for piston aircraft and 1500 ft AGL for turbine aircraft. Some airports have non-standard TPAs due to obstacles, noise abatement, or other factors. Always check the Chart Supplement for each airport's published TPA.", "r": "AIM 4-3-3; Chart Supplement"}, {"t": "Maneuvers", "d": 3, "q": "What is a stabilized approach and why is it critical?", "c": ["An approach flown by autopilot only", "An approach where the aircraft is on the correct flight path at target airspeed in the correct configuration with stable power by 500 ft AGL \u2014 unstabilized approaches are a leading cause of landing accidents; go-around if not stabilized", "Only required for instrument approaches", "Only required for commercial operations"], "a": 1, "e": "A stabilized approach requires by 500 ft AGL (VFR): correct glidepath, target airspeed +/-5 kts, landing configuration, stable power. Unstabilized approaches are a leading cause of approach and landing accidents. If not stabilized by the gate, execute a go-around.", "r": "PHAK Ch.8; AFH Ch.8"}, {"t": "Systems", "d": 2, "q": "What is the purpose of the aircraft's position lights (navigation lights) and when are they required?", "c": ["Required only during IFR flight", "Position lights show aircraft position and direction to other pilots at night \u2014 red (left wing), green (right wing), white (tail); required from sunset to sunrise", "Required at all times day and night", "Required only near airports"], "a": 1, "e": "Position lights (navigation lights) are required from sunset to sunrise and during IMC conditions per 14 CFR 91.209. Colors: red (left/port), green (right/starboard), white (aft). Other pilots use them to determine aircraft heading for collision avoidance.", "r": "14 CFR 91.209; PHAK Ch.7"}, {"t": "Systems", "d": 2, "q": "What does the symbol at the top of the yellow arc on the airspeed indicator represent?", "c": ["Vfe \u2014 maximum flap extension speed", "Vne \u2014 never-exceed speed; the red radial line is the absolute maximum \u2014 exceeding it risks structural failure", "Va \u2014 maneuvering speed", "Vy \u2014 best rate of climb"], "a": 1, "e": "Vne (never-exceed speed) is marked by the red radial line at the high end of the yellow caution arc. The yellow arc itself is the caution range \u2014 smooth air only. Exceeding Vne risks structural failure. It is the absolute maximum operating speed.", "r": "PHAK Ch.8, Ch.11"}, {"t": "Systems", "d": 2, "q": "What is the purpose of the vacuum system and which instruments does it power?", "c": ["Generates electricity for avionics", "Creates suction to spin gyroscopes in the attitude indicator and heading indicator; a vacuum pump driven by the engine generates suction; the suction gauge monitors system health (normal 4.5-5.4 in Hg)", "Controls landing gear operation", "Powers the magnetos"], "a": 1, "e": "The vacuum (suction) system powers gyroscopic instruments \u2014 typically the attitude indicator and heading indicator. An engine-driven pump creates suction that spins the gyro rotors. Loss of vacuum causes these instruments to fail \u2014 transition to partial panel. Monitor the suction gauge.", "r": "PHAK Ch.8"}, {"t": "Aeromedical", "d": 2, "q": "What is the 'DECIDE' model in aeronautical decision-making?", "c": ["A checklist for engine failure procedures", "Detect a problem, Estimate need to react, Choose a course of action, Identify actions needed, Do the necessary actions, Evaluate the effect \u2014 a structured in-flight decision-making process", "A weather evaluation system", "An ATC communication protocol"], "a": 1, "e": "DECIDE: Detect (recognize a change), Estimate (assess need to react), Choose (select best action), Identify (determine specific steps), Do (implement), Evaluate (assess outcome and repeat). Provides a systematic approach to in-flight decision-making under pressure.", "r": "PHAK Ch.17; FAA-H-8083-2"}, {"t": "Aeromedical", "d": 2, "q": "What are the five hazardous attitudes identified by the FAA?", "c": ["Overconfidence, carelessness, laziness, haste, and fear", "Anti-authority, Impulsivity, Invulnerability, Macho, and Resignation \u2014 each has a specific antidote", "Speed, ego, pride, stubbornness, peer pressure", "Risk, reward, urgency, habit, tradition"], "a": 1, "e": "Five hazardous attitudes and antidotes: Anti-authority ('Follow the rules') Impulsivity ('Not so fast, think first') Invulnerability ('It could happen to me') Macho ('Taking chances is foolish') Resignation ('I'm not helpless'). Recognizing and correcting these attitudes is a key ADM skill.", "r": "PHAK Ch.17; FAA-H-8083-2"}, {"t": "Aeromedical", "d": 2, "q": "What is the impact of prescription medications on flight safety?", "c": ["All prescription medications are approved for flight if the pilot feels fine", "Many prescription medications have side effects (sedation, impaired judgment, reduced reaction time) that can be dangerous in flight even without obvious subjective effects; always consult an AME before flying on any medication", "Prescription medications are safer than OTC medications for flight", "Only controlled substances require AME consultation"], "a": 1, "e": "Prescription medications may cause side effects that impair pilot performance, be prescribed for conditions that are themselves disqualifying, or interact with altitude, stress, or other substances in unexpected ways. Never fly on prescription medication without explicit AME approval.", "r": "AIM 8-1-1"}, {"t": "Navigation", "d": 2, "q": "What is the purpose of a course line on a sectional chart and how is it used for flight planning?", "c": ["It is drawn by ATC to show your cleared route", "A straight line drawn from departure to destination on the sectional; the pilot measures the true course with a plotter, applies TVMDC to get compass heading, and identifies checkpoints, terrain, and airspace along the route", "It shows restricted areas only", "Course lines are not used in VFR flight planning"], "a": 1, "e": "For VFR flight planning, pilots draw a course line on the sectional chart from departure to destination. Using a plotter, they measure the true course angle. Applying TVMDC gives the compass heading. The line also identifies terrain, airspace, checkpoints, and emergency landing areas along the route.", "r": "PHAK Ch.17"}, {"t": "Navigation", "d": 2, "q": "How do you identify a VOR station before using it for navigation?", "c": ["Visual inspection of the VOR antenna from the aircraft", "Tune the VOR frequency and listen for the three-letter Morse code identifier or voice identification; no identifier (or TST signal) means the VOR is unreliable and should not be used for navigation", "Use GPS to confirm the VOR location first", "Call ATC to confirm the VOR is active"], "a": 1, "e": "Before using a VOR, identify it by listening to the Morse code three-letter identifier on the VOR frequency. A test (TST) signal means the VOR is under maintenance and unreliable. No identifier may mean the station is out of service. Always identify before navigating.", "r": "AIM 1-1-3"}, {"t": "Regulations", "d": 2, "q": "What is an Airworthiness Certificate and when does it expire?", "c": ["Issued each year by the FAA \u2014 expires annually", "Issued when the aircraft is manufactured; valid as long as the aircraft is maintained in accordance with FARs and has not been modified beyond its type certificate", "Valid for 2 years only", "Must be renewed every time the aircraft changes ownership"], "a": 1, "e": "An Airworthiness Certificate is issued at the time of manufacture and is valid indefinitely as long as the aircraft is maintained in accordance with applicable FARs and has not been modified in a way that voids the type certificate.", "r": "14 CFR 21.181; PHAK Ch.9"}, {"t": "Weather", "d": 3, "q": "What is the significance of the tropopause for VFR pilots?", "c": ["No significance \u2014 VFR pilots never reach the tropopause", "The tropopause is the boundary between the troposphere (where all weather occurs) and the stratosphere \u2014 most severe weather occurs below it; pilots planning high-altitude VFR flights should understand it marks the top of the weather-containing atmosphere", "VFR pilots must always fly above the tropopause", "The tropopause is where VFR cloud clearance rules change"], "a": 1, "e": "The tropopause marks the top of the troposphere where virtually all weather occurs. Temperature stops decreasing and may increase or stabilize. Most severe weather is below it. The tropopause height varies from about 25,000 ft at the poles to 60,000 ft at the equator.", "r": "PHAK Ch.12"}, {"t": "Systems", "d": 1, "q": "What is the arm in a weight and balance calculation?", "c": ["The total weight of all items combined", "The horizontal distance in inches from the datum to the item's center of gravity", "The vertical distance from the aircraft's center to the ground", "The maximum allowable weight at a given CG position"], "a": 1, "e": "The arm is the horizontal distance in inches from the datum (a reference point defined in the aircraft's type certificate) to the center of gravity of each item. Positive values are aft of the datum.", "r": "PHAK Ch.10"}, {"t": "Systems", "d": 1, "q": "How is moment calculated in weight and balance?", "c": ["Moment = Total Weight / CG location", "Moment = Weight x Arm", "Moment = Arm / Weight", "Moment = Total Weight - Empty Weight"], "a": 1, "e": "Moment = Weight x Arm. It represents the turning force about the datum. Sum all moments and divide by total weight to find the overall CG location.", "r": "PHAK Ch.10"}, {"t": "Systems", "d": 2, "q": "What is the most dangerous condition regarding center of gravity?", "c": ["CG too far forward \u2014 requires more elevator back pressure", "CG too far aft \u2014 reduces longitudinal stability, may make stall recovery impossible", "CG at the forward limit \u2014 aircraft is underpowered", "CG at the aft limit \u2014 aircraft stalls at lower airspeeds"], "a": 1, "e": "An aft CG is the most dangerous condition. The aircraft becomes longitudinally unstable and extremely pitch-sensitive. A stall may be unrecoverable. An aft CG also reduces the effective angle of attack range.", "r": "PHAK Ch.10"}, {"t": "Systems", "d": 2, "q": "Avgas 100LL weighs approximately how many pounds per gallon?", "c": ["5 lbs/gal", "6 lbs/gal", "7 lbs/gal", "8 lbs/gal"], "a": 1, "e": "Aviation gasoline (100LL) weighs approximately 6 pounds per gallon. This is used in weight and balance calculations. Jet-A weighs approximately 6.7-6.8 lbs/gal.", "r": "PHAK Ch.10"}, {"t": "Systems", "d": 3, "q": "During flight, fuel burns off from the tanks. How does this typically affect CG?", "c": ["CG never changes during flight", "CG moves depending on the location of the fuel tanks relative to the overall CG \u2014 must verify CG stays within limits throughout flight", "CG always moves forward as fuel burns", "CG always moves aft as fuel burns"], "a": 1, "e": "As fuel burns, the CG shifts in the direction of the fuel tanks relative to the loaded CG. If fuel tanks are aft of the CG, burning fuel moves CG forward and vice versa. Always verify the CG remains within limits from takeoff weight to landing weight.", "r": "PHAK Ch.10; POH Section 6"}, {"t": "Systems", "d": 2, "q": "What is the useful load of an aircraft?", "c": ["The weight of the aircraft with full fuel and no passengers", "Maximum Gross Weight minus Basic Empty Weight", "The total payload capacity including fuel but not crew", "The maximum allowable cargo weight only"], "a": 1, "e": "Useful load = Maximum Gross Weight minus Basic Empty Weight. It represents the total weight available for fuel, passengers, cargo, and other items. Payload = useful load minus fuel weight.", "r": "PHAK Ch.10"}, {"t": "Navigation", "d": 2, "q": "What is the approximate rule of thumb for the effect of a 10-knot headwind on takeoff distance?", "c": ["No meaningful effect", "Reduces takeoff distance by approximately 10%", "Reduces takeoff distance by approximately 20%", "Increases takeoff distance by 10%"], "a": 1, "e": "A 10-knot headwind reduces takeoff distance by approximately 10%. Conversely, a 2-knot tailwind can increase takeoff distance by approximately 10%. Always apply performance chart corrections for actual wind conditions.", "r": "PHAK Ch.11; POH Section 5"}, {"t": "Navigation", "d": 2, "q": "What is service ceiling?", "c": ["The maximum altitude the aircraft can ever reach with any engine power", "The altitude at which the maximum rate of climb equals 100 fpm", "The maximum altitude for VFR cruise flight", "The altitude above which pressurization is required"], "a": 1, "e": "Service ceiling is the density altitude at which the aircraft's maximum rate of climb equals 100 fpm. Absolute ceiling is where the rate of climb reaches 0 fpm. Both decrease with excess weight and high DA.", "r": "PHAK Ch.11"}, {"t": "Navigation", "d": 3, "q": "POH takeoff performance charts assume which runway conditions?", "c": ["Grass runway at sea level on a standard day", "Paved, level, dry runway at the charted conditions with maximum braking", "Any runway type with no special corrections needed", "Uphill slope with a headwind component"], "a": 1, "e": "POH performance charts assume: paved, level, dry runway; correct technique; maximum certificated gross weight; and standard atmospheric corrections as charted. Real-world conditions such as grass, slope, or wet runway require additional safety margins.", "r": "POH Section 5; PHAK Ch.11"}, {"t": "Navigation", "d": 2, "q": "A crosswind of 90 degrees to the runway at 20 knots \u2014 what is the crosswind component?", "c": ["10 knots", "15 knots", "20 knots", "Zero \u2014 pure crosswind has no runway component"], "a": 2, "e": "When the wind is exactly 90 degrees to the runway, the full wind speed is a crosswind component. Crosswind component = wind speed x sin(angle off runway). Sin(90) = 1.0, so 20 kts x 1.0 = 20 kts crosswind.", "r": "PHAK Ch.11"}, {"t": "Navigation", "d": 3, "q": "The density altitude at an airport is 7,000 ft but the field elevation is 4,000 ft MSL. What does this mean for takeoff performance?", "c": ["The aircraft will perform as if it were at 4,000 ft \u2014 DA has no practical effect", "The aircraft will perform as if taking off from a 7,000-ft elevation airport \u2014 significantly degraded performance", "DA only affects climb performance, not ground roll", "DA only matters above 5,000 ft MSL"], "a": 1, "e": "Density altitude represents the effective altitude from a performance standpoint. An aircraft at 7,000 ft DA will have the engine power, propeller efficiency, and aerodynamic performance of an aircraft at 7,000 ft MSL regardless of the actual field elevation.", "r": "PHAK Ch.11"}, {"t": "Regulations", "d": 1, "q": "What color scheme identifies mandatory instruction signs at airports?", "c": ["Black letters on yellow background", "Yellow letters on black background", "White letters on red background", "Black letters on white background"], "a": 2, "e": "Mandatory instruction signs have white inscriptions on a red background. They identify areas where entry is restricted or requires ATC clearance \u2014 runway designations at hold-short lines, no-entry signs, and ILS critical area boundaries.", "r": "AIM 2-3-8"}, {"t": "Regulations", "d": 1, "q": "A yellow inscription on a black background at an airport indicates what type of sign?", "c": ["A mandatory instruction sign requiring immediate stop", "A location sign telling the pilot where they are (taxiway or runway designation)", "A direction sign pointing toward a runway", "A closed runway or taxiway marker"], "a": 1, "e": "Yellow inscription on black background = location sign. It identifies the current taxiway or runway the aircraft is on. Black inscription on yellow background = direction/destination sign showing where to go.", "r": "AIM 2-3-8"}, {"t": "Regulations", "d": 2, "q": "What do the four yellow lines across a taxiway (two solid, two dashed) indicate, and which side must you stop on?", "c": ["Pavement edge \u2014 stop on either side", "Runway hold-short position \u2014 stop on the SOLID line side. Never cross without ATC clearance.", "Instrument landing system critical area \u2014 proceed when the path is clear", "Crossing zone \u2014 yield to aircraft on the runway"], "a": 1, "e": "Hold-short lines consist of four yellow lines: two solid (on the side away from the runway) and two dashed (on the runway side). Stop on the solid side. The solid lines always face the direction traffic must hold short. Never cross without an explicit ATC clearance.", "r": "AIM 2-3-5"}, {"t": "Regulations", "d": 2, "q": "What does a VASI showing red over white indicate?", "c": ["Too high \u2014 descend immediately", "On the correct glidepath", "Too low \u2014 danger of terrain or obstacle contact", "The VASI is malfunctioning"], "a": 1, "e": "VASI color combinations: white over white = too high; red over white = on glidepath ('red over white, you're alright'); red over red = too low and dangerous. Remember: two reds means you're headed for the ground.", "r": "AIM 2-1-2"}, {"t": "Regulations", "d": 2, "q": "What does a PAPI showing 4 red lights indicate?", "c": ["Normal glidepath \u2014 all red is correct on PAPI", "Slightly high \u2014 add a small amount of descent", "Too low \u2014 dangerously below the glidepath, immediate corrective action required", "PAPI out of service"], "a": 2, "e": "PAPI (4 lights): 4 white = too high; 3 white/1 red = slightly high; 2 white/2 red = on glidepath; 1 white/3 red = slightly low; 4 red = dangerously too low. Immediate power and pitch correction required at 4 red.", "r": "AIM 2-1-2"}, {"t": "Regulations", "d": 2, "q": "What color are taxiway edge lights and taxiway centerline lights?", "c": ["White edge lights and blue centerline lights", "Blue edge lights and green centerline lights", "Green edge lights and white centerline lights", "Yellow edge lights and blue centerline lights"], "a": 1, "e": "Taxiway edge lights are blue. Taxiway centerline lights are green. Runway edge lights are white (with yellow in the last 2,000 ft or last half of runway if shorter than 4,000 ft). This color coding helps distinguish taxiways from runways at night.", "r": "AIM 2-1-1"}, {"t": "Regulations", "d": 1, "q": "What airport beacon configuration indicates a civilian land airport?", "c": ["White and green alternating flashes", "White and yellow alternating flashes", "Green and red alternating flashes", "Continuous green light"], "a": 0, "e": "Civilian land airport: alternating white and green flashes. Military airport: two white flashes alternating with one green. Water airport: white and yellow. Beacon operating during the day may indicate weather below VFR minimums.", "r": "AIM 2-1-8"}, {"t": "Regulations", "d": 3, "q": "What is a hot spot on an airport diagram?", "c": ["A location where turbulence is commonly reported", "A location on the airport movement area with a history of incidents or potential for confusion \u2014 depicted as numbered circles on the airport diagram", "An area where the pavement is weak and may cause tire damage", "A taxiway that can only be used in one direction"], "a": 1, "e": "Hot spots are labeled HS-1, HS-2, etc. on airport diagrams and FAA charts. They identify locations with complex geometry, sight line issues, or a history of runway incursions. Descriptions are in the Chart Supplement. Extra vigilance required.", "r": "AIM 2-3-7"}, {"t": "Weather", "d": 1, "q": "What cloud type is associated with thunderstorm activity?", "c": ["Cirrus", "Stratus", "Cumulonimbus", "Altocumulus"], "a": 2, "e": "Cumulonimbus (CB) is the thunderstorm cloud. It is a vertical development cloud extending from low levels to the upper troposphere (up to 60,000+ ft). Never fly into or through a CB. Avoid by at least 20 nm.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 1, "q": "What does a lenticular cloud indicate to a pilot?", "c": ["Approaching warm front with gradual deterioration", "Mountain wave turbulence \u2014 severe rotor turbulence possible below the cloud on the leeward side", "Good VFR conditions with stable air", "Convective activity \u2014 thunderstorms likely nearby"], "a": 1, "e": "Lenticular (lens-shaped) clouds form at the crest of mountain waves and remain stationary as air flows through them. The rotor zone below the wave crest can contain extremely violent turbulence. Avoid lenticular clouds and the area below them.", "r": "PHAK Ch.12; AIM 7-1-23"}, {"t": "Weather", "d": 2, "q": "What is the key difference between stable and unstable air regarding cloud type and precipitation?", "c": ["Stable air produces cumuliform clouds and showery precipitation; unstable produces stratiform clouds and steady precipitation", "Stable air produces stratiform clouds and steady precipitation; unstable air produces cumuliform clouds and showery precipitation", "Both types produce the same clouds but at different altitudes", "Stability only affects turbulence, not cloud type"], "a": 1, "e": "Stable air: stratiform clouds, smooth air, steady precipitation, poor visibility in fog/haze. Unstable air: cumuliform clouds, turbulence, showery/heavy precipitation, good visibility in precipitation. This distinction helps predict weather type from synoptic patterns.", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "Frost forms when the surface temperature is at or below the dewpoint AND below what temperature?", "c": ["32 degrees F only if humidity is above 90%", "0 degrees C (32 degrees F). Even a thin layer reduces lift up to 30% and must be removed before flight.", "Minus 10 degrees C", "Any temperature below standard ISA"], "a": 1, "e": "Frost forms when a surface is at or below the dewpoint temperature AND at or below 0 degrees C. Unlike structural icing in flight, frost forms on the ground. Even a light coat of frost disrupts airflow, reduces lift up to 30%, and increases drag. All frost must be removed before flight.", "r": "PHAK Ch.12; AC 135-17"}, {"t": "Weather", "d": 2, "q": "What is the Convective Outlook (AC) and when is it useful?", "c": ["A forecast of mountain wave turbulence issued by the FAA", "A forecast issued by the Storm Prediction Center identifying areas of potential convective activity and severe thunderstorm risk for up to 8 days. Useful for strategic trip planning when convective weather is a concern.", "An ATC advisory of active convective SIGMETs in your area", "A pilot report of convective activity along your route"], "a": 1, "e": "The Convective Outlook (AC) is issued by the Storm Prediction Center and identifies areas of slight, enhanced, moderate, and high risk for severe thunderstorm development. It is a planning tool for the next 1-8 days and should be consulted before any cross-country when convective weather is possible.", "r": "AIM 7-1-6"}, {"t": "Weather", "d": 2, "q": "Cirrus clouds at high altitude with wispy streaks indicate what weather trend?", "c": ["Good VFR conditions will persist for many hours", "A possible approaching warm front \u2014 cirrus typically appear 24-48 hours before a warm front surface passage", "Thunderstorm development in the next few hours", "High winds aloft only \u2014 no surface weather significance"], "a": 1, "e": "Cirrus clouds form at high altitudes (above 20,000 ft) and are composed of ice crystals. Their presence can indicate an approaching warm front, which typically reaches a given area 24-48 hours after cirrus is first spotted. Also associated with jet stream turbulence (CAT).", "r": "PHAK Ch.12"}, {"t": "Weather", "d": 2, "q": "What weather conditions does AIRMET Sierra specifically warn about?", "c": ["Moderate turbulence and low-level wind shear", "IFR conditions \u2014 ceilings below 1,000 ft and/or visibility below 3 SM over a large area, or mountain obscuration", "Moderate icing and freezing level information", "Severe turbulence that could affect all aircraft"], "a": 1, "e": "AIRMET Sierra covers: IFR conditions (ceiling below 1,000 ft and/or visibility below 3 SM affecting 3,000 or more square miles) and mountain obscuration. It is particularly relevant to VFR pilots who may not have an instrument rating to fly through IFR conditions.", "r": "AIM 7-1-6"}, {"t": "Weather", "d": 3, "q": "What is the Surface Analysis Chart used for in preflight planning?", "c": ["It shows forecast winds aloft for the next 12 hours", "It shows current surface weather including pressure systems, frontal locations, and isobars \u2014 not a forecast. Used to identify current frontal positions, pressure gradient, and overall weather pattern.", "It shows a forecast of ceiling and visibility for the route", "It is the same as the TAF but in graphic form"], "a": 1, "e": "The Surface Analysis Chart shows current (not forecast) surface weather conditions including: high and low pressure centers, frontal boundaries, isobars (lines of equal pressure), and precipitation areas. Updated every 3 hours. Closely spaced isobars indicate a steep pressure gradient and strong winds.", "r": "AC 00-45H"}, {"t": "Navigation", "d": 1, "q": "What is the primary purpose of filing a VFR flight plan?", "c": ["It is required by law for all cross-country flights over 50 nm", "To provide search and rescue information if the aircraft is overdue \u2014 it is NOT legally required but strongly recommended", "To get an ATC transponder code for radar identification", "To reserve airspace for the flight route"], "a": 1, "e": "VFR flight plans are NOT required by 14 CFR but are strongly recommended as a search-and-rescue tool. If not closed within 30 minutes of the ETA, SAR procedures may begin. Always close the flight plan after landing by contacting FSS.", "r": "AIM 5-1-4"}, {"t": "Navigation", "d": 2, "q": "What does RAIM stand for and why does it matter for IFR GPS use?", "c": ["Radar Altitude Instrument Monitor \u2014 used to verify altimeter accuracy", "Receiver Autonomous Integrity Monitoring \u2014 the GPS self-checks signal integrity using redundant satellites. If RAIM is unavailable, GPS cannot be used as a primary navigation source for IFR approaches without WAAS.", "Route Approved Instrument Minimums \u2014 an FAA designation for approach procedures", "Real-time Airspace Information Monitoring \u2014 a system for TFR alerts"], "a": 1, "e": "RAIM allows a GPS receiver to check its own integrity by comparing signals from multiple satellites. For IFR non-WAAS GPS approaches, a RAIM check must be done before departure. If RAIM is unavailable during the approach, the GPS cannot be used as the primary instrument. WAAS-equipped GPS does not require a RAIM check.", "r": "AIM 1-1-17"}, {"t": "Navigation", "d": 2, "q": "How do you request VFR flight following from ATC?", "c": ["File a VFR flight plan and ATC automatically provides flight following", "Contact the appropriate ARTCC or approach control on the appropriate frequency: identify yourself, location, altitude, destination, and request radar traffic advisories", "Squawk 1200 and ATC automatically provides radar service", "Flight following is only available for IFR aircraft"], "a": 1, "e": "To request VFR flight following: contact the appropriate approach control or Center on the correct frequency. State: aircraft identification, aircraft type, position, altitude, destination, and request. ATC will assign a discrete transponder code. Service is workload-permitting and can be terminated by ATC.", "r": "AIM 4-1-15"}, {"t": "Navigation", "d": 2, "q": "What transponder codes indicate specific situations?", "c": ["7500 = lost communications; 7600 = emergency; 7700 = hijacking", "7500 = hijacking; 7600 = lost communications; 7700 = general emergency", "7500 = general emergency; 7600 = hijacking; 7700 = radio failure", "All emergency codes are the same \u2014 7700 covers all situations"], "a": 1, "e": "7500 = hijacking/unlawful interference. 7600 = radio/communications failure. 7700 = general emergency. These codes are internationally recognized and immediately alert ATC to your situation. Squawk 1200 = VFR flight without flight following.", "r": "AIM 6-2-2"}, {"t": "Navigation", "d": 3, "q": "When lost, what is the recommended first action \u2014 and what do the '5 C's' stand for?", "c": ["Immediately declare an emergency on 121.5 MHz", "Climb, Conserve, Communicate, Consult, Circle. First action is to climb for better radio/radar reception and visual range, then conserve fuel, communicate with ATC, consult all available navigation, and circle while resolving position.", "Land immediately at the nearest airport regardless of conditions", "Continue on course and hope to identify a landmark"], "a": 1, "e": "The 5 C's for lost procedure: Climb (altitude improves radio contact and visual range), Conserve fuel, Communicate (121.5 or ATC), Confess (tell ATC you are lost), Comply (with ATC instructions). Climbing is the first priority as it enables all other actions.", "r": "PHAK Ch.17; AIM 6-2"}, {"t": "Navigation", "d": 3, "q": "When diverting to an alternate airport in flight, what information do you need to compute?", "c": ["Only the new heading \u2014 everything else can wait until landing", "New magnetic course, estimated time enroute (ETE), fuel required for the diversion plus reserve, and whether the alternate has appropriate services for your needs. Communicate intentions to ATC promptly.", "Only the fuel remaining \u2014 heading can be determined by GPS", "The diversion procedure only applies to IFR flights"], "a": 1, "e": "When diverting: (1) identify a suitable alternate on the chart, (2) estimate the new magnetic course using the TVMDC formula, (3) estimate distance, (4) calculate ETE = distance / groundspeed, (5) calculate fuel required + reserve, (6) communicate with ATC. GPS simplifies step 2-4 greatly but understand the manual method.", "r": "PHAK Ch.17; ACS VI.C"}, {"t": "Navigation", "d": 2, "q": "What is WAAS and how does it improve GPS accuracy?", "c": ["Wind Adjusted Approach System \u2014 adjusts approaches for wind conditions", "Wide Area Augmentation System \u2014 a network of ground reference stations that transmit corrections to GPS satellites, improving accuracy to approximately 3 meters or better. Enables GPS LPV approaches comparable to ILS.", "Weather Avoidance Advisory System \u2014 weather overlay for EFBs", "Waypoint Automated Alerting System \u2014 warns of nearby waypoints"], "a": 1, "e": "WAAS (Wide Area Augmentation System) uses a network of ground reference stations throughout the US to compute GPS signal corrections, which are uplinked to geostationary satellites and broadcast to WAAS-capable receivers. WAAS improves GPS accuracy to approximately 1-3 meters and enables LPV approaches with decision heights as low as 200 ft HAT.", "r": "AIM 1-1-17"}, {"t": "Maneuvers", "d": 2, "q": "What two conditions must be present simultaneously for a spin to develop?", "c": ["High power and low airspeed", "A stalled condition AND a yawing motion (usually from uncoordinated rudder)", "A bank angle exceeding 45 degrees with back pressure", "High altitude and steep descent angle"], "a": 1, "e": "A spin requires: (1) a stalled wing \u2014 the aircraft must be at or beyond the critical angle of attack, AND (2) a yawing motion \u2014 typically from uncoordinated rudder (skid). The yaw causes one wing to stall more deeply than the other, creating the differential lift that initiates autorotation.", "r": "PHAK Ch.4; AFH Ch.4"}, {"t": "Maneuvers", "d": 2, "q": "What does PARE stand for in spin recovery?", "c": ["Pull-Altitude-Roll-Exit", "Power-Ailerons-Rudder-Elevator", "Power idle, Ailerons neutral, Rudder full opposite to spin direction, Elevator forward to break the stall", "Pitch-Airspeed-Recovery-Exit"], "a": 2, "e": "PARE spin recovery: Power to idle (prevents worsening spin), Ailerons neutralized (ailerons can worsen spin), Rudder full opposite to rotation direction (stops autorotation), Elevator briskly forward (breaks the stall). Once rotation stops: neutralize rudder, recover from dive smoothly.", "r": "AFH Ch.4; ACS VII.D"}, {"t": "Maneuvers", "d": 3, "q": "Why should ailerons be neutralized rather than applied into the spin during spin recovery?", "c": ["Aileron application is not possible during a spin due to airflow", "In some aircraft configurations, applying aileron into or away from the spin can increase the rate of rotation or aggravate the spin \u2014 PARE requires neutral ailerons to avoid this risk", "Ailerons have no effect during a spin in any phase", "Ailerons must be applied with the spin to maintain coordination"], "a": 1, "e": "During a spin, the aerodynamic effects of aileron deflection are different from normal flight. In some aircraft, applying aileron can increase the rate of rotation (pro-spin). PARE specifies neutral ailerons to eliminate this variable. Rudder is the primary control for stopping autorotation; elevator breaks the stall.", "r": "AFH Ch.4"}, {"t": "Maneuvers", "d": 3, "q": "What is the correct sequence for recovering from a nose-low unusual attitude?", "c": ["Pitch up immediately, then add power, then roll wings level", "Power to idle, roll wings level, then smoothly raise the nose to level flight attitude", "Add full power, apply back pressure, then roll wings level", "Roll into a steep bank to slow the nose-low descent then recover"], "a": 1, "e": "Nose-low unusual attitude recovery: (1) Power to idle to prevent overspeed, (2) Level the wings (this is critical \u2014 pulling while banked loads the aircraft heavily), (3) Smoothly raise the nose to level. Do NOT pull back before leveling wings or you risk an accelerated stall or Vne exceedance.", "r": "AFH Ch.12; ACS VIII.E"}, {"t": "Maneuvers", "d": 3, "q": "What instruments remain functional when the vacuum system fails in flight?", "c": ["All six primary flight instruments remain functional", "Only the altimeter remains functional", "Turn coordinator (electric gyro), airspeed indicator, altimeter, and VSI remain functional \u2014 attitude indicator and heading indicator become unreliable", "Only the magnetic compass and altimeter are reliable"], "a": 2, "e": "Vacuum failure makes the attitude indicator and heading indicator unreliable within minutes. Instruments that still work: turn coordinator (electric gyro), airspeed indicator, altimeter, VSI (all pitot-static or electric), and magnetic compass. Transition to partial panel techniques using these instruments.", "r": "PHAK Ch.8"}, {"t": "Maneuvers", "d": 2, "q": "What is the correct recovery procedure for a nose-high unusual attitude?", "c": ["Power to idle, then lower the nose, then roll wings level", "Add full power, roll wings level, then lower the nose to level flight attitude", "Simultaneously add power and push the nose down", "Apply back pressure to prevent further pitch increase, then roll wings level"], "a": 1, "e": "Nose-high unusual attitude: (1) Add full power (aircraft is decelerating and may be near stall), (2) Level the wings, (3) Lower the nose to level flight attitude. Memory: nose-HIGH = power HIGH. The aircraft needs energy to avoid a stall \u2014 power first, then level, then pitch.", "r": "AFH Ch.12; ACS VIII.E"}, {"t": "Maneuvers", "d": 2, "q": "What is the purpose of a forward slip to landing?", "c": ["To increase airspeed on final approach to prevent stall", "To rapidly lose altitude without increasing airspeed \u2014 useful when high on approach with insufficient runway remaining or when flaps are unavailable", "To correct for a crosswind during the final approach \u2014 same as a sideslip", "To increase engine cooling during descent"], "a": 1, "e": "A forward slip creates significant drag by cross-controlling (opposite aileron and rudder), which bleeds altitude quickly without increasing airspeed. It is useful when overshooting the glidepath or when flaps cannot be used. The nose is pointed to the side while the flight path continues toward the runway.", "r": "AFH Ch.8; ACS IV.M"}, {"t": "Maneuvers", "d": 3, "q": "What POH limitation must be checked before performing a forward slip with full flaps?", "c": ["No limitation exists \u2014 forward slips are always permitted with any flap setting", "Check the POH \u2014 some aircraft prohibit slips with certain flap configurations. The Cessna 172 POH notes that forward slips with full flaps may result in a temporary reduction in elevator effectiveness.", "Forward slips are only prohibited without flaps", "The limitation only applies to slips exceeding 30 seconds"], "a": 1, "e": "POH must always be checked. The Cessna 172 POH notes: 'Forward slips with full flaps and high power settings may result in a tendency for the aircraft to pitch up.' Some aircraft prohibit slips with full flaps. Airspeed indication may also be unreliable during a slip due to pitot tube positioning.", "r": "POH; AFH Ch.8; ACS IV.M"}, {"t": "Maneuvers", "d": 2, "q": "In the wing-low (sideslip) crosswind landing technique, what is the correct control input?", "c": ["Aileron into the wind and same-direction rudder to align with the runway", "Aileron into the wind (upwind wing drops) and opposite (downwind) rudder to align the nose with the runway centerline", "Both aileron and rudder away from the wind direction", "Crab into the wind throughout and remove at the last moment"], "a": 1, "e": "Wing-low (sideslip): apply upwind aileron (lowers the upwind wing to prevent drift) and opposite downwind rudder (aligns the nose with the runway). The aircraft touches down on the upwind main gear first with no side load. The ball will be off-center during this maneuver \u2014 this is intentional and correct.", "r": "AFH Ch.8"}, {"t": "Systems", "d": 1, "q": "What is adverse yaw and how is it corrected?", "c": ["A yaw caused by crosswind \u2014 corrected by crabbing into the wind", "When ailerons are applied, the descending wing's aileron creates more drag, causing the nose to yaw opposite to the intended turn. Corrected with coordinated rudder input in the direction of the turn.", "A yaw caused by propeller torque during high-power operations", "Adverse yaw only occurs during stall entry and recovery"], "a": 1, "e": "Adverse yaw: the downward-deflecting aileron (on the rising wing) creates induced drag, while the upward-deflecting aileron (on the descending wing) also creates drag. The net effect is a yaw opposite to the intended turn. Corrected with rudder \u2014 the ball provides real-time feedback on coordination.", "r": "PHAK Ch.6"}, {"t": "Systems", "d": 2, "q": "A constant-speed propeller aircraft has both a throttle and a propeller control. When increasing power for takeoff, what is the correct sequence?", "c": ["Always advance the prop control first, then the throttle", "Advance the throttle first to desired manifold pressure, then adjust the prop control to desired RPM", "Simultaneously advance both controls equally", "The sequence does not matter \u2014 both controls do the same thing"], "a": 0, "e": "For constant-speed prop aircraft: when INCREASING power, advance the prop control first (increase RPM), then advance the throttle (increase manifold pressure). This prevents the engine from over-boosting. When DECREASING power: throttle first (reduce MP), then prop (reduce RPM). Remember: power up = prop first; power down = throttle first.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 2, "q": "What is the purpose of the alternate air (alternate air source) on a fuel-injected engine?", "c": ["It provides an emergency fuel source if the main fuel pump fails", "It bypasses the air filter and draws warm air from inside the cowling to prevent induction icing if the primary inlet becomes blocked", "It provides extra cooling air to prevent engine overheating", "It is the same as carburetor heat on a carbureted engine"], "a": 1, "e": "Fuel-injected engines cannot develop carburetor ice (no carburetor) but can develop induction system icing at the air filter or inlet. The alternate air door bypasses the normal filtered air intake and draws warm, unfiltered air from inside the cowling. Activate if you experience a sudden unexplained power loss in icing conditions.", "r": "PHAK Ch.7"}, {"t": "Systems", "d": 2, "q": "Which of the following correctly describes a 406 MHz ELT compared to an older 121.5 MHz ELT?", "c": ["406 MHz ELTs are no longer required \u2014 121.5 MHz is the current standard", "406 MHz ELTs transmit digitally with aircraft registration and GPS position (if equipped), are monitored by COSPAS-SARSAT satellites, and enable much faster SAR response than the older 121.5 MHz analog units", "Both types are monitored by satellites with equal effectiveness", "121.5 MHz ELTs have longer battery life and are preferred for most aircraft"], "a": 1, "e": "406 MHz ELTs: digital encoding with aircraft ID and GPS position (if GPS equipped), monitored by international COSPAS-SARSAT satellite system, typical location accuracy of 100 meters with GPS. 121.5 MHz ELTs have NOT been monitored by satellites since February 1, 2009. 406 MHz is now required on most aircraft and is far superior for SAR purposes.", "r": "14 CFR 91.207; AIM"}, {"t": "Aeromedical", "d": 2, "q": "Why should pilots use off-center (eccentric) viewing at night?", "c": ["To avoid glare from runway lights by looking to the side", "The center of the retina (fovea) contains cones which require more light \u2014 looking 5-10 degrees off to the side uses the rod-rich peripheral retina which is more sensitive to low light levels", "Night vision is equally good regardless of where on the retina the image falls", "Off-center viewing is for reading charts only, not for spotting aircraft or obstacles"], "a": 1, "e": "The fovea (center of the retina) contains only cones, which detect color and fine detail but require relatively bright light. In darkness, rods in the peripheral retina provide much better detection ability. By looking 5-10 degrees off an object, the image falls on the rod-rich peripheral retina, dramatically improving detection of dim objects at night.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 2, "q": "How long does full dark adaptation take and what destroys it instantly?", "c": ["5 minutes and is not affected by brief light exposure", "Approximately 30 minutes for full dark adaptation \u2014 destroyed instantly by exposure to bright white light. Use red lighting in the cockpit to preserve dark adaptation.", "Approximately 5 minutes and is only partially reduced by light exposure", "Dark adaptation is permanent once achieved and is not affected by light exposure"], "a": 1, "e": "Full dark adaptation takes approximately 30 minutes and relies on a chemical process in the rod cells (rhodopsin builds up in darkness). A single flash of bright white light resets this process, destroying adaptation. Red light has minimal effect on rhodopsin and is used for cockpit lighting and chart reading to preserve night vision.", "r": "AIM 8-1-5"}, {"t": "Aeromedical", "d": 1, "q": "Night currency to carry passengers requires what recent experience?", "c": ["3 touch-and-goes at any time of day within 90 days", "3 full-stop takeoffs and landings between 1 hour after sunset and 1 hour before sunrise within the preceding 90 days", "Any 3 landings at night within the preceding 30 days", "5 takeoffs and landings at night within the preceding 60 days"], "a": 1, "e": "14 CFR 91.107(a)(3): To carry passengers at night, a pilot must have made 3 takeoffs and 3 full-stop landings during the period from 1 hour after sunset to 1 hour before sunrise within the preceding 90 days. Touch-and-goes do NOT satisfy the night currency requirement \u2014 full stops required.", "r": "14 CFR 91.107(a)(3)(ii)"}, {"t": "Regulations", "d": 2, "q": "What is the correct three-step procedure for transferring flight controls between pilots?", "c": ["The receiving pilot simply takes the controls when ready", "Giving pilot: 'You have the controls.' Receiving pilot: 'I have the controls.' (takes physical control) Giving pilot: 'You have the controls.' (confirms transfer)", "A nod or hand gesture is sufficient \u2014 verbal exchange is not required", "Only required for instrument flight \u2014 not necessary for VFR flight"], "a": 1, "e": "Positive exchange of controls uses a specific three-step verbal and physical exchange to prevent both pilots from thinking the other has the controls (or neither does). This exact phraseology is the FAA standard and should be used every time controls are transferred between any two people.", "r": "ACS II.B; AFH Ch.2"}, {"t": "Regulations", "d": 2, "q": "What is CFIT and why is it significant in general aviation?", "c": ["Controlled Flight Into Terrain \u2014 an accident where a functioning aircraft is flown into terrain or water without crew awareness. One of the leading causes of fatal GA accidents, typically associated with VFR flight into IMC or loss of situational awareness.", "Crew Flight Instrument Training \u2014 a type of instrument currency requirement", "Certified Flight Instructor Test \u2014 the checkride for CFI applicants", "Commercial Flight IFR Training \u2014 a category of instrument flight hours"], "a": 0, "e": "CFIT (Controlled Flight Into Terrain) occurs when a properly functioning aircraft is inadvertently flown into terrain, water, or obstacles. Causes include: VFR into IMC, spatial disorientation, poor situational awareness, and terrain avoidance complacency. Use terrain awareness tools, maintain SA, and always have an out when flying near terrain.", "r": "PHAK Ch.17"}];
const TOPICS = ['Regulations','Weather','Airspace','Navigation','Maneuvers','Systems','Aeromedical'];

// State
let setupLen = 10;
let setupTopics = new Set(['Regulations','Weather','Airspace','Navigation','Maneuvers','Systems','Aeromedical']);
let qS = {};

function buildTopicGrid() {
  const g = document.getElementById('tg');
  if (!g) return;
  g.innerHTML = TOPICS.map(t => {
    const cnt = BANK.filter(q => q.t === t).length;
    return `<div class="topic-chip active" id="tt-${t}" data-action="topic-toggle" data-topic="${t}">
      <span id="tc-${t}">✓</span> ${t} <span class="tc-cnt">(${cnt})</span>
    </div>`;
  }).join('');
}

function toggleTopic(t) {
  if (setupTopics.has(t)) {
    if (setupTopics.size === 1) return;
    setupTopics.delete(t);
    document.getElementById('tt-'+t).classList.remove('active');
    document.getElementById('tc-'+t).textContent = '○';
  } else {
    setupTopics.add(t);
    document.getElementById('tt-'+t).classList.add('active');
    document.getElementById('tc-'+t).textContent = '✓';
  }
  updatePreview();
}

function selAll() {
  TOPICS.forEach(t => {
    setupTopics.add(t);
    const el = document.getElementById('tt-'+t);
    if (el) { el.classList.add('active'); document.getElementById('tc-'+t).textContent = '✓'; }
  });
  updatePreview();
}

function clrAll() {
  TOPICS.forEach((t,i) => {
    const el = document.getElementById('tt-'+t);
    if (i === 0) {
      setupTopics.add(t);
      if (el) { el.classList.add('active'); document.getElementById('tc-'+t).textContent = '✓'; }
    } else {
      setupTopics.delete(t);
      if (el) { el.classList.remove('active'); document.getElementById('tc-'+t).textContent = '○'; }
    }
  });
  updatePreview();
}

function setLen(len, clickedEl) {
  setupLen = len;
  document.querySelectorAll('.len-btn').forEach(b => b.classList.remove('active'));
  if (clickedEl) clickedEl.classList.add('active');
  updatePreview();
}

function updatePreview() {
  const avail  = BANK.filter(q => setupTopics.has(q.t)).length;
  const actual = setupLen === 9999 ? avail : Math.min(setupLen, avail);
  const el = document.getElementById('qprev');
  if (el) el.textContent = `${actual} question${actual !== 1 ? 's' : ''} from ${avail} available`;
}

function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function startQuiz() {
  const pool  = shuffle(BANK.filter(q => setupTopics.has(q.t)));
  const limit = setupLen === 9999 ? pool.length : Math.min(setupLen, pool.length);
  qS = { diff:1, streak:0, total:0, correct:0, wrong:0,
         queue: pool.slice(0, limit), idx:0, maxQ:limit, answered:false };
  document.getElementById('setup-panel').style.display = 'none';
  document.getElementById('active-quiz').style.display = 'block';
  updateStats();
  nextQuestion();
}

function endQuiz() {
  document.getElementById('setup-panel').style.display = 'block';
  document.getElementById('active-quiz').style.display = 'none';
  updatePreview();
}

function nextQuestion() {
  if (qS.idx >= qS.queue.length) { showComplete(); return; }
  const remaining = qS.queue.slice(qS.idx);
  remaining.sort((a,b) => Math.abs(a.d - qS.diff) - Math.abs(b.d - qS.diff));
  for (let i = 0; i < remaining.length; i++) qS.queue[qS.idx + i] = remaining[i];
  const q = qS.queue[qS.idx];
  qS.answered = false;
  renderQ(q);
  updateDiff();
  updateProg();
}

function renderQ(q) {
  const L  = ['A','B','C','D'];
  const DL = ['Easy','Medium','Hard','Expert','Ace'];
  const DC = ['d-easy','d-med','d-hard','d-expert','d-ace'];
  document.getElementById('qcon').innerHTML = `
    <div class="q-card">
      <div class="q-meta">
        <span class="q-num">Q${qS.total+1} / ${qS.maxQ}</span>
        <span class="q-topic">${q.t}</span>
        <span class="q-diff ${DC[q.d-1]}">${DL[q.d-1]}</span>
      </div>
      <div class="q-text">${q.q}</div>
      <div class="choices">
        ${q.c.map((c,i) => `
          <button class="choice" id="cb${i}" data-action="quiz-answer" data-choice="${i}">
            <span class="choice-ltr">${L[i]}</span><span>${c}</span>
          </button>`).join('')}
      </div>
      <div class="explanation" id="expl">
        <div class="exp-ref">Ref: ${q.r}</div>${q.e}
      </div>
    </div>
    <div class="q-actions">
      <button class="btn btn-bright" id="nbtn" data-action="quiz-next" disabled>Next</button>
      <button class="btn btn-outline" data-action="quiz-end">End Quiz</button>
    </div>`;
}

function pick(idx) {
  if (qS.answered) return;
  qS.answered = true;
  const q  = qS.queue[qS.idx]; qS.idx++; qS.total++;
  const ok = idx === q.a;
  if (ok) { qS.correct++; qS.streak++; if (qS.streak >= 3 && qS.diff < 5) { qS.diff++; qS.streak = 0; } }
  else    { qS.wrong++;  qS.streak = 0; if (qS.diff > 1) qS.diff--; }
  for (let i = 0; i < q.c.length; i++) {
    const b = document.getElementById('cb'+i);
    b.disabled = true;
    if (i === q.a)             b.classList.add(ok && i === idx ? 'correct' : 'revealed');
    else if (i === idx && !ok) b.classList.add('wrong');
  }
  document.getElementById('expl').classList.add('show');
  document.getElementById('nbtn').disabled = false;
  updateStats(); updateProg();
}

function nextQ() { nextQuestion(); }

function updateStats() {
  document.getElementById('s-done').textContent = qS.total;
  document.getElementById('s-left').textContent = qS.maxQ - qS.total;
  document.getElementById('s-cor').textContent  = qS.correct;
  document.getElementById('s-wrg').textContent  = qS.wrong;
  document.getElementById('s-pct').textContent  = qS.total > 0 ? Math.round(qS.correct/qS.total*100)+'%' : '--';
}

function updateDiff() {
  const cols = ['var(--glow)','#f4c842','var(--amber)','var(--red)','var(--signal)'];
  const labs  = ['Easy','Medium','Hard','Expert','Ace'];
  for (let i = 1; i <= 5; i++) {
    const dot = document.getElementById('d'+i);
    if (dot) dot.style.background = i <= qS.diff ? cols[qS.diff-1] : 'var(--lift)';
  }
  const dt = document.getElementById('dtxt');
  if (dt) { dt.textContent = labs[qS.diff-1]; dt.style.color = cols[qS.diff-1]; }
}

function updateProg() {
  const pct = qS.maxQ > 0 ? (qS.total / qS.maxQ) * 100 : 0;
  const el  = document.getElementById('pbf');
  if (el) el.style.width = Math.min(100, pct) + '%';
}

function showComplete() {
  const pct   = qS.total > 0 ? Math.round(qS.correct/qS.total*100) : 0;
  const grade = pct >= 90 ? 'Checkride Ready' : pct >= 80 ? 'Strong Performance' : pct >= 70 ? 'Keep Reviewing' : 'Focus on Weak Areas';
  const col   = pct >= 90 ? 'var(--glow)' : pct >= 80 ? 'var(--bright)' : pct >= 70 ? 'var(--amber)' : 'var(--red)';
  document.getElementById('qcon').innerHTML = `
    <div class="result-card">
      <div class="result-score" style="color:${col}">${pct}%</div>
      <div class="result-grade" style="color:${col}">${grade}</div>
      <div class="result-stats">
        <div class="stat-box"><div class="stat-val" style="color:var(--glow)">${qS.correct}</div><div class="stat-lbl">Correct</div></div>
        <div class="stat-box"><div class="stat-val" style="color:var(--red)">${qS.wrong}</div><div class="stat-lbl">Wrong</div></div>
        <div class="stat-box"><div class="stat-val" style="color:var(--cloud)">${qS.total}</div><div class="stat-lbl">Total</div></div>
      </div>
      <p class="result-msg">Quiz complete. Adjust settings and go again.</p>
      <button class="btn btn-bright" data-action="quiz-end">Back to Setup</button>
    </div>`;
}


// ── Init + event delegation ──

export function initQuiz() {
  buildTopicGrid();
  updatePreview();
  const quizPage = document.querySelector('.quiz-page');
  if (quizPage) quizPage.addEventListener('click', handleClick);
}

function handleClick(e) {
  const target = e.target.closest('[data-action]');
  if (!target) return;
  const action = target.dataset.action;
  if (action === 'topic-toggle') { toggleTopic(target.dataset.topic); }
  else if (action === 'quiz-topics-all') { selAll(); }
  else if (action === 'quiz-topics-clear') { clrAll(); }
  else if (action === 'quiz-length') { setLen(parseInt(target.dataset.length, 10), target); }
  else if (action === 'quiz-start') { startQuiz(); }
  else if (action === 'quiz-answer') { pick(parseInt(target.dataset.choice, 10)); }
  else if (action === 'quiz-next') { nextQ(); }
  else if (action === 'quiz-end') { endQuiz(); }
}

// Called by mode-switch when entering quiz mode
export function onEnterQuiz() { updatePreview(); }
